-- Poems batch 32
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('26234f56-e269-46e5-bcf0-25b3b422a3dd','鸛雀樓晴望','馬戴','唐','唐诗','tang','','[]','堯女樓西望，人懷太古時。',48,'全唐诗/poet.tang.30000.json','["堯女樓西望，人懷太古時。", "海波通禹鑿，山木閉虞祠。", "鳥道殘虹挂，龍潭返照移。", "行雲如可馭，萬里赴心期。"]'),
('e634c0e4-9ad6-41e2-abc5-af3b7cff023a','贈淮南將','馬戴','唐','唐诗','tang','','[]','何事淮南將，功高業未成。',72,'全唐诗/poet.tang.30000.json','["何事淮南將，功高業未成。", "風濤辭海郡，雷雨鎮山營。", "度磧黃雲起，防秋白髮生。", "密機曾制敵，憂國更論兵。", "塞色侵旗動，寒光鎖甲明。", "自憐心有作，獨立望專征。"]'),
('2534da75-79ec-4db7-aac5-8d53c77b034c','寄賈島','馬戴','唐','唐诗','tang','','[]','海上不同來，關中俱久住。',84,'全唐诗/poet.tang.30000.json','["海上不同來，關中俱久住。", "尋思別山日，老盡經行樹。", "志業人未聞，時光鳥空度。", "風悲漢苑秋，雨滴秦城暮。", "佩玉與鏘金，非親亦非故。", "朱顏枉自毀，明代空相遇。", "歲晏各能歸，心知舊歧路。"]'),
('d426ea6f-3c1c-4b61-b192-e42e9f8c1fca','湘川弔舜','馬戴','唐','唐诗','tang','','[]','伊予生好古，弔舜蒼梧間。',72,'全唐诗/poet.tang.30000.json','["伊予生好古，弔舜蒼梧間。", "白日坐將沒，遊波凝不還。", "九疑雲動影，曠野竹成班。", "鴈集蒹葭渚，猨啼霧露山。", "南風吹早恨，瑤瑟怨長閑。", "元化誰能問，天門恨久關。"]'),
('9a1ea0d2-c758-4407-aa9d-1d64f5d16179','送僧歸閩中舊寺','馬戴','唐','唐诗','tang','','[]','寺隔海山遙，帆前落葉飄。',72,'全唐诗/poet.tang.30000.json','["寺隔海山遙，帆前落葉飄。", "斷猨通楚塞，驚鷺出蘭橈。", "星月浮波島，煙蘿渡石橋。", "鐘聲催野飯，秋色落寒潮。", "舊社人多老，閑房樹半凋。", "空林容病士，歲晚待相招。"]'),
('a8e9af2a-ed90-4b8a-8fcf-b5fc625e3c37','寄遠','馬戴','唐','唐诗','tang','','[]','坐想親愛遠，行嗟天地闊。',60,'全唐诗/poet.tang.30000.json','["坐想親愛遠，行嗟天地闊。", "積疹甘毀顏，沈憂更銷骨。", "迢迢遊子心，望望歸雲沒。", "喬木非故里，高樓共明月。", "夜深秋風多，聞鴈來天末。"]'),
('a6675ac9-39c0-4304-b969-baac79305652','經咸陽北原','馬戴','唐','唐诗','tang','','[]','秦山曾共轉，秦雲自舒卷。',60,'全唐诗/poet.tang.30000.json','["秦山曾共轉，秦雲自舒卷。", "古來爭雄圖，到此多不返。", "野狖穴孤墳，農人耕廢苑。", "川長波又逝，日與歲俱晚。", "夜入咸陽中，悲吞不能飯。"]'),
('086e8a34-4c65-42b7-ba57-818cd4eec743','冬日寄洛中楊少尹','馬戴','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河岸柳衰，城下渡流澌。',48,'全唐诗/poet.tang.30000.json','["黃河岸柳衰，城下渡流澌。", "年長從公懶，天寒入府遲。", "家山望幾遍，魏闕赴何時。", "懷古心誰識，應多謁舜祠。"]'),
('92609c38-144c-4924-a521-04d872bffc32','浙江夜宿','馬戴','唐','唐诗','tang','','[]','落帆人更起，露草滿汀洲。',48,'全唐诗/poet.tang.30000.json','["落帆人更起，露草滿汀洲。", "遠狖啼荒嶠，孤螢溺漫流。", "積陰開片月，爽氣集高秋。", "去去胡爲戀，搴芳時一遊。"]'),
('7455f507-16a8-41a1-bce9-03b1082ccda0','寄西岳白石僧','馬戴','唐','唐诗','tang','','[]','挂錫中峯上，經行踏石梯。',48,'全唐诗/poet.tang.30000.json','["挂錫中峯上，經行踏石梯。", "雲房出定後，岳月在池西。", "峭壁殘霞照，欹松積雪齊。", "年年著山屐，曾得到招提。"]'),
('843f8896-5eb7-41a9-9576-88902fe09012','同州冬日陪吳常侍閑宴','馬戴','唐','唐诗','tang','','[]','中天白雲散，集客郡齋時。',48,'全唐诗/poet.tang.30000.json','["中天白雲散，集客郡齋時。", "陶性聊飛爵，看山忽罷碁。", "雪花凝始散，木葉脫無遺。", "靜理良多暇，招邀愜所思。"]'),
('30297498-3d72-4c4f-8bd2-9449f7f36bbb','答鄜畤友人同宿見示','馬戴','唐','唐诗','tang','','[]','爲客自堪悲，風塵日滿衣。',48,'全唐诗/poet.tang.30000.json','["爲客自堪悲，風塵日滿衣。", "承明無計入，舊隱但懷歸。", "雪積孤城暗，燈殘曉角微。", "相逢喜同宿，此地故人稀。"]'),
('bae75abb-8776-4845-8e1c-5a931512d0c2','題僧禪院','馬戴','唐','唐诗','tang','','[]','虛室焚香久，禪心悟幾生。',48,'全唐诗/poet.tang.30000.json','["虛室焚香久，禪心悟幾生。", "濾泉侵月起，掃徑避蟲行。", "樹隔前朝在，苔滋廢渚平。", "我來風雨夜，像設一燈明。"]'),
('df661cd7-e2ae-4eb1-ae64-c9ba97f336f8','懷故山寄賈島','馬戴','唐','唐诗','tang','','[]','心偶羨明代，學詩觀國風。',48,'全唐诗/poet.tang.30000.json','["心偶羨明代，學詩觀國風。", "自從來闕下，未勝在山中。", "丹桂日應老，白雲居久空。", "誰能謝詩去，聊與此生同。"]'),
('f2f04c30-149d-4b2b-bce1-1334adf84739','灞上秋居','馬戴','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u79cb\u5929", "\u4e94\u8a00\u5f8b\u8bd7", "\u6000\u624d\u4e0d\u9047"]','灞原風雨定，晚見鴈行頻。',48,'全唐诗/poet.tang.30000.json','["灞原風雨定，晚見鴈行頻。", "落葉他鄉樹，寒燈獨夜人。", "空園白露滴，孤壁野僧隣。", "寄臥郊扉久，何門致此身。"]'),
('bede7d9c-23e5-419e-8761-f4128f5e8cd3','寄崇德里居作','馬戴','唐','唐诗','tang','','[]','掃君園林地，澤我清涼襟。',48,'全唐诗/poet.tang.30000.json','["掃君園林地，澤我清涼襟。", "高鳥雲路晚，孤蟬楊柳深。", "風微漢宮漏，月迥秦城砧。", "光景坐如此，徒懷經濟心。"]'),
('ba193e4c-434a-4057-93d0-00094454e20d','河梁別','馬戴','唐','唐诗','tang','','[]','河梁送別者，行哭半非親。',48,'全唐诗/poet.tang.30000.json','["河梁送別者，行哭半非親。", "此路足征客，胡天多殺人。", "金罍照離思，寶瑟凝殘春。", "早晚期相見，垂楊凋復新。"]'),
('62635725-cef0-4e25-a9ab-3e4ea864f082','留別定襄盧軍事','馬戴','唐','唐诗','tang','','[]','行行與君別，路在鴈門西。',48,'全唐诗/poet.tang.30000.json','["行行與君別，路在鴈門西。", "秋色見邊草，軍聲聞戍鼙。", "酣歌擊寶劒，躍馬上金堤。", "歸去咸陽里，平生志不迷。"]'),
('34e56099-81a7-4c9f-a636-4f6e9695a03c','送杜秀才東遊','馬戴','唐','唐诗','tang','','[]','羇遊年復長，去日值秋殘。',48,'全唐诗/poet.tang.30000.json','["羇遊年復長，去日值秋殘。", "草出函關白，雲藏野渡寒。", "鴻多霜雪重，山廣道途難。", "心事何人識，斗牛應數看。"]'),
('b61066a0-f58e-4839-9d66-ebc90d9cee92','懷黃頗','馬戴','唐','唐诗','tang','','[]','有客南浮去，平生與我同。',48,'全唐诗/poet.tang.30000.json','["有客南浮去，平生與我同。", "炎州結遙思，芳杜採應空。", "秦鴈歸侵月，湘猿戲褭楓。", "期君翼明代，未可戀山中。"]'),
('0a2486ef-b0b1-4503-a349-f24baf1f4504','隴上獨望','馬戴','唐','唐诗','tang','','[]','斜日挂邊樹，蕭蕭獨望間。',48,'全唐诗/poet.tang.30000.json','["斜日挂邊樹，蕭蕭獨望間。", "陰雲藏漢壘，飛火照胡山。", "隴首行人絕，河源夕鳥還。", "誰爲立勳者，可惜寶刀閑。"]'),
('6f9c734b-00ef-4d46-b30a-79ff6770c7aa','長安書懷','馬戴','唐','唐诗','tang','','[]','岐路今如此，還堪慟哭頻。',48,'全唐诗/poet.tang.30000.json','["岐路今如此，還堪慟哭頻。", "關中成久客，海上老諸親。", "谷口田應廢，鄉山草又春。", "年年銷壯志，空作獻書人。"]'),
('d9202065-0811-4720-87a3-d288cde39cbb','邯鄲驛樓作','馬戴','唐','唐诗','tang','','[]','蕪沒叢臺久，清漳廢御溝。',48,'全唐诗/poet.tang.30000.json','["蕪沒叢臺久，清漳廢御溝。", "蟬鳴河外樹，人在驛西樓。", "雲燒天中赤，山當日落秋。", "近郊經戰後，處處骨成丘。"]'),
('a258323a-855d-4b7b-a742-a593f8e9fc0f','別家後次飛狐西即事','馬戴','唐','唐诗','tang','','[]','遠歸從此別，親愛失天涯。',48,'全唐诗/poet.tang.30000.json','["遠歸從此別，親愛失天涯。", "去國頻迴首，方秋不在家。", "鳴蛩聞塞路，冷鴈背龍沙。", "西次桑乾曲，洲中見荻花。"]'),
('939b6cc6-63cf-4c88-a5bf-7396fac69fb1','題青龍寺鏡公房','馬戴','唐','唐诗','tang','','[]','一室意何有，閑門爲我開。',48,'全唐诗/poet.tang.30000.json','["一室意何有，閑門爲我開。", "爐香寒自滅，履雪飯初迴。", "窗迥孤山入，燈殘片月來。", "禪心方此地，不必訪天台。"]'),
('0e88cd12-cf15-4c60-8963-1fa3ea435686','邊城獨望','馬戴','唐','唐诗','tang','','["\u601d\u4e61"]','聊憑危堞望，倍起異鄉情。',48,'全唐诗/poet.tang.30000.json','["聊憑危堞望，倍起異鄉情。", "霜落蒹葭白，山昏霧露生。", "河灘胡鴈下，戎壘漢鼙驚。", "獨樹殘秋色，狂歌淚滿纓。"]'),
('279e6dda-6843-424b-a68e-1ad2e59a7797','江亭贈別','馬戴','唐','唐诗','tang','','[]','長亭晚送君，秋色渡江濆。',48,'全唐诗/poet.tang.30000.json','["長亭晚送君，秋色渡江濆。", "衰柳風難定，寒濤雪不分。", "猨聲離楚峽，帆影入湘雲。", "獨泛扁舟夜，山鐘可臥聞。"]'),
('f7794bcc-a10d-44bd-8449-ec3b3c9e85d6','旅次寄賈島兼簡無可上人','馬戴','唐','唐诗','tang','','[]','相思邊草長，迴望水連空。',48,'全唐诗/poet.tang.30000.json','["相思邊草長，迴望水連空。", "鴈過當行次，蟬鳴復客中。", "壯年看即改，羸病計多同。", "儻宿林中寺，深憑問遠公。"]'),
('84c9c014-b1ce-489f-b2de-dcee4c988068','寄剡中友人','馬戴','唐','唐诗','tang','','[]','故人今在剡，秋草意如何。',48,'全唐诗/poet.tang.30000.json','["故人今在剡，秋草意如何。", "嶺暮雲霞雜，潮迴島嶼多。", "沃洲僧幾訪，天姥客誰過。", "歲晚偏相憶，風生隔楚波。"]'),
('356c72c3-d3f4-47a9-90cc-ae4c49338879','送國子韋丞','馬戴','唐','唐诗','tang','','[]','臨水獨相送，歸期千里間。',48,'全唐诗/poet.tang.30000.json','["臨水獨相送，歸期千里間。", "雲迴逢過雨，路轉入連山。", "一騎行芳草，新蟬發故關。", "遙聆茂陵下，夜啓竹扉閑。"]'),
('cda8e5ce-0f45-4baf-bb9f-7804005368b5','題吳發原南居','馬戴','唐','唐诗','tang','','[]','閑居誰厭僻，門掩漢祠前。',48,'全唐诗/poet.tang.30000.json','["閑居誰厭僻，門掩漢祠前。", "山色夏雲映，樹陰幽草連。", "晴光分渚曲，綠氣冒原田。", "何日遠遊罷，高枝已噪蟬。"]'),
('f4562dfc-b136-4ff9-bb53-0488eaab0424','雒中寒夜姚侍御宅懷賈島','馬戴','唐','唐诗','tang','','[]','夜木動寒色，雒陽城闕深。',48,'全唐诗/poet.tang.30000.json','["夜木動寒色，雒陽城闕深。", "如何異鄉思，更抱故人心。", "微月關山遠，閑堦霜霰侵。", "誰知石門路，待與子同尋。"]'),
('d388030f-5bd5-46ee-b93c-b5b997351958','征婦歎','馬戴','唐','唐诗','tang','','[]','稚子在我抱，送君登遠道。',60,'全唐诗/poet.tang.30000.json','["稚子在我抱，送君登遠道。", "稚子今已行，念君上邊城。", "蓬根既無定，蓬子焉用生。", "但見請防胡，不聞言罷兵。", "及老能得歸，少者還長征。"]'),
('2e1fce4c-ec2a-43db-b972-4f362dab2f6b','山中寄姚合員外','馬戴','唐','唐诗','tang','','[]','朝與城闕別，暮同麋鹿歸。',48,'全唐诗/poet.tang.30000.json','["朝與城闕別，暮同麋鹿歸。", "鳥鳴松觀靜，人過石橋稀。", "木葉搖山翠，泉痕入澗扉。", "敢招仙署客，暫此拂朝衣。"]'),
('4247d5db-dacb-45f3-b2ef-c7eeb47fedfd','中秋月','馬戴','唐','唐诗','tang','','[]','陰魄出海上，望之增苦吟。',48,'全唐诗/poet.tang.30000.json','["陰魄出海上，望之增苦吟。", "冷搜驪頷重，寒徹蚌胎深。", "皓氣籠諸夏，清光射萬岑。", "悠然天地內，皎潔一般心。"]'),
('4dfad3ed-9a51-4112-942e-1e84207fdf2c','下第寄友人','馬戴','唐','唐诗','tang','','[]','金門君待問，石室我思歸。',36,'全唐诗/poet.tang.30000.json','["金門君待問，石室我思歸。", "聖主尊黃屋，何人薦白衣。", "年來御溝柳，贈別雨霏霏。"]'),
('6179b631-87ba-4a6b-8f1f-a5f5b9b66253','寄廣州楊參軍','馬戴','唐','唐诗','tang','','[]','南方春景好，念子緩歸心。',96,'全唐诗/poet.tang.30000.json','["南方春景好，念子緩歸心。", "身方脫野服，冠未繫朝簪。", "足恣平生賞，無虞外役侵。", "汀洲觀鳥戲，向月和猨吟。", "稅駕楚山廣，揚帆湘水深。", "採奇搜石穴，懷勝即楓林。", "悵望極霞際，流情墮海陰。", "前朝杳難問，歎息灑鳴琴。"]'),
('ee559b10-0d79-414b-9900-aec0a51bc417','離夜二首 一','馬戴','唐','唐诗','tang','','[]','東征遼水迥，北近單于臺。',36,'全唐诗/poet.tang.30000.json','["東征遼水迥，北近單于臺。", "戎衣挂寶劍，玉筯銜金杯。", "紅燭暗將滅，翠蛾終不開。"]'),
('dcdf690a-332d-4017-8ac3-59c9d42e8cba','離夜二首 二','馬戴','唐','唐诗','tang','','[]','凝夜照離色，恐聞啼晚鴉。',36,'全唐诗/poet.tang.30000.json','["凝夜照離色，恐聞啼晚鴉。", "前年營鴈塞，明月戍龍沙。", "曾與五陵子，休裝孤劍花。"]'),
('79b4e2e7-8425-45ce-9f77-0e9673355628','荅太原從軍楊員外送別','馬戴','唐','唐诗','tang','','[]','君將海月珮，贈之光我行。',72,'全唐诗/poet.tang.30000.json','["君將海月珮，贈之光我行。", "見知言不淺，懷報意非輕。", "反照臨歧思，中年未達情。", "河梁人送別，秋漢鴈相鳴。", "衰柳搖邊吹，寒雲冒古城。", "西遊還獻賦，應許託平生。"]'),
('a32012d9-fa61-47bf-868c-25128f31aa7c','送從叔重赴海南從事','馬戴','唐','唐诗','tang','','[]','又從連帥請，還作嶺南行。',72,'全唐诗/poet.tang.30000.json','["又從連帥請，還作嶺南行。", "窮海何時到，孤帆累月程。", "亂蟬吟暮色，哀狖落秋聲。", "晚路潮波起，寒葭霧雨生。", "沙埋銅柱沒，山簇瘴雲平。", "念此別離苦，其如宗從情。"]'),
('5806fc77-b49c-404e-aa91-46d6d92b6e74','送韓校書江西從事','馬戴','唐','唐诗','tang','','[]','出關寒色盡，雲夢草生新。',72,'全唐诗/poet.tang.30000.json','["出關寒色盡，雲夢草生新。", "鴈背岳陽雨，客行江上春。", "遙程隨水闊，枉路倒帆頻。", "夕照臨孤館，朝霞發廣津。", "湖山潮半隔，郡壁岸斜鄰。", "自此鍾陵道，裁書有故人。"]'),
('b26b953b-531d-40fd-9bdc-e5e923b3bf93','送顧少府之永康','馬戴','唐','唐诗','tang','','[]','婺女星邊去，春生即有花。',72,'全唐诗/poet.tang.30000.json','["婺女星邊去，春生即有花。", "寒關雲復雪，古渡草連沙。", "宿次吳江晚，行侵日徼斜。", "官傳梅福政，縣顧赤松家。", "燒起明山翠，潮迴動海霞。", "清高宜閱此，莫歎近天涯。"]'),
('6a81fe39-ec68-40ed-984f-f42c648f2070','幽上留別令狐侍郎','馬戴','唐','唐诗','tang','','[]','自別丘中隱，頻年哭路岐。',96,'全唐诗/poet.tang.30000.json','["自別丘中隱，頻年哭路岐。", "辛勤今若是，少壯豈多時。", "露滴陰蟲苦，秋聲遠客悲。", "晚營嚴鼓角，紅葉拂旌旗。", "北闕虛延望，西林久見思。", "川流寒水急，雲返故山遲。", "落照遊人去，長空獨鳥隨。", "不堪風景隔，忠信寡相知。"]'),
('8ccc2a03-4704-4b2a-86c1-645d3a669a46','襄陽席上呈于司空','馬戴','唐','唐诗','tang','','[]','花枝臨水復臨堤，也照清江也照泥。',32,'全唐诗/poet.tang.30000.json','["花枝臨水復臨堤，也照清江也照泥。", "寄語東君好擡舉，夜來曾伴鳳皇棲。"]'),
('ccc8f53e-b4e1-4486-b61e-da66829bcab0','宿裴氏谿居懷厲玄先輩','馬戴','唐','唐诗','tang','','[]','樹下孤石坐，草間微有霜。',48,'全唐诗/poet.tang.30000.json','["樹下孤石坐，草間微有霜。", "同人不同北，雲鳥自南翔。", "迢遰夜山色，清泠泉月光。", "西風耿離抱，江海遙相望。"]'),
('a62f2092-d6e9-4a7e-97a4-0baa12311aea','集宿姚殿中宅期僧無可不至','馬戴','唐','唐诗','tang','','[]','殿中日相命，開尊話舊時。',48,'全唐诗/poet.tang.30000.json','["殿中日相命，開尊話舊時。", "餘鐘催鳥絕，積雪阻僧期。", "林靜寒光遠，天陰曙色遲。", "今夕復何夕，人謁去難追。"]'),
('a63f6a41-deed-45ca-821f-8be30d583663','宿賈島原居','馬戴','唐','唐诗','tang','','[]','寒鴈過原急，渚邊秋色深。',48,'全唐诗/poet.tang.30000.json','["寒鴈過原急，渚邊秋色深。", "煙霞向海島，風雨宿園林。", "俱住明時願，同懷故國心。", "未能先隱跡，聊此一相尋。"]'),
('b53c4ba8-1bdd-4c32-b18b-33bc14cef2fc','贈別空公','馬戴','唐','唐诗','tang','','[]','雲門秋却入，微徑久無人。',48,'全唐诗/poet.tang.30000.json','["雲門秋却入，微徑久無人。", "後夜中峰月，空林百衲身。", "寂寥寒磬盡，盥漱瀑泉新。", "履跡誰相見，松風掃石塵。"]'),
('31d6dc34-ddcf-479d-975d-7159a00da2b9','府試觀開元皇帝東封圖','馬戴','唐','唐诗','tang','','[]','儼若翠華舉，登封圖乍開。',72,'全唐诗/poet.tang.30000.json','["儼若翠華舉，登封圖乍開。", "冕旒明主立，冠劍侍臣陪。", "跡類飛仙去，光同拜日來。", "粉痕疑檢玉，黛色訝生苔。", "挂壁雲將起，陵風仗若迴。", "何年復東幸，魯叟望悠哉。"]'),
('a7ae6b9f-7099-436e-be20-5f4138618b06','府試水始冰','馬戴','唐','唐诗','tang','','[]','南池寒色動，北陸歲陰生。',72,'全唐诗/poet.tang.30000.json','["南池寒色動，北陸歲陰生。", "薄薄流澌聚，灕灕翠瀲平。", "暗霑霜稍厚，迴照日還輕。", "乳竇懸殘滴，湘流減恨聲。", "即堪金井貯，會映玉壺清。", "潔白心雖識，空期飲此明。"]'),
('60c936a0-921f-4f13-9111-74d1a6e3ec3b','邊館逢賀秀才','馬戴','唐','唐诗','tang','','[]','貧病無疎我與君，不知何事久離羣。',64,'全唐诗/poet.tang.30000.json','["貧病無疎我與君，不知何事久離羣。", "鹿裘共弊同爲客，龍闕將移擬獻文。", "空館夕陽鴉繞樹，荒城寒色鴈和雲。", "不堪吟斷邊笳曉，葉落東西客又分。"]'),
('80d6db57-35ee-4c52-916a-285bcb559547','宿王屋天壇','馬戴','唐','唐诗','tang','','[]','星斗半沈蒼翠色，紅霞遠照海濤分。',64,'全唐诗/poet.tang.30000.json','["星斗半沈蒼翠色，紅霞遠照海濤分。", "折松曉拂天壇雪，投簡寒窺玉洞雲。", "絕頂醮迴人不見，深林磬度鳥應聞。", "未知誰與傳金籙，獨向仙祠拜老君。"]'),
('91ac3614-9bbd-4089-8ce3-79ed3046b7ae','岐陽逢曲陽故人話舊','馬戴','唐','唐诗','tang','','[]','異地還相見，平生問可知。',96,'全唐诗/poet.tang.30000.json','["異地還相見，平生問可知。", "壯年俱欲暮，往事盡堪悲。", "道路頻艱阻，親朋久別離。", "解兵逃白刃，謁帝值明時。", "淹疾生涯故，因官事業移。", "雞鳴關月落，鴈度朔風吹。", "客淚翻岐下，鄉心落海湄。", "積愁何計遣，滿酌浣相思。"]'),
('9ae0a460-1c44-40ff-885a-b26bc78cd4cc','贈禪僧','馬戴','唐','唐诗','tang','','[]','弟子人天遍，童年在沃洲。',48,'全唐诗/poet.tang.30000.json','["弟子人天遍，童年在沃洲。", "開禪山木長，浣衲海沙秋。", "振錫搖汀月，持瓶接瀑流。", "赤城何日上，鄙願從師遊。"]'),
('1f809aab-bb40-410e-b6e2-e29c265d1d96','題廬山寺','馬戴','唐','唐诗','tang','','["\u5e90\u5c71"]','白茅爲屋宇編荆，數處堦墀石疊成。',64,'全唐诗/poet.tang.30000.json','["白茅爲屋宇編荆，數處堦墀石疊成。", "東谷笑言西谷響，下方雲雨上方晴。", "鼠驚樵客緣蒼壁，猨戲山頭撼紫檉。", "別有一條投澗水，竹筒斜引入茶鐺。"]'),
('d181bfc0-594e-4fbd-b409-a37f59b16ed9','題石甕寺','馬戴','唐','唐诗','tang','','[]','僧室並皇宮，雲門輦路同。',72,'全唐诗/poet.tang.30000.json','["僧室並皇宮，雲門輦路同。", "渭分雙闕北，山迥五陵東。", "修綆懸林表，深泉汲洞中。", "人煙窺垤蟻，鴛瓦拂冥鴻。", "蘚壁松生峭，龕燈月照空。", "稀逢息心侶，獨禮竺乾公。"]'),
('54b62761-8a49-49bf-bbe9-a57ecf9c5e93','謁仙觀二首 一','馬戴','唐','唐诗','tang','','[]','我生求羽化，齋沐造仙居。',48,'全唐诗/poet.tang.30000.json','["我生求羽化，齋沐造仙居。", "葛蔓沒丹井，石函盛道書。", "寒松多偃側，靈洞遍清虛。", "一就泉西飲，雲中採藥蔬。"]'),
('5aac20f2-2745-4d74-8010-3b85c5feb87c','謁仙觀二首 二','馬戴','唐','唐诗','tang','','[]','山空蕙氣香，乳管折雲房。',48,'全唐诗/poet.tang.30000.json','["山空蕙氣香，乳管折雲房。", "願值壺中客，親傳肘後方。", "三更禮星斗，寸匕服丹霜。", "默坐樹陰下，仙經橫石牀。"]'),
('2ecf0c47-b59c-46ea-8360-1402ac4719c8','送朴山人歸新羅','馬戴','唐','唐诗','tang','','[]','浩渺行無極，揚帆但信風。',48,'全唐诗/poet.tang.30000.json','["浩渺行無極，揚帆但信風。", "雲山過海半，鄉樹入舟中。", "波定遙天出，沙平遠岸窮。", "離心寄何處，目斷曙霞東。"]'),
('8ca6fcbc-49f0-4230-b3b2-710c35a33b40','題靜住寺欽用上人房','馬戴','唐','唐诗','tang','','[]','寺近朝天路，多聞玉珮音。',48,'全唐诗/poet.tang.30000.json','["寺近朝天路，多聞玉珮音。", "鑒人開慧眼，歸鳥息禪心。", "磬接星河曙，窗連夏木深。", "此中能宴坐，何必在雲林。"]'),
('6495376c-1138-4097-8fd3-e037bd4db046','贈楊先輩','馬戴','唐','唐诗','tang','','[]','平生閑放久，野鹿許爲羣。',48,'全唐诗/poet.tang.30000.json','["平生閑放久，野鹿許爲羣。", "居止鄰西岳，軒窗度白雲。", "齋心飯松子，話道接茅君。", "漢主思清淨，休書諫獵文。"]'),
('9e9cd411-987b-44eb-acf1-488bb7d71913','詶李景章先輩','馬戴','唐','唐诗','tang','','[]','平生詩句忝多同，不得陪君奉至公。',64,'全唐诗/poet.tang.30000.json','["平生詩句忝多同，不得陪君奉至公。", "金鏑自宜先中鵠，鉛刀甘且學雕蟲。", "鶯啼細柳臨關路，燕接飛花遶漢宮。", "九陌芳菲人競賞，此時心在別離中。"]'),
('9ab77b05-8e8a-49e0-9eca-e04ed814f349','贈祠部令狐郎中','馬戴','唐','唐诗','tang','','[]','官初執憲稱雄才，省轉爲郎雅望催。',64,'全唐诗/poet.tang.30000.json','["官初執憲稱雄才，省轉爲郎雅望催。", "待制松陰移玉殿，分宵露氣靜天臺。", "算棋默向孤雲坐，隨鶴閑窮片水迴。", "忽憶十年相識日，小儒新自海邊來。"]'),
('6f86a601-d9f1-4d68-a5a7-ec774381689d','送冊東夷王使','馬戴','唐','唐诗','tang','','[]','越海傳金冊，華夷禮命行。',72,'全唐诗/poet.tang.30000.json','["越海傳金冊，華夷禮命行。", "片帆秋色動，萬里信潮生。", "日映孤舟出，沙連絕島明。", "翳空翻大鳥，飛雪灑長鯨。", "舊鬢迴應改，遐荒夢易驚。", "何當理風檝，天外問來程。"]'),
('297cbd21-9366-4641-aa8e-09db9f8340dd','送武陵王將軍','馬戴','唐','唐诗','tang','','[]','河外今無事，將軍有戰名。',72,'全唐诗/poet.tang.30000.json','["河外今無事，將軍有戰名。", "艱難長劍缺，功業少年成。", "曉仗親雲陛，寒宵突禁營。", "朱旗身外色，玉漏耳邊聲。", "開閤談賓至，調弓過鴈驚。", "爲儒多不達，見學請長纓。"]'),
('1bb2071b-98be-48f5-9e1a-27abb9a6c105','贈鄠縣尉李先輩二首 一','馬戴','唐','唐诗','tang','','[]','同人家鄠杜，相見罷官時。',48,'全唐诗/poet.tang.30000.json','["同人家鄠杜，相見罷官時。", "野坐苔生石，荒居菊入籬。", "聽蟬臨水久，送鶴背山遲。", "未擬還城闕，溪僧別有期。"]'),
('1d563208-d740-47d5-be78-f8f280fec7d7','贈鄠縣尉李先輩二首 二','馬戴','唐','唐诗','tang','','[]','休官不到闕，求靜匪營他。',48,'全唐诗/poet.tang.30000.json','["休官不到闕，求靜匪營他。", "種藥唯愁晚，看雲肯厭多。", "渚邊逢鷺下，林表伴僧過。", "閑檢仙方試，松花酒自和。"]'),
('2c52ce05-5950-473e-99d1-ae8955260476','邊將','馬戴','唐','唐诗','tang','','[]','玉榼酒頻傾，論功笑李陵。',48,'全唐诗/poet.tang.30000.json','["玉榼酒頻傾，論功笑李陵。", "紅韁跑駿馬，金鏃掣秋鷹。", "塞迥連天雪，河深徹底冰。", "誰言提一劍，勤苦事中興。"]'),
('e73ec8cc-adc7-48de-8cd5-8780f364700c','下第別令狐員外','馬戴','唐','唐诗','tang','','[]','論文期雨夜，飲酒及芳晨。',48,'全唐诗/poet.tang.30000.json','["論文期雨夜，飲酒及芳晨。", "坐歎百花發，潛驚雙鬢新。", "舊交多得路，別業遠仍貧。", "便欲辭知己，歸耕海上春。"]'),
('9c60bea3-e1a5-4699-9e53-47c30466ff69','送春坊董正字浙右歸覲','馬戴','唐','唐诗','tang','','[]','去覲毘陵日，秋殘建業中。',48,'全唐诗/poet.tang.30000.json','["去覲毘陵日，秋殘建業中。", "莎垂石城古，山闊海門空。", "灌木寒檣遠，層波皓月同。", "何當復讎校，春集少陽宮。"]'),
('d06489b9-825b-411c-a9c8-db2879c6a1fc','送和北虜使','馬戴','唐','唐诗','tang','','[]','路始陰山北，迢迢雨雪天。',96,'全唐诗/poet.tang.30000.json','["路始陰山北，迢迢雨雪天。", "長城人過少，沙磧馬難前。", "日入流沙際，陰生瀚海邊。", "刀鐶向月動，旌纛冒霜懸。", "逐獸孤圍合，交兵一箭傳。", "穹廬移斥候，烽火絕祁連。", "漢將行持節，胡兒坐控弦。", "明妃的迴面，南送使君旋。"]'),
('3fdf339e-637f-459e-8af0-e44f02b63b64','攄情留別幷州從事','馬戴','唐','唐诗','tang','','[]','淺學長自鄙，謬承賢達知。',96,'全唐诗/poet.tang.30000.json','["淺學長自鄙，謬承賢達知。", "才希漢主召，玉任楚人疑。", "年長慙漂泊，恩深惜別離。", "秋光獨鳥過，暝色一蟬悲。", "鶴髮生何速，龍門上苦遲。", "彫蟲羞朗鑒，干祿貴明時。", "故國誠難返，青雲致未期。", "空將感激淚，一自灑臨岐。"]'),
('9c01aeef-3da0-47dd-be5b-534bccf3c16b','酬田卿送西遊','馬戴','唐','唐诗','tang','','[]','華堂開翠簟，惜別玉壺深。',48,'全唐诗/poet.tang.30000.json','["華堂開翠簟，惜別玉壺深。", "客去當煩暑，蟬鳴復此心。", "廢城喬木在，古道濁河侵。", "莫慮西遊遠，西關絕隴陰。"]'),
('5dc28968-a609-46bf-ac05-885400bcebe7','雪中送青州薛評事','馬戴','唐','唐诗','tang','','[]','臘景不可犯，從戎難自由。',48,'全唐诗/poet.tang.30000.json','["臘景不可犯，從戎難自由。", "憐君急王事，走馬赴邊州。", "岳雪明日觀，海雲冒營丘。", "慙無斗酒瀉，敢望御重裘。"]'),
('7033db17-9311-4be0-8ffa-7bdc0f50baba','哭京兆龐尹','馬戴','唐','唐诗','tang','','[]','神州喪賢尹，父老泣關中。',60,'全唐诗/poet.tang.30000.json','["神州喪賢尹，父老泣關中。", "未盡羣生願，纔留及物功。", "清光沈皎月，素業振遺風。", "履跡莓苔掩，珂聲紫陌空。", "從來受知者，會葬漢陵東。"]'),
('ba671863-b442-47ef-9a31-acb4ade9b978','路傍樹','馬戴','唐','唐诗','tang','','[]','古樹何人種，清陰減昔時。',48,'全唐诗/poet.tang.30000.json','["古樹何人種，清陰減昔時。", "莓苔根半露，風雨節偏危。", "蟲蠹心將穴，蟬催葉向衰。", "樵童不須翦，聊起邵公思。"]'),
('c0905485-1254-442f-8c90-e4d01de58576','送客南遊','馬戴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','擬卜何山隱，高秋指岳陽。',50,'全唐诗/poet.tang.30000.json','["擬卜何山隱，高秋指岳陽。", "葦乾雲夢色，橘熟洞庭香。", "疎雨殘虹影，[囘]雲背鳥行。", "靈均如可問，一爲哭清湘。"]'),
('73dd12a7-48d8-4b9e-bcac-c07270847304','寄襄陽王公子','馬戴','唐','唐诗','tang','','[]','君馬勒金羈，君家貯玉笄。',48,'全唐诗/poet.tang.30000.json','["君馬勒金羈，君家貯玉笄。", "白雲登峴首，碧樹醉銅鞮。", "澤廣荆州北，山多漢水西。", "鹿門知不隱，芳草自萋萋。"]'),
('33236907-df1c-4890-984a-099367f1b306','集宿姚侍御宅懷永樂宰殷侍御','馬戴','唐','唐诗','tang','','[]','石田虞芮接，種樹白雲陰。',48,'全唐诗/poet.tang.30000.json','["石田虞芮接，種樹白雲陰。", "穴閉神踪古，河流禹鑿深。", "樵人應滿郭，僊鳥幾巢林。", "此會偏相語，曾供雪夜吟。"]'),
('72586e99-f113-4d0d-9f16-6015c4e7da47','易水懷古','馬戴','唐','唐诗','tang','','[]','荆卿西去不復返，易水東流無盡期。',32,'全唐诗/poet.tang.30000.json','["荆卿西去不復返，易水東流無盡期。", "落日蕭條薊城北，黃沙白草任風吹。"]'),
('15f0943a-4211-41e1-b830-a3b493048f96','送僧二首 一','馬戴','唐','唐诗','tang','','[]','親在平陽憶久歸，洪河雨漲出關遲。',32,'全唐诗/poet.tang.30000.json','["親在平陽憶久歸，洪河雨漲出關遲。", "獨過舊寺人稀識，一一杉松老別時。"]'),
('3c9a8218-f54a-4008-938c-002aaad1b9fd','送僧二首 二','馬戴','唐','唐诗','tang','','[]','龕中破衲自持行，樹下禪牀坐一生。',32,'全唐诗/poet.tang.30000.json','["龕中破衲自持行，樹下禪牀坐一生。", "來往白雲知歲久，滿山猨鳥會經聲。"]'),
('c9620643-8eb0-4c7f-a1aa-8745bc45eb06','贈友人邊遊回','馬戴','唐','唐诗','tang','','[]','遊子新從絕塞回，自言曾上李陵臺。',32,'全唐诗/poet.tang.30000.json','["遊子新從絕塞回，自言曾上李陵臺。", "尊前語盡北風起，秋色蕭條胡鴈來。"]'),
('d2bf42b8-beac-4e81-b1d6-adbc14ab743e','山中作','馬戴','唐','唐诗','tang','','[]','屐齒無泥竹策輕，莓苔梯滑夜難行。',32,'全唐诗/poet.tang.30000.json','["屐齒無泥竹策輕，莓苔梯滑夜難行。", "獨開石室松門裏，月照前山空水聲。"]'),
('7ff3e644-c094-47b7-a546-4d33d9c7fa4f','出塞詞','馬戴','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','金帶連環束戰袍，馬頭衝雪度臨洮。',32,'全唐诗/poet.tang.30000.json','["金帶連環束戰袍，馬頭衝雪度臨洮。", "卷旗夜劫單于帳，亂斫胡兒缺寶刀。"]'),
('fd2ea763-c109-4e41-ad3b-915d801055f4','寄雲臺觀田秀才','馬戴','唐','唐诗','tang','','[]','雲壓松枝拂石窗，幽人獨坐鶴成雙。',32,'全唐诗/poet.tang.30000.json','["雲壓松枝拂石窗，幽人獨坐鶴成雙。", "晚來漱齒敲冰渚，閑讀仙書倚翠幢。"]'),
('ba6e544d-649b-417e-92d7-fd47cb420bde','邊上送楊侍御鞫獄回','馬戴','唐','唐诗','tang','','[]','獄成冤雪晚雲開，豸角威清塞鴈回。',32,'全唐诗/poet.tang.30000.json','["獄成冤雪晚雲開，豸角威清塞鴈回。", "飛將送迎遙避馬，離亭不敢勸金杯。"]'),
('81908fe0-1542-4285-979b-4e9797387df3','射鵰騎','馬戴','唐','唐诗','tang','','[]','蕃面將軍著鼠裘，酣歌衝雪在邊州。',32,'全唐诗/poet.tang.30000.json','["蕃面將軍著鼠裘，酣歌衝雪在邊州。", "獵過黑山猶走馬，寒鵰射落不回頭。"]'),
('e40d606c-4c5f-4217-a0e4-939aee655c0a','高司馬移竹','馬戴','唐','唐诗','tang','','[]','叢居堂下幸君移，翠掩燈窗露葉垂。',32,'全唐诗/poet.tang.30000.json','["叢居堂下幸君移，翠掩燈窗露葉垂。", "莫羨孤生在山者，無人看著拂雲枝。"]'),
('45213ee8-2745-4f4b-b0d5-d1a0add85c13','贈前蔚州崔使君','馬戴','唐','唐诗','tang','','[]','戰回脫劍綰銅魚，塞鴈迎風避隼旟。',32,'全唐诗/poet.tang.30000.json','["戰回脫劍綰銅魚，塞鴈迎風避隼旟。", "欲識前時爲郡政，校成上下考新書。"]'),
('a15343da-3f7e-4d97-8df0-6d9a5b567a40','秋思二首 一','馬戴','唐','唐诗','tang','','[]','萬木秋霖後，孤山夕照餘。',24,'全唐诗/poet.tang.30000.json','["萬木秋霖後，孤山夕照餘。", "田園無歲計，寒近憶樵漁。"]'),
('60a78a67-b2f7-4074-9bd9-6b1ddf0ac5a5','秋思二首 二','馬戴','唐','唐诗','tang','','[]','亭樹霜霰滿，野塘鳧鳥多。',24,'全唐诗/poet.tang.30000.json','["亭樹霜霰滿，野塘鳧鳥多。", "蕙蘭不可折，楚老徒悲歌。"]'),
('51479f73-6ab6-4dc2-8390-7133e7f759ce','黃神谷紀事','馬戴','唐','唐诗','tang','','[]','霹靂振秋岳，折松橫洞門。',24,'全唐诗/poet.tang.30000.json','["霹靂振秋岳，折松橫洞門。", "雲龍忽變化，但覺玉潭昏。"]'),
('4617b59b-f075-4028-866b-7af90fadeecf','過亡友墓','馬戴','唐','唐诗','tang','','[]','憶昨送君葬，今看墳樹高。',24,'全唐诗/poet.tang.30000.json','["憶昨送君葬，今看墳樹高。", "尋思後期者，只是益生勞。"]'),
('eb8ca915-d8a4-4468-bfb3-2a657e5551d4','聞瀑布冰折','馬戴','唐','唐诗','tang','','[]','萬仞冰峭折，寒聲投白雲。',24,'全唐诗/poet.tang.30000.json','["萬仞冰峭折，寒聲投白雲。", "光搖山月墮，我向石牀聞。"]'),
('5d5c1773-a552-4415-8c5a-c303a7f13260','贈道者','馬戴','唐','唐诗','tang','','[]','深居白雲穴，靜注赤松經。',24,'全唐诗/poet.tang.30000.json','["深居白雲穴，靜注赤松經。", "往往龍潭上，焚香禮斗星。"]'),
('f255769e-40bc-4dae-8868-4c9f526d13c3','華下逢楊侍御','馬戴','唐','唐诗','tang','','[]','巨靈掌上月，玉女盆中泉。',24,'全唐诗/poet.tang.30000.json','["巨靈掌上月，玉女盆中泉。", "柱史息車看，孤雲心浩然。"]'),
('bbf73521-d156-4d4a-b7e3-cd4dd537e397','新春聞赦','馬戴','唐','唐诗','tang','','[]','道在猜讒息，仁深疾苦除。',24,'全唐诗/poet.tang.30000.json','["道在猜讒息，仁深疾苦除。", "堯聰能下聽，湯網本來疎。"]'),
('58b35417-c352-4fa4-9445-71a50c95ab96','送李侍御福建從事','馬戴','唐','唐诗','tang','','[]','晉安來越國，蔓草故宮迷。',72,'全唐诗/poet.tang.30000.json','["晉安來越國，蔓草故宮迷。", "釣渚龍應在，琴臺鶴亂栖。", "泛濤明月廣，邊海衆山齊。", "賓府通蘭棹，蠻僧接石梯。", "片雲和瘴濕，孤嶼映帆低。", "上客多詩興，秋猨足夜啼。"]'),
('df7cd263-55f4-478f-83b8-662be9bb3b77','酬刑部姚郎中','馬戴','唐','唐诗','tang','','[]','路岐人不見，尚得記心中。',48,'全唐诗/poet.tang.30000.json','["路岐人不見，尚得記心中。", "月憶瀟湘渚，春生蘭杜叢。", "鳥啼花半落，人散爵方空。", "所贈誠難荅，泠然一雅風。"]'),
('b3154fb8-f95e-47b4-87ab-43e9226c839a','送柳秀才往連州看弟','馬戴','唐','唐诗','tang','','[]','離人非逆旅，有弟謫連州。',48,'全唐诗/poet.tang.30000.json','["離人非逆旅，有弟謫連州。", "楚雨霑猨暮，湘雲拂鴈秋。", "蒹葭行廣澤，星月棹寒流。", "何處江關鏁，風濤阻客愁。"]'),
('542782c9-0673-4ef0-a910-0c7f8a199235','晚眺有懷','馬戴','唐','唐诗','tang','','[]','點點抱離念，曠懷成怨歌。',48,'全唐诗/poet.tang.30000.json','["點點抱離念，曠懷成怨歌。", "高臺試延望，落照在寒波。", "此地芳草歇，舊山喬木多。", "悠然暮天際，但見鳥相過。"]'),
('905a0b01-43d6-456b-b995-954ec7f80019','山中興作','馬戴','唐','唐诗','tang','','[]','高高丹桂枝，嫋嫋女蘿衣。',48,'全唐诗/poet.tang.30000.json','["高高丹桂枝，嫋嫋女蘿衣。", "密葉浮雲過，幽陰暮鳥歸。", "月和風翠動，花落瀑泉飛。", "欲翦蘭爲佩，中林露未晞。"]'),
('6fed9dc4-aa57-4e1f-b52e-dcbc21f243fe','送皇甫協律淮南從事','馬戴','唐','唐诗','tang','','[]','辟書丞相草，招作廣陵行。',48,'全唐诗/poet.tang.30000.json','["辟書丞相草，招作廣陵行。", "隋柳疎淮岸，汀洲接海城。", "楚檣經雨泊，煙月隔潮生。", "誰與同尊俎，雞鸞集虎營。"]'),
('068e4250-c47a-41f8-b17e-26ba19c1bf15','別靈武令狐校書','馬戴','唐','唐诗','tang','','[]','北風吹別思，落月度關河。',48,'全唐诗/poet.tang.30000.json','["北風吹別思，落月度關河。", "樹隱流沙短，山平近塞多。", "鴈池戎馬飲，鵰帳戍人過。", "莫慮行軍苦，華夷道正和。"]'),
('378b1f62-ef1a-445d-bd6c-bc1f67e41847','田氏南樓對月','馬戴','唐','唐诗','tang','','[]','主人同露坐，明月在高臺。',48,'全唐诗/poet.tang.30000.json','["主人同露坐，明月在高臺。", "咽咽陰蟲叫，蕭蕭寒鴈來。", "影搖疎木落，魄轉曙鐘開。", "幸免丹霞映，清光溢酒杯。"]'),
('2f54aaba-e725-497f-bd5b-1d0cf1f330e1','送宗密上人','馬戴','唐','唐诗','tang','','[]','門前九陌塵，石上定中身。',48,'全唐诗/poet.tang.30000.json','["門前九陌塵，石上定中身。", "近放遼天鶴，曾爲南岳人。", "臘高松葉換，雪盡茗芽新。", "一自傳香後，名山願卜鄰。"]'),
('3c54d25a-9dce-4e90-8fb8-01be81bedc6a','白鹿原晚望','馬戴','唐','唐诗','tang','','[]','滻曲鴈飛下，秦原人葬回。',24,'全唐诗/poet.tang.30000.json','["滻曲鴈飛下，秦原人葬回。", "丘墳與城闕，草樹共塵埃。"]'),
('f11cda90-cfcb-43fe-91a9-701992c91c1d','失意書懷呈知己','馬戴','唐','唐诗','tang','','[]','直道何由啓聖君，非才誰敢議論文。',64,'全唐诗/poet.tang.30000.json','["直道何由啓聖君，非才誰敢議論文。", "心存黃籙兼丹訣，家憶青山與白雲。", "麋鹿幽栖閑可近，鴛鸞高舉勢宜分。", "微生不學劉琨輩，劍刃相交擬立勳。"]'),
('6248d782-091d-4134-b106-06597a3c7d59','春日尋滻川王處士','馬戴','唐','唐诗','tang','','[]','碧草徑微斷，白雲扉晚開。',48,'全唐诗/poet.tang.30000.json','["碧草徑微斷，白雲扉晚開。", "罷琴松韻發，鑒水月光來。", "宿鳥排花動，樵童澆竹迴。", "與君同露坐，澗石拂青苔。"]'),
('b03b58aa-ea77-4312-a387-519917d8a083','宿陽臺觀','馬戴','唐','唐诗','tang','','[]','玉洞仙何在，爐香客自焚。',48,'全唐诗/poet.tang.30000.json','["玉洞仙何在，爐香客自焚。", "醮壇圍古木，石磬響寒雲。", "曙月孤霞映，懸流峭壁分。", "心知人世隔，坐與鶴爲羣。"]'),
('715a9521-1779-4728-a918-065dd7d8d84c','寄金州姚使君員外','馬戴','唐','唐诗','tang','','[]','老懷清淨化，乞去守洵陽。',120,'全唐诗/poet.tang.30000.json','["老懷清淨化，乞去守洵陽。", "廢井人應滿，空林虎自藏。", "迸泉疎石竇，殘雨發椒香。", "山缺通巴峽，江流帶楚檣。", "憂農生野思，禱廟結雲裝。", "覆局松移影，聽琴月墮光。", "鳥鳴開郡印，僧去置禪牀。", "罷貢金休鑿，凌寒笋更長。", "退公披鶴氅，高步隔鵷行。", "相見朱門內，麾幢拂曙霜。"]'),
('3dc307d0-81b0-45c6-b403-113a1ec032de','中秋夜坐有懷','馬戴','唐','唐诗','tang','','[]','秋光動河漢，耿耿曙難分。',48,'全唐诗/poet.tang.30000.json','["秋光動河漢，耿耿曙難分。", "墮露垂叢藥，殘星間薄雲。", "心懸赤城嶠，志向紫陽君。", "鴈過海風起，蕭蕭時獨聞。"]'),
('3fe31d82-d0ed-48cf-9bf2-c9a601bffd4c','題鏡湖野老所居','馬戴','唐','唐诗','tang','','[]','湖裏尋君去，樵風往返吹。',48,'全唐诗/poet.tang.30000.json','["湖裏尋君去，樵風往返吹。", "樹喧巢鳥出，路細葑田移。", "漚苧成魚網，枯根是酒巵。", "老年唯自適，生事任羣兒。"]'),
('ebcd3d59-79c6-4ad3-8dad-4d26c961bd2a','題女道士居','馬戴','唐','唐诗','tang','','[]','不餌住雲溪，休丹罷藥畦。',48,'全唐诗/poet.tang.30000.json','["不餌住雲溪，休丹罷藥畦。", "杏花虛結子，石髓任成泥。", "掃地青牛臥，栽松白鶴棲。", "共知仙女麗，莫是阮郎妻。"]'),
('f0f5452c-5d30-49e3-b28e-4c9d5cb4e6a1','送王道士','馬戴','唐','唐诗','tang','','[]','真人俄整舃，雙鶴屢飛翔。',48,'全唐诗/poet.tang.30000.json','["真人俄整舃，雙鶴屢飛翔。", "恐入壺中住，須傳肘後方。", "霓裳雲氣潤，石徑朮苗香。", "一去何時見，仙家日月長。"]'),
('a349aca9-49e5-4bd0-8c56-700071dbf895','送道友入天台山作','馬戴','唐','唐诗','tang','','[]','却憶天台去，移居海島空。',48,'全唐诗/poet.tang.30000.json','["却憶天台去，移居海島空。", "觀寒琪樹碧，雪淺石橋通。", "漱齒飛泉外，餐霞早境中。", "終期赤城裏，披氅與君同。"]'),
('43db82d6-e467-4b63-91a9-9939bee76503','題章野人山居','馬戴','唐','唐诗','tang','','[]','帶郭茅亭詩興饒，回看一曲倚危橋。',64,'全唐诗/poet.tang.30000.json','["帶郭茅亭詩興饒，回看一曲倚危橋。", "門前山色能深淺，壁上湖光自動搖。", "閑花散落填書帙，戲鳥低飛礙柳條。", "向此隱來經幾載，如今已是漢家朝。"]'),
('15c6e5b7-c9ec-41a6-b869-13c8ebe13c01','江中遇客','馬戴','唐','唐诗','tang','','[]','危石江中起，孤雲嶺上還。',24,'全唐诗/poet.tang.30000.json','["危石江中起，孤雲嶺上還。", "相逢皆得意，何處是鄉關。"]'),
('6396ec5b-ee20-4102-9463-2ca22d911c63','期王鍊師不至','馬戴','唐','唐诗','tang','','[]','黃精蒸罷洗瓊桮，林下從留石上苔。',32,'全唐诗/poet.tang.30000.json','["黃精蒸罷洗瓊桮，林下從留石上苔。", "昨日圍棋未終局，多乘白鶴下山來。"]'),
('266e348a-964f-46f7-8c49-cef4ffa6b79c','秋日送僧志幽歸山寺','馬戴','唐','唐诗','tang','','[]','禪室繩牀在翠微，松間荷笠一僧歸。',32,'全唐诗/poet.tang.30000.json','["禪室繩牀在翠微，松間荷笠一僧歸。", "磬聲寂歷宜秋夜，手冷燈前自衲衣。"]'),
('1deddf71-9ab1-41e2-bb7e-2b86d0400cdf','句','馬戴','唐','唐诗','tang','','[]','申胥任向秦庭哭，靳尚終貽楚國憂。',16,'全唐诗/poet.tang.30000.json','["申胥任向秦庭哭，靳尚終貽楚國憂。"]'),
('4f11dd0a-0bac-48a1-89a4-dcf9902c2fa0','寄宜陽兄弟','易重','唐','唐诗','tang','','[]','六年雁序恨分離，詔下今朝遇已知。',64,'全唐诗/poet.tang.30000.json','["六年雁序恨分離，詔下今朝遇已知。", "上國皇風初喜日，御堦恩渥屬身時。", "內庭再考稱文異，聖主宣名獎藝奇。", "故里仙才若相問，一春攀得兩重枝。"]'),
('414118c2-6629-400b-aaba-8ffc9453926e','發蕙風館遇陰不見九華山有作','孟遲','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','我來淮陰城，千江萬山無不經。',142,'全唐诗/poet.tang.30000.json','["我來淮陰城，千江萬山無不經。", "山青水碧千萬丈，奇峯急派何縱橫。", "又聞九華山，山頂連青冥。", "太白有逸韻，使我西南行。", "一步一攀策，前行正雞鳴。", "陰雲冉冉忽飛起，千里萬里危崢嶸。", "譬如天之有日蝕，使我昏沈猶不明。", "人家敲鏡救不得，光陰却屬貪狼星。", "恨亦不能通，言亦不足聽。", "長鞭揮馬出門去，是以九華爲不平。"]'),
('d4be2d7d-dce0-47e0-8992-25e62b961e52','寄浙右舊幕僚','孟遲','唐','唐诗','tang','','[]','由來惡舌駟難追，自古無媒謗所歸。',64,'全唐诗/poet.tang.30000.json','["由來惡舌駟難追，自古無媒謗所歸。", "勾踐豈能容范蠡，李斯何暇救韓非。", "巨拳豈爲雞揮肋，強弩那因鼠發機。", "慚愧故人同鮑叔，此心江柳尚依依。"]'),
('cdb0b2cc-f676-4942-91f2-cb82478d8c00','壯士吟','孟遲','唐','唐诗','tang','','[]','壯士何曾悲，悲即無回期。',24,'全唐诗/poet.tang.30000.json','["壯士何曾悲，悲即無回期。", "如何易水上，未歌淚先垂。"]'),
('192e875f-5fd2-470d-985e-95d5fef52e5b','徐波渡','孟遲','唐','唐诗','tang','','[]','曉月千重樹，春煙十里溪。',24,'全唐诗/poet.tang.30000.json','["曉月千重樹，春煙十里溪。", "過來還過去，此路不知迷。"]'),
('62f6476e-dcd2-45e5-be2a-71f958e24e4d','題嘉祥驛','孟遲','唐','唐诗','tang','','[]','樹頂煙微綠，山根菊暗香。',24,'全唐诗/poet.tang.30000.json','["樹頂煙微綠，山根菊暗香。", "何人獨鞭馬，落日上嘉祥。"]'),
('0a4a2505-e835-4946-8276-1ae297ba945e','懷鄭洎','孟遲','唐','唐诗','tang','','[]','風蘭舞幽香，雨葉墮寒滴。',24,'全唐诗/poet.tang.30000.json','["風蘭舞幽香，雨葉墮寒滴。", "美人來不來，前山看向夕。"]'),
('8e1229a5-ca4f-4d22-b5cb-a2c383d36991','長信宮','孟遲','唐','唐诗','tang','','[]','君恩已盡欲何歸，猶有殘香在舞衣。',32,'全唐诗/poet.tang.30000.json','["君恩已盡欲何歸，猶有殘香在舞衣。", "自恨身輕不如燕，春來還遶御簾飛。"]'),
('671f5b4e-e27b-4e17-ab4e-066751b75352','閨情','孟遲','唐','唐诗','tang','','[]','山上有山歸不得，湘江暮雨鷓鴣飛。',32,'全唐诗/poet.tang.30000.json','["山上有山歸不得，湘江暮雨鷓鴣飛。", "蘼蕪亦是王孫草，莫送春香入客衣。"]'),
('c0e0613e-c047-4459-ba18-fd2802efaa9e','蓮塘','孟遲','唐','唐诗','tang','','[]','脉脉低回殷袖遮，臉橫秋水髻盤鴉。',32,'全唐诗/poet.tang.30000.json','["脉脉低回殷袖遮，臉橫秋水髻盤鴉。", "蓮莖有刺不成折，盡日岸傍空看花。"]'),
('844b3841-0c34-4d9d-bb8a-07377c4fada7','還淮卻寄睢陽','孟遲','唐','唐诗','tang','','[]','梁王池苑已蒼然，滿樹斜陽極浦煙。',32,'全唐诗/poet.tang.30000.json','["梁王池苑已蒼然，滿樹斜陽極浦煙。", "盡日回頭看不見，兩行愁淚上南船。"]'),
('91ffa045-4377-47bf-8807-be1e7cc9ae1e','烏江','孟遲','唐','唐诗','tang','','[]','中分豈是無遺策，百戰空勞不逝騅。',32,'全唐诗/poet.tang.30000.json','["中分豈是無遺策，百戰空勞不逝騅。", "大葉固非人事及，烏江亭長又何知。"]'),
('5580c982-d27d-40fb-9cee-c20e2bdda267','新安故關','孟遲','唐','唐诗','tang','','[]','漢帝英雄重武材，崇山險處鑿門開。',32,'全唐诗/poet.tang.30000.json','["漢帝英雄重武材，崇山險處鑿門開。", "如今更有將軍否，移取潼關向北來。"]'),
('3bdfa91e-4971-4068-94cd-a87e05bfd694','廣陵城','孟遲','唐','唐诗','tang','','[]','紅遶高臺綠遶城，城邊春草傍牆生。',32,'全唐诗/poet.tang.30000.json','["紅遶高臺綠遶城，城邊春草傍牆生。", "隋家不向此中盡，汴水應無東去聲。"]'),
('8c7331f5-925d-4b37-b7a2-f94827e2a98f','過驪山','孟遲','唐','唐诗','tang','','[]','冷日微煙渭水愁，華清宮樹不勝秋。',32,'全唐诗/poet.tang.30000.json','["冷日微煙渭水愁，華清宮樹不勝秋。", "霓裳一曲千門鎖，白盡梨園弟子頭。"]'),
('77078680-2880-4934-9607-edff104b8de5','吳故宮','孟遲','唐','唐诗','tang','','[]','越女歌長君且聽，芙蓉香滿水邊城。',32,'全唐诗/poet.tang.30000.json','["越女歌長君且聽，芙蓉香滿水邊城。", "豈知一日終非主，猶自如今有怨聲。"]'),
('57affaa2-5723-42fc-8d4c-a6d765f7b969','蘭昌宮','孟遲','唐','唐诗','tang','','[]','宮門兩片掩埃塵，牆上無花草不春。',32,'全唐诗/poet.tang.30000.json','["宮門兩片掩埃塵，牆上無花草不春。", "誰見當時禁中事，阿嬌解佩與何人。"]'),
('ad61312c-2a93-4404-9c5d-91f075e3bc0d','宮人斜','孟遲','唐','唐诗','tang','','[]','雲慘煙愁苑路斜，路傍丘冢盡宮娃。',32,'全唐诗/poet.tang.30000.json','["雲慘煙愁苑路斜，路傍丘冢盡宮娃。", "茂陵不是同歸處，空寄香魂著野花。"]'),
('119e2206-6703-49ed-ae95-8c717e0da2d0','句','孟遲','唐','唐诗','tang','','[]','天地有時饒一擲，江山無主任平分。',16,'全唐诗/poet.tang.30000.json','["天地有時饒一擲，江山無主任平分。"]'),
('5ad2ae20-cd1f-4f41-bfa4-0bbfba170b64','和于興宗登越王樓詩','王鐸','唐','唐诗','tang','','[]','謝眺題詩處，危樓壓郡城。',48,'全唐诗/poet.tang.30000.json','["謝眺題詩處，危樓壓郡城。", "雨餘江水碧，雲斷雪山明。", "錦繡來仙境，風光入帝京。", "恨無青玉案，何以報高情。"]'),
('624fbc66-a644-47d9-9c1c-40b049cf0730','謁梓潼張惡子廟','王鐸','唐','唐诗','tang','','[]','盛唐聖主解青萍，欲振新封濟順名。',64,'全唐诗/poet.tang.30000.json','["盛唐聖主解青萍，欲振新封濟順名。", "夜雨龍拋三尺匣，春雲鳳入九重城。", "劒門喜氣隨雷動，玉壘韶光待賊平。", "惟報關東諸將相，柱天功業賴陰兵。"]'),
('b96c0fe1-5315-4eae-9b61-3465e28ac073','罷都統守鎮滑州作','王鐸','唐','唐诗','tang','','[]','用軍何事敢遷延，恩重才輕分使然。',96,'全唐诗/poet.tang.30000.json','["用軍何事敢遷延，恩重才輕分使然。", "黜詔已聞來闕下，檄書猶未遍軍前。", "腰間盡解蘇秦印，波上虛迎范蠡船。", "正會星辰扶北極，却驅戈甲鎮南燕。", "三塵上相逢明主，九合諸侯媿昔賢。", "看却中興扶大業，殺身無路好歸田。"]'),
('c3ba9321-6bc3-4af7-9e0d-5b6ddab1a1ad','句','王鐸','唐','唐诗','tang','','[]','華表尚迷丁令鶴，竹坡猶認葛溪龍。',16,'全唐诗/poet.tang.30000.json','["華表尚迷丁令鶴，竹坡猶認葛溪龍。"]'),
('a2ab5fa3-8132-4fba-94b6-cda1db4755dd','中秋月直禁苑','鄭畋','唐','唐诗','tang','','[]','禁署方懷忝，綸闈已再加。',48,'全唐诗/poet.tang.30000.json','["禁署方懷忝，綸闈已再加。", "暫來西掖路，還整上清槎。", "恍惚歸丹地，深嚴宿絳霞。", "幽襟聊自適，閑弄紫薇花。"]'),
('1567757f-34ad-40e6-8bf2-d2eb76454a2c','麥穗兩岐','鄭畋','唐','唐诗','tang','','[]','聖慮憂千畝，嘉苗薦兩岐。',72,'全唐诗/poet.tang.30000.json','["聖慮憂千畝，嘉苗薦兩岐。", "如雲方表盛，成穗忽標奇。", "瑞露縱橫滴，祥風左右吹。", "謳歌連上苑，化日遍平陂。", "史冊書堪重，丹青畫更宜。", "願依連理樹，俱作萬年枝。"]'),
('729d87a8-7286-48e3-9b02-5032c4ef5d39','五月一日紫宸候對時屬禁直穿內而行因書六韻','鄭畋','唐','唐诗','tang','','[]','朱夏五更後，步廊三里餘。',72,'全唐诗/poet.tang.30000.json','["朱夏五更後，步廊三里餘。", "有人從翰苑，穿入內中書。", "漏響飄銀箭，燈光照玉除。", "禁扉猶鏁鑰，宮妓已妝梳。", "紫府遊應似，鈞天夢不如。", "塵埃九重外，誰信在清虛。"]'),
('f3a62c39-2698-4d68-842f-a9ff595faa85','題緱山王子晉廟','鄭畋','唐','唐诗','tang','','["\u8861\u5c71"]','有昔靈王子，吹笙遡泬㵳。',264,'全唐诗/poet.tang.30000.json','["有昔靈王子，吹笙遡泬㵳。", "六宮攀不住，三島去相招。", "亡國原陵古，賓天歲月遙。", "無蹊窺海曲，有廟訪山椒。", "石帳龍蛇拱，雲櫳彩翠銷。", "露壇裝琬琰，真像寫松喬。", "珠館青童宴，琳宮阿母朝。", "氣輿仙女侍，天馬吏兵調。", "湘妓紅絲瑟，秦郎白管簫。", "西城要綽約，南嶽命嬌嬈。", "句曲觴金洞，天台嘯石橋。", "晚花珠弄蘂，春茹玉生苗。", "二景神光秘，三元寶籙饒。", "霧垂鴉翅髮，冰束虎章腰。", "鶴馭爭銜箭，龍妃合獻綃。", "衣從星渚浣，丹就日宮燒。", "物外花嘗滿，人間葉自凋。", "望臺悲漢戾，閱水笑梁昭。", "古殿香殘炧，荒堦柳長條。", "幾曾期七日，無復降重霄。", "嵩嶺連天漢，伊瀾入海潮。", "何由得真訣，使我珮環飄。"]'),
('7f9d14e5-c2d4-45a1-beb2-752efa1e3db7','初秋寓直三首 一','鄭畋','唐','唐诗','tang','','[]','曉星獨挂結麟樓，三殿風高藥樹秋。',32,'全唐诗/poet.tang.30000.json','["曉星獨挂結麟樓，三殿風高藥樹秋。", "玉笛數聲飄不住，問人依約在東頭。"]'),
('0dcc7b94-64da-4f67-92cb-c47a6d347b05','初秋寓直三首 二','鄭畋','唐','唐诗','tang','','[]','宿鳥翩翩落照微，石臺樓閣鎖重扉。',32,'全唐诗/poet.tang.30000.json','["宿鳥翩翩落照微，石臺樓閣鎖重扉。", "步廊無限金羈響，應是諸司扈從歸。"]'),
('d5311784-d491-40ae-bea2-0888c5dcf2d4','初秋寓直三首 三','鄭畋','唐','唐诗','tang','','[]','幽閣焚香萬慮凝，下簾胎息過禪僧。',32,'全唐诗/poet.tang.30000.json','["幽閣焚香萬慮凝，下簾胎息過禪僧。", "玉堂分照無人後，消盡金盆一碗冰。"]'),
('919b77b2-59b8-4517-86e9-44e0218e539b','夜景又作','鄭畋','唐','唐诗','tang','','[]','鈴絛無響閉珠宮，小閣涼添玉蘂風。',32,'全唐诗/poet.tang.30000.json','["鈴絛無響閉珠宮，小閣涼添玉蘂風。", "枕簟滿牀明月到，自疑身在五雲中。"]'),
('84fed06b-c500-4cdb-9336-32c87acd98ad','杪秋夜直','鄭畋','唐','唐诗','tang','','[]','蘂宮裁詔與宵分，雖在青雲憶白雲。',32,'全唐诗/poet.tang.30000.json','["蘂宮裁詔與宵分，雖在青雲憶白雲。", "待報君恩了歸去，山翁何急草移文。"]'),
('3bfd7596-9288-4a38-9d0b-c77d6f9e1ef1','禁直寄崔員外','鄭畋','唐','唐诗','tang','','[]','銀臺樓北蘂珠宮，敻與人間路不同。',32,'全唐诗/poet.tang.30000.json','["銀臺樓北蘂珠宮，敻與人間路不同。", "在省五更春睡侶，早來分夢玉堂中。"]'),
('cfba46c4-2a0b-467a-b108-68bcfe8248b7','聞號','鄭畋','唐','唐诗','tang','','[]','陛兵偏近羽林營，夜靜仍傳禁號聲。',32,'全唐诗/poet.tang.30000.json','["陛兵偏近羽林營，夜靜仍傳禁號聲。", "應笑執金雙闕下，近南猶隔兩重城。"]'),
('70d85846-0705-4732-86bb-3e6c218800d5','禁直和人飲酒','鄭畋','唐','唐诗','tang','','[]','卉醴陀花物外香，清濃標格勝椒漿。',32,'全唐诗/poet.tang.30000.json','["卉醴陀花物外香，清濃標格勝椒漿。", "我來尚有鈞天會，猶得金尊半日嘗。"]'),
('14c301fb-8db1-4220-bded-7b13f121a7ec','下直早出','鄭畋','唐','唐诗','tang','','[]','諸司人盡馬蹄稀，紫帕雲竿九釘歸。',32,'全唐诗/poet.tang.30000.json','["諸司人盡馬蹄稀，紫帕雲竿九釘歸。", "偏覺石臺清貴處，牓懸金字射晴暉。"]'),
('52854c29-5ef8-45bd-9044-9966bcaad0a3','金鑾坡上南望','鄭畋','唐','唐诗','tang','','[]','玉晨鐘韻上清虛，畫戟祥煙拱帝居。',32,'全唐诗/poet.tang.30000.json','["玉晨鐘韻上清虛，畫戟祥煙拱帝居。", "極眼向南無限地，綠煙深處認中書。"]'),
('97b16580-163e-4807-9a76-846468bfe735','酬隱珪舍人寄紅燭','鄭畋','唐','唐诗','tang','','[]','蜜炬殷紅畫不如，且將歸去照吾廬。',32,'全唐诗/poet.tang.30000.json','["蜜炬殷紅畫不如，且將歸去照吾廬。", "今來併得三般事，靈運詩篇逸少書。"]'),
('7e75853a-bf7a-4d8d-b3e9-0537f4ed913a','馬嵬坡','鄭畋','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u5e26\u6709\u5730\u540d", "\u548f\u53f2", "\u5730\u540d"]','[玄]宗回馬楊妃死，雲雨雖亡日月新。',34,'全唐诗/poet.tang.30000.json','["[玄]宗回馬楊妃死，雲雨雖亡日月新。", "終是聖明天子事，景陽宮井又何人。"]'),
('e830e284-dfea-4a90-b604-bd1ae75431d9','句','鄭畋','唐','唐诗','tang','','[]','圓明青[䭀]飯，光潤碧霞漿。',30,'全唐诗/poet.tang.30000.json','["圓明青[䭀]飯，光潤碧霞漿。", "浴殿晴秋倘中謝，殘英猶可醉瓊杯。"]'),
('aab33b7c-cb01-4ee4-8308-5cfd522caca4','題九華山','譚銖','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','憶聞九華山，尚在童稚年。',180,'全唐诗/poet.tang.30000.json','["憶聞九華山，尚在童稚年。", "浮沈任名路，窺仰會無緣。", "罷職池陽時，復遭迎送牽。", "因茲契誠願，矚望枕席前。", "況值春正濃，氣色無不全。", "或如碧玉靜，或似青靄鮮。", "或接白雲堆，或暎紅霞天。", "呈姿既不一，變態何啻千。", "巍峩本無動，崇峻性豈偏。", "外景自隱隱，潛虛固幽玄。", "我來暗凝情，務道志更堅。", "色與山異性，性併山亦然。", "境變山不動，性存形自遷。", "自遷不阻俗，自定不失賢。", "浮華與朱紫，安可迷心田。"]'),
('10185486-fd2c-41df-8234-8326b619e1fe','真娘墓','譚銖','唐','唐诗','tang','','[]','武丘山下冢纍纍，松柏蕭條盡可悲。',32,'全唐诗/poet.tang.30000.json','["武丘山下冢纍纍，松柏蕭條盡可悲。", "何事世人偏重色，真娘墓上獨題詩。"]'),
('d1dbf197-b9e1-4864-b9e3-f89c7ee53451','望九華山','盧嗣立','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','九華深翠落軒楹，迥眺澄江氣象明。',64,'全唐诗/poet.tang.30000.json','["九華深翠落軒楹，迥眺澄江氣象明。", "不遇陰霾孤岫隱，正當寒日衆峯呈。", "坐觀風雪銷煩思，惜別煙嵐駐曉行。", "得路歸山期早訣，夜來潛已告精誠。"]'),
('49c442a7-b1e4-4871-bb55-9e18a63d8a4e','應舉日寄兄弟','朱可名','唐','唐诗','tang','','[]','廢刈鏡湖田，上書紫閣前。',48,'全唐诗/poet.tang.30000.json','["廢刈鏡湖田，上書紫閣前。", "愁人久委地，詩道未聞天。", "不是燒金手，徒拋釣月船。", "多慚兄弟意，不敢問林泉。"]'),
('510310a8-01b0-43a5-9622-4bc31edd5573','河出榮光','張良器','唐','唐诗','tang','','[]','引派崑山峻，朝宗海路長。',96,'全唐诗/poet.tang.30000.json','["引派崑山峻，朝宗海路長。", "千齡逢聖主，五色瑞榮光。", "隱暎浮中國，晶明助太陽。", "坤維連浩漫，天漢接微茫。", "丹闕清氛裏，函關紫氣旁。", "位尊常守伯，道泰每呈祥。", "習坎靈逾久，居卑德有常。", "龍門如可涉，忠信是舟梁。"]'),
('d6662430-2909-49a2-9757-421d75ca0097','新雪八韻','薛能','唐','唐诗','tang','','[]','大雪滿初晨，開門萬象新。',96,'全唐诗/poet.tang.30000.json','["大雪滿初晨，開門萬象新。", "龍鍾雞未起，蕭索我何貧。", "耀若花前境，清如物外身。", "細飛斑戶牖，乾灑亂松筠。", "正色凝高嶺，隨流助要津。", "鼎消微是滓，車碾半和塵。", "茶興留詩客，瓜情想戍人。", "終篇本無字，誰別勝陽春。"]'),
('afecc7e9-3aa7-4b8b-9d57-7c39827e28f6','國學試風化下','薛能','唐','唐诗','tang','','[]','霽闕露穹崇，含生仰聖聰。',72,'全唐诗/poet.tang.30000.json','["霽闕露穹崇，含生仰聖聰。", "英明高比日，聲敎下如風。", "靜發宸居內，低來品物中。", "南薰歌自溥，北極響皆通。", "蘋末看無狀，人間覺有功。", "因今委泥者，覩此忘途窮。"]'),
('77d2f6f6-15d2-4d1a-a3d3-e3a61f4cf506','昇平詞十首 一','薛能','唐','唐诗','tang','','[]','瑞氣遶宮樓，皇居信上遊。',48,'全唐诗/poet.tang.30000.json','["瑞氣遶宮樓，皇居信上遊。", "遠岡連聖祚，平地載神州。", "會合皆重譯，潺湲近八流。", "中興豈假問，據此自千秋。"]'),
('04088b46-d767-43b1-b8f0-2d14b5827c32','昇平詞十首 二','薛能','唐','唐诗','tang','','[]','寥泬敞延英，朝班立位橫。',48,'全唐诗/poet.tang.30000.json','["寥泬敞延英，朝班立位橫。", "宣傳無草動，拜舞有衣聲。", "鴛瓦霜消濕，蟲絲日照明。", "辛勤自不到，遙見似前程。"]'),
('345f6e72-a85e-476f-8e7b-610983591bce','昇平詞十首 三','薛能','唐','唐诗','tang','','[]','處處是歡心，時康歲已深。',48,'全唐诗/poet.tang.30000.json','["處處是歡心，時康歲已深。", "不同三尺劒，應似五弦琴。", "壽笑山猶盡，明嫌日有陰。", "何當憐一物，亦遣斷愁吟。"]'),
('e2764933-6410-42f9-936b-cb90fd947c55','昇平詞十首 四','薛能','唐','唐诗','tang','','[]','曙質絕埃氛，彤庭列禁軍。',48,'全唐诗/poet.tang.30000.json','["曙質絕埃氛，彤庭列禁軍。", "聖顏初對日，龍尾競緣雲。", "佩響交成韻，簾陰暖帶紋。", "逍遙豈有事，於此詠南薰。"]'),
('3234c655-7b1b-4be7-bdc3-7f6c93106dae','昇平詞十首 五','薛能','唐','唐诗','tang','','[]','一物至周天，洪纖盡晏然。',48,'全唐诗/poet.tang.30000.json','["一物至周天，洪纖盡晏然。", "車書無異俗，甲子並豐年。", "奇技皆歸朴，征夫亦服田。", "君王故不有，台鼎合韋弦。"]'),
('4c7df6d8-f7cc-4476-b568-7fec18cc4cb7','昇平詞十首 六','薛能','唐','唐诗','tang','','[]','日日聽歌謠，區中盡祝堯。',48,'全唐诗/poet.tang.30000.json','["日日聽歌謠，區中盡祝堯。", "蟲蝗初不害，夷狄近全銷。", "史筆惟書瑞，天臺絕見妖。", "因令匹夫志，轉欲事清朝。"]'),
('c72a9af5-ed08-4627-bf20-9ee339648f41','昇平詞十首 七','薛能','唐','唐诗','tang','','[]','品物盡昭蘇，神功復帝謨。',48,'全唐诗/poet.tang.30000.json','["品物盡昭蘇，神功復帝謨。", "他時應有壽，當代且無虞。", "賜曆通遐俗，移關入半胡。", "鷦鷯一何幸，於此寄微軀。"]'),
('d4063565-5be6-46b8-ab58-3d6802921d6e','昇平詞十首 八','薛能','唐','唐诗','tang','','[]','無戰復無私，堯時即此時。',48,'全唐诗/poet.tang.30000.json','["無戰復無私，堯時即此時。", "焚香臨極早，待月卷簾遲。", "端拱乾坤內，何言黈纊垂。", "君看聖明驗，只此是神龜。"]'),
('bc4435cb-a58b-43bc-bfa5-9cee777affe2','昇平詞十首 九','薛能','唐','唐诗','tang','','[]','旭日上清穹，明堂坐聖聰。',48,'全唐诗/poet.tang.30000.json','["旭日上清穹，明堂坐聖聰。", "衣裳承瑞氣，冠冕蓋重瞳。", "花木經宵露，旌旗入仗風。", "何期於此地，見說是神工。"]'),
('da7c0225-506f-4c87-bda2-019cce9e19dd','昇平詞十首 十','薛能','唐','唐诗','tang','','[]','五帝三皇主，蕭曹魏邴臣。',48,'全唐诗/poet.tang.30000.json','["五帝三皇主，蕭曹魏邴臣。", "文章惟返朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。", "昇平不可記，所見是閑人。"]'),
('31b9eaa8-608b-47f3-ad36-c79c48f39ecb','送馮溫往河外','薛能','唐','唐诗','tang','','[]','琴劒事行裝，河關出北方。',48,'全唐诗/poet.tang.30000.json','["琴劒事行裝，河關出北方。", "秦音盡河內，魏畫自黎陽。", "野日村苗熟，秋霜館葉黃。", "風沙問船處，應得立清漳。"]'),
('b708fe60-6657-42e2-a55e-bbd2c42499a4','送從兄之太原副使','薛能','唐','唐诗','tang','','["\u534e\u5c71"]','少載琴書去，須知暫佐軍。',48,'全唐诗/poet.tang.30000.json','["少載琴書去，須知暫佐軍。", "初程見西嶽，盡室渡橫汾。", "元日何州在，枯風宿館聞。", "都門送行處，青紫騎紛紛。"]'),
('8306e008-e7cb-4030-bdab-dc2a2472e0a2','送馬戴書記之太原','薛能','唐','唐诗','tang','','[]','一曲大河聲，全家幾日行。',48,'全唐诗/poet.tang.30000.json','["一曲大河聲，全家幾日行。", "從容長約夜，差互忽離城。", "鎮北胡沙淺，途中霍嶽橫。", "相逢莫已訊，詩雅負雄名。"]'),
('6f31e8ab-68d8-4cac-8694-474587f59e78','送友人出塞','薛能','唐','唐诗','tang','','[]','榆關到不可，何況出榆關。',48,'全唐诗/poet.tang.30000.json','["榆關到不可，何況出榆關。", "春草臨岐斷，邊樓帶日閑。", "人歸穹帳外，鳥亂廢營間。", "此地堪愁想，霜前作意還。"]'),
('77fcf781-bdb6-4825-a261-76f2a0623ff9','送李溟出塞','薛能','唐','唐诗','tang','','[]','邊城官尚惡，況乃是羈遊。',48,'全唐诗/poet.tang.30000.json','["邊城官尚惡，況乃是羈遊。", "別路應相憶，離亭更少留。", "黃沙人外闊，飛雪馬前稠。", "甚險穹廬宿，無爲過代州。"]'),
('028eb480-7fbe-4cde-95b5-61c1fa5683e3','寄終南隱者','薛能','唐','唐诗','tang','','[]','海日東南出，應開嶺上扉。',48,'全唐诗/poet.tang.30000.json','["海日東南出，應開嶺上扉。", "掃壇花入篲，科竹露霑衣。", "飯後嫌身重，茶中見鳥歸。", "相思愛民者，難說與親違。"]'),
('98ab0ba9-c087-4fa3-b75a-9754529fe829','贈隱者','薛能','唐','唐诗','tang','','[]','自得高閑性，平生向北棲。',48,'全唐诗/poet.tang.30000.json','["自得高閑性，平生向北棲。", "月潭雲影斷，山葉雨聲齊。", "庭樹人書匝，欄花鳥坐低。", "相留永不忘，經宿話丹梯。"]'),
('9e5a15ce-95bc-44b9-a3ba-6f44f73867ad','惜春','薛能','唐','唐诗','tang','','[]','花開亦花落，時節暗中遷。',48,'全唐诗/poet.tang.30000.json','["花開亦花落，時節暗中遷。", "無計延春日，可能留少年。", "小叢初散蝶，高柳即聞蟬。", "繁豔歸何處，滿山啼杜鵑。"]'),
('1d22aca8-9cd4-4177-a871-dc56d930c714','送人自蘇州之長沙縣官','薛能','唐','唐诗','tang','','["\u8861\u5c71"]','驅馬復乘流，何時發虎丘？',48,'全唐诗/poet.tang.30000.json','["驅馬復乘流，何時發虎丘？", "全家上南嶽，一尉事諸侯。", "茶煮朝宗水，船停調角州。", "炎方好將息，卑濕舊堪憂。"]'),
('fd8b60f4-8ffd-4a3b-b96a-4ea00f11f422','早春歸山中舊居','薛能','唐','唐诗','tang','','[]','茫茫驅匹馬，歸處是荒榛。',48,'全唐诗/poet.tang.30000.json','["茫茫驅匹馬，歸處是荒榛。", "猨跡破庭雪，鼠蹤生甑塵。", "開門衝網斷，掃葉放苔勻。", "爲惜詩情錯，應難致此身。"]'),
('934120ad-883a-4701-9df6-097bfb08c20a','麟中寓居寄蒲中友人','薛能','唐','唐诗','tang','','[]','蕭條秋雨地，獨院阻同羣。',48,'全唐诗/poet.tang.30000.json','["蕭條秋雨地，獨院阻同羣。", "一夜驚爲客，多年不見君。", "邊心生落日，鄉思羨歸雲。", "更在相思處，子規燈下聞。"]'),
('02096dd9-1734-4358-81f0-98ce21febd85','關中送別','薛能','唐','唐诗','tang','','["\u9ec4\u6cb3"]','一行千里外，幾事寸心間。',48,'全唐诗/poet.tang.30000.json','["一行千里外，幾事寸心間。", "才子貧堪歎，男兒別是閑。", "黃河淹華岳，白日照潼關。", "若值鄉人問，終軍賤不還。"]'),
('b7094d6a-d2c4-47e9-b19d-d8d2f528e40a','中秋夜寄李溟','薛能','唐','唐诗','tang','','[]','滿魄斷埃氛，牽吟並舍聞。',48,'全唐诗/poet.tang.30000.json','["滿魄斷埃氛，牽吟並舍聞。", "一年唯此夜，到晚願無雲。", "待賞從初出，看行過二分。", "嚴城亦已閉，悔不預期君。"]'),
('8303cd6a-d38e-420a-98a4-ccd407ef8d73','贈禪師','薛能','唐','唐诗','tang','','[]','夢想青山寺，前年住此中。',48,'全唐诗/poet.tang.30000.json','["夢想青山寺，前年住此中。", "夜堂吹竹雨，春地落花風。", "舊句師曾見，清齋我亦同。", "浮生蹇莫問，辛苦未成功。"]'),
('08a2fe3c-057f-40e7-ace2-6a2513588589','送禪僧','薛能','唐','唐诗','tang','','[]','寒空孤鳥度，落日一僧歸。',48,'全唐诗/poet.tang.30000.json','["寒空孤鳥度，落日一僧歸。", "近寺路聞梵，出郊風滿衣。", "步搖瓶浪起，盂戛磬聲微。", "還坐棲禪所，荒山月照扉。"]'),
('0b824656-b275-4123-8323-5e79d417dea0','贈隱者','薛能','唐','唐诗','tang','','[]','門前雖有徑，絕向世間行。',48,'全唐诗/poet.tang.30000.json','["門前雖有徑，絕向世間行。", "薙草因逢藥，移花便得鶯。", "甘貧原是道，苦學不爲名。", "莫怪蒼髭晚，無機任世情。"]'),
('7ac7ed6a-cbc8-464f-894d-3fe8da56063b','冬日送僧歸吳中舊居','薛能','唐','唐诗','tang','','[]','去掃冬林下，閑持未徧經。',48,'全唐诗/poet.tang.30000.json','["去掃冬林下，閑持未徧經。", "爲山低鑿牖，容月廣開庭。", "舊葉雲千里，生涯水一瓶。", "還應覓新句，看雪倚禪扃。"]'),
('f71ef698-2204-4c30-9ee2-f9dcebb80ed4','恭禧皇太后挽歌詞三首 一','薛能','唐','唐诗','tang','','[]','八月曾殊選，三星固異儀。',48,'全唐诗/poet.tang.30000.json','["八月曾殊選，三星固異儀。", "祔陵經灞滻，歸賵雜華夷。", "旌去題新諡，宮存鏁素幃。", "重泉應不恨，生見太平時。"]'),
('45c6e213-cc43-4c89-a21e-95f3a90fcb7e','恭禧皇太后挽歌詞三首 二','薛能','唐','唐诗','tang','','[]','月落娥兼隱，宮空后豈還。',48,'全唐诗/poet.tang.30000.json','["月落娥兼隱，宮空后豈還。", "銜哀窮地界，親蒞泣天顏。", "舊住留丹藥，新陵在碧山。", "國人傷莫及，應只詠關關。"]'),
('48172562-5aef-49c6-ae42-12292b361e84','恭禧皇太后挽歌詞三首 三','薛能','唐','唐诗','tang','','[]','配聖三朝隔，靈儀萬姓哀。',48,'全唐诗/poet.tang.30000.json','["配聖三朝隔，靈儀萬姓哀。", "多年好黃老，舊日薦賢才。", "道著標彤管，宮閑閉綠苔。", "平生六衣在，曾著祀高禖。"]'),
('e40dcfce-c511-4740-99a8-d19c9ebb0852','送胡澳下第歸蒲津','薛能','唐','唐诗','tang','','[]','無媒甘下飛，君子尚麻衣。',48,'全唐诗/poet.tang.30000.json','["無媒甘下飛，君子尚麻衣。", "歲月終榮在，家園近且歸。", "山光臨舜廟，河氣隔王畿。", "甚積湯原思，青青宿麥肥。"]'),
('5e191e57-f8fb-4321-8036-0959aae25b3d','春日閑居','薛能','唐','唐诗','tang','','[]','權門多見薄，吾道豈終行。',48,'全唐诗/poet.tang.30000.json','["權門多見薄，吾道豈終行。", "散地徒憂國，良時不在城。", "花繁春正王，茶美夢初驚。", "賴有茲文在，猶堪暢此生。"]'),
('07eceda2-115a-4e64-80d8-7fddb48b22c6','題逃戶','薛能','唐','唐诗','tang','','[]','幾世瞢農桑，凶年竟失鄉。',48,'全唐诗/poet.tang.30000.json','["幾世瞢農桑，凶年竟失鄉。", "朽關生濕菌，傾屋照斜陽。", "雨水淹殘臼，葵花壓倒牆。", "明時豈致此，應自負蒼蒼。"]'),
('0b1418cd-3d56-48dd-abd1-9e2863f9f4a8','郊居荅客','薛能','唐','唐诗','tang','','[]','傍舍蟲聲滿，殘秋宿雨村。',48,'全唐诗/poet.tang.30000.json','["傍舍蟲聲滿，殘秋宿雨村。", "遠勞才子騎，光顧野人門。", "敗葉盤空蔓，彫叢露暗根。", "相攜未盡語，川月照黃昏。"]'),
('bae29f55-2148-462c-8c64-a2b6b03dc6c0','早春歸山中舊居','薛能','唐','唐诗','tang','','[]','綠草閉閑院，悄然花正開。',48,'全唐诗/poet.tang.30000.json','["綠草閉閑院，悄然花正開。", "新年人未去，戊日燕還來。", "雨地殘枯沫，燈窗積舊煤。", "歸田語不忘，樗散料非才。"]'),
('228fa652-eea8-4900-b4cc-21327395011b','下第後春日長安寓居三首 一','薛能','唐','唐诗','tang','','[]','一榜盡精選，此身猶陸沈。',48,'全唐诗/poet.tang.30000.json','["一榜盡精選，此身猶陸沈。", "自無功讜分，敢抱怨尤心。", "暖陌開花氣，春居閉日陰。", "相知豈不有，知淺未知深。"]'),
('9de7e928-d9f7-4162-b7c1-85e47235e2bf','下第後春日長安寓居三首 二','薛能','唐','唐诗','tang','','[]','暫屈固何恨，所憂無此時。',48,'全唐诗/poet.tang.30000.json','["暫屈固何恨，所憂無此時。", "隔年空仰望，臨日又參差。", "勞力且成病，壯心能不衰。", "猶將琢磨意，更欲候宗師。"]'),
('ce50954c-e00b-4c17-abb0-4d782936b82a','下第後春日長安寓居三首 三','薛能','唐','唐诗','tang','','[]','關東歸不得，豈是愛他鄉。',48,'全唐诗/poet.tang.30000.json','["關東歸不得，豈是愛他鄉。", "草碧餘花落，春閑白日長。", "全家期聖澤，半路敢農桑。", "獨立應無侶，浮生欲自傷。"]'),
('88877dbb-3e4d-40a8-8626-3a13951718c0','春早選寓長安二首 一','薛能','唐','唐诗','tang','','[]','疎拙自沈昏，長安豈是村。',48,'全唐诗/poet.tang.30000.json','["疎拙自沈昏，長安豈是村。", "春非閑客事，花在五侯門。", "道僻惟憂禍，詩深不敢論。", "揚雄若有薦，君聖合承恩。"]'),
('b77f6043-0350-434b-ac27-995a33036c76','春早選寓長安二首 二','薛能','唐','唐诗','tang','','[]','舊論已浮海，此心猶滯秦。',48,'全唐诗/poet.tang.30000.json','["舊論已浮海，此心猶滯秦。", "上僚如報國，公道豈無人。", "巖隱懸溪瀑，城居入榻塵。", "漁舟即擬去，不待晚年身。"]'),
('dc66aeea-7169-4e2f-ba0a-ed9b67ebda12','送進士許棠下第東歸','薛能','唐','唐诗','tang','','[]','長安那不住，西笑又東行。',48,'全唐诗/poet.tang.31000.json','["長安那不住，西笑又東行。", "若以貧無計，何因事有成。", "雲峰天外出，江色草中明。", "謾忝相於分，吾言世甚輕。"]'),
('afb0834e-6d83-4ebf-8538-b74f76b15867','詠島','薛能','唐','唐诗','tang','','[]','孤島如江上，詩家猶閉門。',48,'全唐诗/poet.tang.31000.json','["孤島如江上，詩家猶閉門。", "一池分倒影，空舸繫荒根。", "煙濕高吟石，雲生偶坐痕。", "登臨有新句，公退與誰論。"]'),
('7adca8b8-aedf-4568-9d31-6469c2a39414','冬日寫懷','薛能','唐','唐诗','tang','','[]','幕府盡平蠻，客留戎閫間。',48,'全唐诗/poet.tang.31000.json','["幕府盡平蠻，客留戎閫間。", "急流霜夾水，輕靄日連山。", "設醴徒慙楚，爲郎未姓顏。", "斯文苦不勝，會擬老民間。"]'),
('df9ec30c-abcd-41ea-bf28-97b417b0466c','和楊中丞早春即事','薛能','唐','唐诗','tang','','[]','貴宅登臨地，春來見物華。',48,'全唐诗/poet.tang.31000.json','["貴宅登臨地，春來見物華。", "遠江橋外色，繁杏竹邊花。", "戍客烽樓迥，文君酒幔斜。", "新題好不極，珠府未窮奢。"]'),
('0249dac2-b35c-4f36-84b6-6aeea1ba443a','聞官軍破吉浪戎小而固慮史氏遺忽因記爲二章 一','薛能','唐','唐诗','tang','','[]','一戰便抽兵，蠻孤吉浪平。',48,'全唐诗/poet.tang.31000.json','["一戰便抽兵，蠻孤吉浪平。", "通連無舊穴，要害有新城。", "晝卒烽前寢，春農界上耕。", "高樓一擬望，新雨劒南清。"]'),
('5f26a797-019f-4028-af1a-2bfac690fb91','聞官軍破吉浪戎小而固慮史氏遺忽因記爲二章 二','薛能','唐','唐诗','tang','','[]','瀘水斷囂氛，妖巢已自焚。',48,'全唐诗/poet.tang.31000.json','["瀘水斷囂氛，妖巢已自焚。", "漢江無敵國，蠻物在迴軍。", "越雟通遊國，苴哶閉聚蚊。", "空餘羅鳳曲，哀思滿邊雲。"]'),
('9ab3a7d2-5d89-4471-b94f-d10d78722aae','寒食有懷','薛能','唐','唐诗','tang','','[]','流落傷寒食，登臨望歲華。',48,'全唐诗/poet.tang.31000.json','["流落傷寒食，登臨望歲華。", "村毬高過索，墳樹綠和花。", "晉聚應搜火，秦喧定走車。", "誰知恨榆柳，風景似吾家。"]'),
('1c0322b7-ad73-4406-8594-75182650064e','綿樓','薛能','唐','唐诗','tang','','[]','溪邊人浣紗，樓下海棠花。',48,'全唐诗/poet.tang.31000.json','["溪邊人浣紗，樓下海棠花。", "極望雖懷土，多情擬置家。", "前山應象外，此地已天涯。", "未有銷憂賦，梁王禮欲奢。"]'),
('fd93d7b5-9729-43f6-80af-539b8a7ccc67','雕堂','薛能','唐','唐诗','tang','','[]','丈室久多病，小園晴獨遊。',48,'全唐诗/poet.tang.31000.json','["丈室久多病，小園晴獨遊。", "鳴蛩孤燭雨，啅雀一籬秋。", "聖主恩難謝，生靈志亦憂。", "他年誰識我，心跡在徐州。"]'),
('d4679e47-a212-452d-8039-048a86955f79','贈歌人','薛能','唐','唐诗','tang','','[]','溫燠坐相侵，羅襦一水沈。',48,'全唐诗/poet.tang.31000.json','["溫燠坐相侵，羅襦一水沈。", "拜深知有意，令背不無心。", "近住應名玉，前生約姓陰。", "東山期已定，相許便抽簪。"]'),
('2a973802-1f1d-470d-a281-14ac37174dcb','柘枝詞三首 一','薛能','唐','唐诗','tang','','[]','同營三十萬，震鼓伐西羌。',36,'全唐诗/poet.tang.31000.json','["同營三十萬，震鼓伐西羌。", "戰血黏秋草，征塵攪夕陽。", "歸來人不識，帝里獨戎裝。"]'),
('ebeac82d-2c4b-41cc-86d3-fabb837b7a1a','柘枝詞三首 二','薛能','唐','唐诗','tang','','[]','懸軍征拓羯，內地隔蕭關。',36,'全唐诗/poet.tang.31000.json','["懸軍征拓羯，內地隔蕭關。", "日色崑崙上，風聲朔漠間。", "何當千萬騎，颯颯貳師還。"]'),
('174b7902-a90c-492a-baea-4627aa556ea5','柘枝詞三首 三','薛能','唐','唐诗','tang','','[]','意氣成功日，春風起絮天。',38,'全唐诗/poet.tang.31000.json','["意氣成功日，春風起絮天。", "樓臺新邸第，歌舞小嬋娟。", "急破[催]搖曳，羅衫半脫肩。"]'),
('6a748148-082d-4666-ba95-438f2f7f6837','詠柳花','薛能','唐','唐诗','tang','','[]','浮生失意頻，起絮又飄淪。',72,'全唐诗/poet.tang.31000.json','["浮生失意頻，起絮又飄淪。", "發自誰家樹，飛來獨院春。", "朝容縈斷砌，晴影過諸鄰。", "亂掩宮中蝶，繁衝陌上人。", "隨波應到海，霑雨或依塵。", "會向慈恩日，輕輕對此身。"]'),
('05d0c667-b634-4962-8141-6a0cd84f56be','一葉落','薛能','唐','唐诗','tang','','[]','輕葉獨悠悠，天高片影流。',72,'全唐诗/poet.tang.31000.json','["輕葉獨悠悠，天高片影流。", "隨風來此地，何樹落先秋。", "變色黃應近，辭林綠尚稠。", "無雙浮水面，孤絕落關頭。", "乍減誠難覺，將凋勢未休。", "客心空自比，誰肯問新愁。"]'),
('b6434820-81da-4427-a554-caac87fc0cdf','行路難','薛能','唐','唐诗','tang','','[]','何處力堪殫，人心險萬端。',72,'全唐诗/poet.tang.31000.json','["何處力堪殫，人心險萬端。", "藏山難測度，暗水自波瀾。", "對面如千里，迴腸似七盤。", "已經吳坂困，欲向鴈門難。", "南北誠須泣，高深不可干。", "無因善行止，車轍得平安。"]'),
('cd0f2334-0b47-4ac2-a347-12ec1ae3ddd0','蔡州蔣亭','薛能','唐','唐诗','tang','','[]','草徑徹林間，過橋如入山。',72,'全唐诗/poet.tang.31000.json','["草徑徹林間，過橋如入山。", "蔡侯添水榭，蔣氏本柴關。", "靜汎窮幽趣，驚飛濕醉顏。", "恨無優俸買，來得暫時閑。", "步與招提接，舟臨夕照還。", "春風應不到，前想負花灣。"]'),
('ec0c18dc-509b-41d2-b17e-d0359d6ad1f9','戲題','薛能','唐','唐诗','tang','','[]','閃閃動鳴璫，初來燭影傍。',72,'全唐诗/poet.tang.31000.json','["閃閃動鳴璫，初來燭影傍。", "擁頭珠翠重，縈步綺羅長。", "靜發歌如磬，連飄氣覺香。", "不言微有笑，多媚總無妝。", "坐缺初離席，簾垂却入房。", "思惟不是夢，此會勝高唐。"]'),
('3bfc9e50-ef86-4df8-8d7c-0a0a7bdff2ea','酬曹侍御見寄','薛能','唐','唐诗','tang','','[]','儒道苦不勝，邇來惟慕禪。',120,'全唐诗/poet.tang.31000.json','["儒道苦不勝，邇來惟慕禪。", "觸途非巧者，於世分沈然。", "要地羞難入，閑居鈍更便。", "清和挑菜食，悶寂閉花眠。", "累遣期拋俸，機忘怕與權。", "妨春愁筦榷，響夜憶林泉。", "匪石從遭刖，殊膏枉被煎。", "討論唯子厚，藏退合吾先。", "舊製羣英伏，來章六義全。", "休旬一擬和，鄉思亂情田。"]'),
('ae2887c0-d432-4dd8-83e9-852fb352c6f8','送趙道士歸天目舊山','薛能','唐','唐诗','tang','','[]','愚朴尚公平，此心鄰道情。',120,'全唐诗/poet.tang.31000.json','["愚朴尚公平，此心鄰道情。", "有緣終自鄙，何計逐師行。", "日者聞高躅，時人蓋強名。", "口無滋味入，身有羽儀生。", "奏乞還鄉遠，詩曾對御成。", "土毛珍到越，塵髮倦離京。", "符叱風雷惡，朝脩月露清。", "觀臨天目頂，家住海潮聲。", "道引圖看足，參同注解精。", "休糧一擬問，窗草俟回程。"]'),
('2c067e29-9c3a-4911-8bf6-f7d66c0c91de','除夜作','薛能','唐','唐诗','tang','','[]','和吹度穹旻，虛徐接建寅。',120,'全唐诗/poet.tang.31000.json','["和吹度穹旻，虛徐接建寅。", "不辭加一歲，唯喜到三春。", "燎照雲煙好，幡懸井邑新。", "禎祥應北極，調燮驗平津。", "樹欲含遲日，山將退舊塵。", "蘭萎殘此夜，竹爆和諸鄰。", "祝壽思明聖，驅儺看鬼神。", "團圓多少輩，眠寢獨勞筋。", "茜斾猶雙節，雕盤又五辛。", "何當平賊後，歸作自由身。"]'),
('13fc10b0-140d-4db3-a984-a0bfe985c6c6','桃花','薛能','唐','唐诗','tang','','[]','香色自天種，千年豈易逢。',144,'全唐诗/poet.tang.31000.json','["香色自天種，千年豈易逢。", "開齊全未落，繁極欲相重。", "泠濕朝如淡，晴乾午更濃。", "風光新社燕，時節舊春農。", "籬落欹臨竹，亭臺盛間松。", "亂緣堪羨蟻，深入不如蜂。", "有影宜暄煦，無言自冶容。", "洞連非俗世，溪靜接仙蹤。", "子熟河應變，根盤土已封。", "西王潛愛惜，東朔盜過從。", "醉席眠英好，題詩戀景慵。", "芳菲聊一望，何必在臨邛。"]'),
('ff8314f9-d177-421a-b9fb-9bc743969b6d','黃河','薛能','唐','唐诗','tang','','["\u9ec4\u6cb3"]','何處發崑崙，連乾復浸坤。',168,'全唐诗/poet.tang.31000.json','["何處發崑崙，連乾復浸坤。", "波渾經鴈塞，聲振自龍門。", "岸裂新衝勢，灘餘舊落痕。", "橫溝通海上，遠色盡山根。", "勇逗三峰坼，雄標四瀆尊。", "灣中秋景樹，闊外夕陽村。", "沫亂知魚呴，槎來見鳥蹲。", "飛沙當白日，凝霧接黃昏。", "潤可資農畝，清能表帝恩。", "雨吟堪極目，風度想驚魂。", "顯瑞龜曾出，陰靈伯固存。", "盤渦寒漸急，淺瀨暑微溫。", "九曲終柔勝，常流可暗吞。", "人間無博望，誰復到窮源。"]'),
('edd1545b-cdf0-43e8-a396-675c3f6a6e78','華嶽','薛能','唐','唐诗','tang','','["\u534e\u5c71"]','簇簇復亭亭，三峰卓杳冥。',168,'全唐诗/poet.tang.31000.json','["簇簇復亭亭，三峰卓杳冥。", "每思窮本末，應合記圖經。", "發地連宮觀，衝天接井星。", "河微臨巨勢，秦重載奇形。", "太古朝羣后，中央擘巨靈。", "鄰州猶映檻，幾縣恰當庭。", "鶴毳壇風亂，龍漦洞水腥。", "望遙通北極，上徹見東溟。", "客翫晴難偶，農祈雨必零。", "度關無暑氣，過路得愁醒。", "羽客時應見，霜猨夜可聽。", "頂懸飛瀑峻，崦合白雲青。", "混石猜良玉，尋苗得茯苓。", "從官知側近，悉俸致巖扃。"]'),
('5f7d4937-da1e-4b8b-8054-53feed0425c8','秋雨','薛能','唐','唐诗','tang','','[]','宿雨覺纔初，亭林忽復徐。',168,'全唐诗/poet.tang.31000.json','["宿雨覺纔初，亭林忽復徐。", "簇聲諸樹密，懸滴四簷疎。", "省漏疑方丈，愁炊問斗儲。", "步難多入屐，窗淺欲飄書。", "動蠖蒼苔靜，藏蠶落葉虛。", "吹交來翕習，雷慢歇躊躇。", "滯已妨行路，晴應好荷鋤。", "醉樓思蜀客，鯹市想淮魚。", "徑草因緣合，欄花自此除。", "有形皆霢霂，無地不汙瀦。", "境晦宜甘寢，風清□退居。", "我魂驚曉簟，鄰話喜秋蔬。", "既用功成歲，旋應慘變舒。", "倉箱足可恃，歸去傲吾廬。"]'),
('ed4e65e3-f1fc-4dc2-9d91-5c3590907cd7','春色滿皇州','薛能','唐','唐诗','tang','','[]','藹藹復悠悠，春歸十二樓。',72,'全唐诗/poet.tang.31000.json','["藹藹復悠悠，春歸十二樓。", "最明雲裏闕，先滿日邊州。", "色媚青門外，光搖紫陌頭。", "上林榮舊樹，太液鏡新流。", "暖帶祥煙起，清添瑞景浮。", "陽和如啓蟄，從此事芳遊。"]'),
('33728d98-46d4-4929-bf68-c8825bd978cd','寄唁張喬喻坦之','薛能','唐','唐诗','tang','','[]','何事盡參差，惜哉吾子詩。',48,'全唐诗/poet.tang.31000.json','["何事盡參差，惜哉吾子詩。", "日令銷此道，天亦負明時。", "有路當重振，無門即不知。", "何當見堯日，相與啜澆漓。"]'),
('94a929a6-5aff-48ef-a3a2-a9b8023e5a99','贈僧','薛能','唐','唐诗','tang','','[]','盡日行方到，何年獨此林。',48,'全唐诗/poet.tang.31000.json','["盡日行方到，何年獨此林。", "客歸惟鶴伴，人少似師心。", "坐石落松子，禪牀搖竹陰。", "山靈怕驚定，不遣夜猨吟。"]'),
('2890b42e-a963-4d0e-af7b-6fea8787f576','春日旅舍書懷','薛能','唐','唐诗','tang','','[]','出去歸來旅食人，麻衣長帶幾坊塵。',64,'全唐诗/poet.tang.31000.json','["出去歸來旅食人，麻衣長帶幾坊塵。", "開門草色朝無客，落案燈花夜一身。", "貧舍臥多消永日，故園鶯老憶殘春。", "蹉跎冠蓋誰相念，二十年中盡苦辛。"]'),
('25b2850e-6107-45a3-a5bc-e1fbf91ff39b','秋日將離滑臺酬所知二首 一','薛能','唐','唐诗','tang','','[]','身起中宵骨亦驚，一分年少已無成。',64,'全唐诗/poet.tang.31000.json','["身起中宵骨亦驚，一分年少已無成。", "松吹竹簟朝眠冷，雨濕蔬飡宿疾生。", "僮汲野泉兼土味，馬磨霜樹作秋聲。", "相知莫話詩心苦，未似前賢取得名。"]'),
('282ededa-af64-410b-beb5-0220b4c0c45b','秋日將離滑臺酬所知二首 二','薛能','唐','唐诗','tang','','[]','燈澀秋光靜不眠，葉聲身影客窗前。',64,'全唐诗/poet.tang.31000.json','["燈澀秋光靜不眠，葉聲身影客窗前。", "閑園露濕鳴蛩夜，急雨風吹落木天。", "城見遠山應北嶽，野多空地本南燕。", "明朝欲別忘形處，愁把離杯聽管弦。"]'),
('309447c1-e083-41c4-83cc-234d2527bf44','下第後夷門乘舟至永城驛題','薛能','唐','唐诗','tang','','[]','秋賦春還計盡違，自知身是拙求知。',64,'全唐诗/poet.tang.31000.json','["秋賦春還計盡違，自知身是拙求知。", "唯思曠海爲休處，忽喜孤舟似去時。", "連浦一城兼汴宋，夾堤千柳雜唐隋。", "從來此恨皆前達，敢負吾君作楚辭。"]'),
('b4080e7b-319a-406b-8c28-0b0973b085b5','秋夜旅舍寓懷','薛能','唐','唐诗','tang','','[]','庭鎖荒蕪獨夜吟，西風吹動故山心。',64,'全唐诗/poet.tang.31000.json','["庭鎖荒蕪獨夜吟，西風吹動故山心。", "三秋木落半年客，滿地月明何處砧？", "漁唱亂沿汀鷺合，鴈聲寒咽隴雲深。", "平生只有松堪對，露浥霜欺不受侵。"]'),
('4b7399e5-1997-4d68-9ba2-58f82998b827','洛下寓懷','薛能','唐','唐诗','tang','','[]','胡爲遭遇孰爲官，朝野君親各自歡。',64,'全唐诗/poet.tang.31000.json','["胡爲遭遇孰爲官，朝野君親各自歡。", "敢向官途爭虎首，尚嫌身累愛猪肝。", "冰霜谷口晨樵遠，星火爐邊夜坐寒。", "唯有報恩心未剖，退居猶欲佩芄蘭。"]'),
('369f6a0c-9c9c-4509-9a9c-3ce449037ad1','題平湖','薛能','唐','唐诗','tang','','[]','平湖湖畔雨晴新，南北東西不隔塵。',64,'全唐诗/poet.tang.31000.json','["平湖湖畔雨晴新，南北東西不隔塵。", "映野煙波浮動日，損花風雨寂寥春。", "山無俗路藏高士，岸泊仙舟憶主人。", "那得載來都未保，此心離此甚情親。"]'),
('44c8d252-7815-447a-a937-57e4d8cbe30c','平陽寓懷','薛能','唐','唐诗','tang','','["\u897f\u6e56"]','晉國風流阻洳川，家家弦管路岐邊。',64,'全唐诗/poet.tang.31000.json','["晉國風流阻洳川，家家弦管路岐邊。", "曾爲郡職隨分竹，亦作歌詞乞採蓮。", "北榭遠峰閑即望，西湖殘景醉常眠。", "牆花此日休迴避，不是當時惡少年。"]'),
('147ac7fc-d1ac-4f6f-b687-a834bbb31b9e','留題汾上舊居','薛能','唐','唐诗','tang','','[]','鄉園一別五年歸，迴首人間總禍機。',64,'全唐诗/poet.tang.31000.json','["鄉園一別五年歸，迴首人間總禍機。", "尚勝鄰翁常寂寞，敢嫌裘馬未輕肥。", "塵顏不見應消落，庭樹曾栽已合圍。", "難說累牽還却去，可憐榆柳尚依依。"]'),
('bfbf356f-c704-467a-a157-d87791865dec','懷汾上舊居','薛能','唐','唐诗','tang','','[]','素汾千載傍吾家，常憶衡門對浣紗。',64,'全唐诗/poet.tang.31000.json','["素汾千載傍吾家，常憶衡門對浣紗。", "好事喜逢投宿客，刈田因得自生瓜。", "山頭鼓笛陰沈廟，陌上薪蒸突兀車。", "投暗作珠何所用，被人專擬害靈蛇。"]'),
('91b68dc1-5226-49f1-b463-4cda900d7fd4','送同儒大德歸柏梯寺','薛能','唐','唐诗','tang','','[]','柏梯還擬謝微官，遙擬千峰送法蘭。',64,'全唐诗/poet.tang.31000.json','["柏梯還擬謝微官，遙擬千峰送法蘭。", "行徑未曾青石斷，拂牀終有白雲殘。", "京塵濯後三衣潔，山舍禪初萬象安。", "薇蕨縱多師莫踏，我心猶欲盡圖看。"]'),
('3ac87c33-36bc-41ed-b6d8-9ad7bd82e387','春日使府寓懷二首 一','薛能','唐','唐诗','tang','','[]','一想流年百事驚，已拋漁父戴塵纓。',64,'全唐诗/poet.tang.31000.json','["一想流年百事驚，已拋漁父戴塵纓。", "青春背我堂堂去，白髮欺人故故生。", "道困古來應有分，詩傳身後亦何榮。", "誰憐合負清朝力，獨把風騷破鄭聲。"]'),
('a0e6dd61-d138-45d5-8b47-14f0f151ad9a','春日使府寓懷二首 二','薛能','唐','唐诗','tang','','[]','平生無解亦無操，永日書生坐獨勞。',64,'全唐诗/poet.tang.31000.json','["平生無解亦無操，永日書生坐獨勞。", "唯覺宦情如水薄，不知人事有山高。", "孤心好直迍猶強，病髮慵梳癢更搔。", "何事故溪歸未得，幾拋清淺汎紅桃。"]'),
('0d074046-3761-418c-8d13-0ee19ead67f3','許州題德星亭','薛能','唐','唐诗','tang','','[]','瀵水南流東有堤，堤邊亭是武陵溪。',64,'全唐诗/poet.tang.31000.json','["瀵水南流東有堤，堤邊亭是武陵溪。", "槎松配石堪僧坐，蘂杏含春欲鳥啼。", "高樹月生滄海外，遠郊山在夕陽西。", "頻來不似軍從事，只戴紗巾曳杖藜。"]'),
('b8002801-d823-4d6a-b80e-4a50f687e48e','送人歸上黨','薛能','唐','唐诗','tang','','[]','燕臺基壤穴狐蛇，計拙因循歲月賒。',64,'全唐诗/poet.tang.31000.json','["燕臺基壤穴狐蛇，計拙因循歲月賒。", "兵革未銷王在鎬，桑蠶臨熟客還家。", "霏微對岸漳邊雨，堆阜鄰疆薊北沙。", "若到長平戰場地，爲求遺鏃辟魔邪。"]'),
('a437d554-6505-4e38-9ace-93459f0dab1c','春日重遊平湖','薛能','唐','唐诗','tang','','[]','湖上春風發管弦，須臨三十此離筵。',64,'全唐诗/poet.tang.31000.json','["湖上春風發管弦，須臨三十此離筵。", "離人忽有重來日，遊女初非舊少年。", "官職已辜疲瘵望，詩名空被後生傳。", "啼鶯莫惜蹉跎恨，閑事聽吟一兩篇。"]'),
('0c86c1a4-8a34-459e-9236-19a2b0400bfe','幷州','薛能','唐','唐诗','tang','','[]','少年流落在幷州，裘脫文君取次遊。',64,'全唐诗/poet.tang.31000.json','["少年流落在幷州，裘脫文君取次遊。", "攜挈共過芳草渡，登臨齊凭綠楊樓。", "庭前蛺蝶春方好，牀上樗蒲宿未收。", "坊號偃松人在否，餅爐南畔曲西頭。"]'),
('6b976a5a-f247-412c-9ec8-53419cb13ccb','相國隴西公南征能以留務獨宿府城作','薛能','唐','唐诗','tang','','[]','吾君賢相事南征，獨宿軍廚負請纓。',64,'全唐诗/poet.tang.31000.json','["吾君賢相事南征，獨宿軍廚負請纓。", "燈室臥孤如怨別，月階簪草似臨行。", "高墉撼鐸思巴棧，老木嘷風念野營。", "殊憶好僧招不及，夜來倉卒鏁嚴城。"]'),
('360d74c9-21f0-439c-a941-e49d0ec1eab2','早春書事','薛能','唐','唐诗','tang','','[]','百蠻降伏委三秦，錦里風迴歲已新。',64,'全唐诗/poet.tang.31000.json','["百蠻降伏委三秦，錦里風迴歲已新。", "渠濫水泉花巷濕，日銷冰雪柳營春。", "何年道勝蘇羣物，盡室天涯是旅人。", "焚却蜀書宜不讀，武侯無可律余身。"]'),
('b08e9cfa-ab7a-44d2-a447-4e0c51e669bd','春日書懷','薛能','唐','唐诗','tang','','[]','伯牙琴絕豈求知，往往情牽自有詩。',64,'全唐诗/poet.tang.31000.json','["伯牙琴絕豈求知，往往情牽自有詩。", "壠月正當寒食夜，春陰初過海棠時。", "耽書未必酬良相，斷酒唯堪作老師。", "多病不任衣更薄，東風臺上莫相吹。"]'),
('44c65a92-ad1c-4ecd-ad24-10a8dd630291','投杜舍人','薛能','唐','唐诗','tang','','[]','牀上新詩詔草和，欄邊清酒落花多。',64,'全唐诗/poet.tang.31000.json','["牀上新詩詔草和，欄邊清酒落花多。", "閒消白日舍人宿，夢覺紫薇山鳥過。", "春刻幾分添禁漏，夏桐初葉滿庭柯。", "風騷委地苦無主，此事聖君終若何。"]'),
('849e62e4-d408-4529-95c5-6153612abc1f','獻僕射相公','薛能','唐','唐诗','tang','','[]','清如冰雪重如山，百辟嚴趨禮絕攀。',64,'全唐诗/poet.tang.31000.json','["清如冰雪重如山，百辟嚴趨禮絕攀。", "強虜外聞應喪膽，平人相見盡開顏。", "朝廷有道青春好，門館無私白日閑。", "致却垂衣更何事，幾多詩句詠關關。"]'),
('3500d0b7-c644-49ff-946f-c0c86e36cae1','上鹽鐵尚書','薛能','唐','唐诗','tang','','[]','南宮環雉隔囂塵，況值清齋宿大臣。',64,'全唐诗/poet.tang.31000.json','["南宮環雉隔囂塵，況值清齋宿大臣。", "城絕鼓鐘更點後，雨涼煙樹月華新。", "簷前漱曉穹蒼碧，庭下眠秋沆瀣津。", "聞說務閑心更靜，此時憂國合求人。"]'),
('9941e5d6-e506-4263-b89d-cfd26cc350b7','漢南春望','薛能','唐','唐诗','tang','','[]','獨尋春色上高臺，三月皇州駕未回。',64,'全唐诗/poet.tang.31000.json','["獨尋春色上高臺，三月皇州駕未回。", "幾處松筠燒後死，誰家桃李亂中開。", "奸邪用法原非法，唱和求才不是才。", "自古浮雲蔽白日，洗天風雨幾時來。"]'),
('111d5959-a747-421e-80ce-d853a26856f0','晚春','薛能','唐','唐诗','tang','','[]','惡憐風景極交親，每恨年年作瘦人。',64,'全唐诗/poet.tang.31000.json','["惡憐風景極交親，每恨年年作瘦人。", "臥晚不曾拋好夜，情多唯欲哭殘春。", "陰成杏葉纔通日，雨著楊花已汙塵。", "無限後期知有在，只愁煩作總戎身。"]'),
('57acb0c8-c418-41aa-a886-ed7808ac8e31','將赴鎮過太康縣有題','薛能','唐','唐诗','tang','','[]','纔入東郊便太康，自聽何暮豈龔黃。',64,'全唐诗/poet.tang.31000.json','["纔入東郊便太康，自聽何暮豈龔黃。", "晴村透日桑榆影，曉露濕秋禾黍香。", "十萬旌旗移巨鎮，幾多輗軏負孤莊。", "時人欲識征東將，看取欃槍落太荒。"]'),
('6dae0cb8-4a30-4334-995d-2adf8e3bf82f','彭門解嘲二首 一','薛能','唐','唐诗','tang','','[]','嗚嗚吹角貳師營，落日身閑笑傲行。',64,'全唐诗/poet.tang.31000.json','["嗚嗚吹角貳師營，落日身閑笑傲行。", "盡覺文章尊萬事，却嫌官職剩雙旌。", "終休未擬降低屈，忽遇還須致太平。", "頻上水樓誰會我，泗濱浮磬是同聲。"]'),
('0449950c-0bf3-4126-99f6-5a17c7b203bc','彭門解嘲二首 二','薛能','唐','唐诗','tang','','[]','傷禽栖後意猶驚，偶向黐竿脫此生。',64,'全唐诗/poet.tang.31000.json','["傷禽栖後意猶驚，偶向黐竿脫此生。", "身外不思簪組事，耳中唯要管弦聲。", "耽吟乍可妨時務，淺飲無因致宿酲。", "秦客莫嘲瓜戍遠，水風瀟灑是彭城。"]'),
('540971f7-0aca-4980-95ce-ef2309a75071','清河汎舟','薛能','唐','唐诗','tang','','[]','都人層立似山丘，坐嘯將軍擁棹遊。',64,'全唐诗/poet.tang.31000.json','["都人層立似山丘，坐嘯將軍擁棹遊。", "遶郭煙波浮泗水，一船絲竹載涼州。", "城中覩望皆丹雘，旗裏驚飛盡白鷗。", "儒將不須誇郄縠，未聞詩句解風流。"]'),
('68c7bc07-b7d1-4973-99e5-82d36e686745','新竹','薛能','唐','唐诗','tang','','[]','柳營茅土倦麤材，因向山家乞翠栽。',64,'全唐诗/poet.tang.31000.json','["柳營茅土倦麤材，因向山家乞翠栽。", "清露便敎終夜滴，好風疑是故園來。", "欄邊匠去朱猶濕，溉後蟲浮穴暗開。", "他日會應威鳳至，莫辭公府受塵埃。"]'),
('390bc411-91ee-4ebc-9b78-06ea6182c629','晚春','薛能','唐','唐诗','tang','','[]','征東留滯一年年，又向軍前遇火前。',64,'全唐诗/poet.tang.31000.json','["征東留滯一年年，又向軍前遇火前。", "畫出鷁舟宜祓禊，鏤成雞卵有鞦韆。", "澄明煙水孤城立，狼藉風花落日眠。", "賴指清和櫻筍熟，不然愁殺暮春天。"]'),
('069395bb-111f-436d-b00a-feaf52b57399','題彭祖樓','薛能','唐','唐诗','tang','','[]','新晴天狀濕融融，徐國灘聲上下洪。',64,'全唐诗/poet.tang.31000.json','["新晴天狀濕融融，徐國灘聲上下洪。", "極目澄鮮無限景，入懷輕好可憐風。", "身防潦倒師彭祖，妓擁登臨媿謝公。", "誰致此樓潛惠我，萬家殘照在河東。"]'),
('6f1e3453-1e0b-4da7-9ed4-38becac07afe','漢廟祈雨回陽春亭有懷','薛能','唐','唐诗','tang','','[]','南榮軒檻接城闉，適罷祈農此訪春。',64,'全唐诗/poet.tang.31000.json','["南榮軒檻接城闉，適罷祈農此訪春。", "九九已從南至盡，芊芊初傍北籬新。", "池中水是前秋雨，陌上風驚自古塵。", "欲召羅敷傾一盞，乘閒言語不容人。"]'),
('c3d940b6-839d-4702-853d-288d4a1c1172','送李倍秀才','薛能','唐','唐诗','tang','','[]','南朝才子尚途窮，畢竟應須問葉公。',64,'全唐诗/poet.tang.31000.json','["南朝才子尚途窮，畢竟應須問葉公。", "書劒伴身離泗上，雪風吹面立船中。", "家園棗熟歸圭竇，會府槐疎試射弓。", "相顧日偏留不得，夜深聊欲一桮同。"]'),
('8c4d9433-e381-41f7-baf4-3c837d10cb1a','重遊德星亭感事','薛能','唐','唐诗','tang','','[]','穎水川中枕水臺，當時難別此重來。',64,'全唐诗/poet.tang.31000.json','["穎水川中枕水臺，當時難別此重來。", "舟沈土岸生新草，詩映紗籠有薄埃。", "事繫興亡人少到，地當今古我遲迴。", "殘陽照樹明於旭，猶向池邊把酒桮。"]'),
('9a1a56b6-db2c-43c2-84a8-3c60372128fe','許州題觀察判官廳','薛能','唐','唐诗','tang','','[]','三載從戎類繫匏，重遊全許尚分茅。',64,'全唐诗/poet.tang.31000.json','["三載從戎類繫匏，重遊全許尚分茅。", "劉郎別後無遺履，丁令歸來有舊巢。", "冬暖井梧多未落，夜寒窗竹自相敲。", "纖腰弟子知千恨，笑與揚雄作解嘲。"]'),
('835ba8be-b9ca-417c-b9df-58a7a389a64c','閒題','薛能','唐','唐诗','tang','','[]','八年藩翰似僑居，只此誰知報玉除。',64,'全唐诗/poet.tang.31000.json','["八年藩翰似僑居，只此誰知報玉除。", "舊將已成三僕射，老身猶是六尚書。", "時丁厚讟終無咎，道致中興尚有餘。", "爲問春風誰是主，空催弱柳擬何如。"]'),
('4936dd7c-b1ca-4475-935e-33888de20c4f','送福建李大夫','薛能','唐','唐诗','tang','','[]','洛州良牧帥甌閩，曾是西垣作諫臣。',64,'全唐诗/poet.tang.31000.json','["洛州良牧帥甌閩，曾是西垣作諫臣。", "紅斾已勝前尹正，尺書猶帶舊絲綸。", "秋來海有幽都鴈，船到城添外國人。", "行過小藩應大笑，只知誇近不知貧。"]'),
('70779e82-343e-41d5-b503-55027fbef28a','送李倍巡官歸永樂舊居','薛能','唐','唐诗','tang','','[]','羨君歸去五峰前，往往星河實見仙。',64,'全唐诗/poet.tang.31000.json','["羨君歸去五峰前，往往星河實見仙。", "麥壠夏枯成廢地，棗枝秋赤近高天。", "山泉飲犢流多變，村酒經蠶味可憐。", "曾約道門終老住，步虛聲裏寄閑眠。"]'),
('fc5ef131-5228-495f-935a-89a8f2913de3','贈歌者','薛能','唐','唐诗','tang','','[]','一字新聲一顆珠，轉喉疑是擊珊瑚。',64,'全唐诗/poet.tang.31000.json','["一字新聲一顆珠，轉喉疑是擊珊瑚。", "聽時坐部音中有，唱後櫻花葉裏無。", "漢浦蔑聞虛解佩，臨邛焉用枉當壚。", "誰人得向青樓宿，便是仙郎不是夫。"]'),
('487f1835-c97e-4368-a0fb-80caeef1b4f4','舞者','薛能','唐','唐诗','tang','','[]','綠毛釵動小相思，一唱南軒日午時。',64,'全唐诗/poet.tang.31000.json','["綠毛釵動小相思，一唱南軒日午時。", "慢靸輕裾行欲近，待調諸曲起來遲。", "筵停匕筯無非聽，吻帶宮商盡是詞。", "爲問傾城年幾許，更勝瓊樹是瓊枝。"]'),
('10fd9791-873b-4b45-9b7a-23c17eef5862','天際識歸舟','薛能','唐','唐诗','tang','','[]','斜日滿江樓，天涯照背流。',72,'全唐诗/poet.tang.31000.json','["斜日滿江樓，天涯照背流。", "同人在何處，遠目認孤舟。", "帆省當時席，歌聲舊日謳。", "人浮津濟晚，棹倚泬寥秋。", "晴闊忻全見，歸遲怪久遊。", "離居意無限，貪此望難休。"]'),
('c983a658-e451-41c8-bbb1-9b61206ace6e','和曹侍御除夜有懷','薛能','唐','唐诗','tang','','[]','有病無媒客，多慵亦太疎。',120,'全唐诗/poet.tang.31000.json','["有病無媒客，多慵亦太疎。", "自憐成叔夜，誰與薦相如。", "嗜退思年老，諳空笑歲除。", "跡閑過寺宿，頭煖近階梳。", "春立窮冬後，陽生舊物初。", "葉多庭不掃，根在逕新鋤。", "田事終歸彼，心情倦老於。", "斵材須見像，藏劒豈爲魚。", "效淺慙尹祿，恩多負辟書。", "醻知必擬共，勿使浪躊躇。"]'),
('fcd60fbc-fd71-4c83-a553-76a880c8c1df','華清宮和杜舍人','薛能','唐','唐诗','tang','','[]','五十年天子，離宮仰峻牆。',288,'全唐诗/poet.tang.31000.json','["五十年天子，離宮仰峻牆。", "登封時正泰，御宇日何長。", "上位先名實，中興事憲章。", "起戎輕甲胄，餘地復河湟。", "道降玄元祖，儒封孔子王。", "因緣百司署，聚會一人湯。", "渭水波搖綠，秦山草半黃。", "馬馴金勒細，鷹健玉鈴鏘。", "下箭朱方滿，鳴鞭皓腕攘。", "畋思獲呂望，諫祗避周昌。", "兔跡貪前逐，梟心不早防。", "幾添鸚鵡勸，先賜荔枝嘗。", "月鎖千門靜，天吹一笛涼。", "細音搖羽佩，輕步宛霓裳。", "禍亂基潛結，昇平意遽忘。", "衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中原事可量。", "血埋妃子豔，刃斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。", "益知迷寵佞，遺恨喪賢良。", "北闕尊明主，南宮遜上皇。", "禁清餘鳳吹，池冷睡龍光。", "祝壽山猶在，流年水共傷。", "杜鵑魂厭蜀，蝴蝶夢悲壯。"]'),
('1018ad98-bcb0-4e76-9168-24d7d881f371','送浙東王大夫','薛能','唐','唐诗','tang','','[]','天爵擅忠貞，皇恩復寵榮。',264,'全唐诗/poet.tang.31000.json','["天爵擅忠貞，皇恩復寵榮。", "遠源過晉史，甲族本緱笙。", "亞相兼尤美，周行歷盡清。", "制除天近曉，衙謝草初生。", "賓客招閑地，戎裝擁上京。", "九街鳴玉勒，一宅照紅旌。", "細雨當離席，遙花顯去程。", "佩刀畿甸色，歌吹館橋聲。", "騕褭從秦賜，艅艎到汴迎。", "步沙逢霽月，宿岸致嚴更。", "渤澥流東鄙，天台壓屬城。", "衆談稱重鎮，公意念疲甿。", "井邑曾多難，瘡痍此未平。", "察應均賦歛，逃必復桑耕。", "隼重權兼帥，鼉雄設有兵。", "越臺隨厚俸，剡硾得尤名。", "夜蠟州中宴，春風部外行。", "香匳扃鳳詔，朱篆動龍坑。", "報後功何患，投虛論素精。", "徵還真指掌，感激自關情。", "舊業懷昏作，微班負旦評。", "空餘騷雅事，千古傲劉楨。"]'),
('80560e30-5af8-40fc-8303-28a4023e6bf7','送李殷遊京西','薛能','唐','唐诗','tang','','[]','立馬送君地，黯然愁到身。',120,'全唐诗/poet.tang.31000.json','["立馬送君地，黯然愁到身。", "萬途皆有匠，六義獨無人。", "莫怪敢言此，已能甘世貧。", "時來貴亦在，事是掩何因。", "投刺皆羈旅，遊邊更苦辛。", "岐山終蜀境，涇水復蠻塵。", "埋沒飡須強，炎蒸醉莫頻。", "俗徒欺合得，吾道死終新。", "展分先難許，論詩永共親。", "歸京稍作意，充斥犯西鄰。"]'),
('85b31c72-4f72-4963-b44b-1d635a0360b6','長安送友人之黔南','薛能','唐','唐诗','tang','','[]','衡嶽猶云過，君家獨幾千。',96,'全唐诗/poet.tang.31000.json','["衡嶽猶云過，君家獨幾千。", "心從賤遊話，分向禁城偏。", "陸路終何處，三湘在素船。", "琴書去迢遞，星路照潺湲。", "臺鏡簪秋晚，盤蔬飯雨天。", "同文到鄉盡，殊國共行連。", "後會應多日，歸程自一年。", "貧交永無忘，孤進合相憐。"]'),
('42d33d46-a704-4d7c-88d5-000a73d92394','寄李頻','薛能','唐','唐诗','tang','','[]','長安千萬蹊，迷者自多迷。',48,'全唐诗/poet.tang.31000.json','["長安千萬蹊，迷者自多迷。", "直性身難達，良時日易低。", "環簷消舊雪，晴氣滿春泥。", "那得同君去，逢峰苦愛齊。"]'),
('8fa9905e-5a6e-47aa-8af3-3f3db6afc434','贈苗端公二首 一','薛能','唐','唐诗','tang','','[]','繁總近何如，君才必有餘。',48,'全唐诗/poet.tang.31000.json','["繁總近何如，君才必有餘。", "身歡步兵酒，吏寫魯連書。", "坐默聞鼙吹，庭班見雪初。", "沈碑若果去，一爲訪鄰居。"]'),
('4f41380a-9669-46ec-b4f6-d4354ed6670e','贈苗端公二首 二','薛能','唐','唐诗','tang','','[]','至老不相疎，斯言不是虛。',48,'全唐诗/poet.tang.31000.json','["至老不相疎，斯言不是虛。", "兩心宜一體，同舍又鄰居。", "曉角秋砧外，清雲白月初。", "從軍何有用，未造魯連書。"]'),
('54aa96cd-630d-47cb-bdbb-911e31440a4d','寄河南鄭侍郎','薛能','唐','唐诗','tang','','[]','三峽與三壕，門闌夢去勞。',48,'全唐诗/poet.tang.31000.json','["三峽與三壕，門闌夢去勞。", "細冰和洛水，初雪灑嵩高。", "大雅何由接，微榮亦已逃。", "寒窗不可寐，風地葉蕭騷。"]'),
('b057e18b-4184-43ee-9814-1fc18d2a09be','蒙恩除侍御史行次華州寄蔣相','薛能','唐','唐诗','tang','','["\u9ec4\u6cb3"]','林下天書起遁逃，不堪移疾入塵勞。',64,'全唐诗/poet.tang.31000.json','["林下天書起遁逃，不堪移疾入塵勞。", "黃河近岸陰風急，仙掌臨關旭日高。", "行野衆喧聞鴈發，宿亭孤寂有狼嗥。", "荀家位極兼禪理，應笑埋輪著所操。"]'),
('8831d0aa-6ec8-4978-8ca1-432b1e2d78dc','寄唐州楊郎中','薛能','唐','唐诗','tang','','[]','關雎憔悴一儒生，忽把魚鬚事聖明。',64,'全唐诗/poet.tang.31000.json','["關雎憔悴一儒生，忽把魚鬚事聖明。", "貧得俸錢還乍喜，晚登朝序却無榮。", "前年坐蜀同樽俎，此日邊淮獨斾旌。", "班列道孤君不見，曲江春暖共僧行。"]'),
('1a04eb76-4382-4fef-aa8c-d2e11838508d','塞上蒙汝州任中丞寄書','薛能','唐','唐诗','tang','','[]','三省推賢兩掖才，關東深許稍遲迴。',64,'全唐诗/poet.tang.31000.json','["三省推賢兩掖才，關東深許稍遲迴。", "舟浮汝水通淮去，雨出嵩峰到郡來。", "投札轉京憂不遠，枉緘經虜喜初開。", "西樓一望知無極，更與何人把酒桮。"]'),
('36b4ef7a-82b0-4b0f-b78b-8e0ee033063d','題鹽鐵李尚書滻州別業','薛能','唐','唐诗','tang','','[]','鹿原陰面滻州湄，坐覺林泉逼夢思。',64,'全唐诗/poet.tang.31000.json','["鹿原陰面滻州湄，坐覺林泉逼夢思。", "閑景院開花落後，濕香風好雨來時。", "鄰驚麥野聞雛雉，別創茅亭住老師。", "備足好中還有闕，許昌軍裏李陵詩。"]'),
('f5c1c091-3fa2-4da4-867f-8e64d2d3bb23','送劉駕歸京','薛能','唐','唐诗','tang','','[]','相逢聽一吟，惟我不降心。',48,'全唐诗/poet.tang.31000.json','["相逢聽一吟，惟我不降心。", "在世憂何事，前生得至音。", "蒲多南去遠，汾盡北遊深。", "爲宿關亭日，蒼蒼曉欲臨。"]'),
('051c3033-e855-4c08-b186-0320b54b32d1','夏日寺中有懷','薛能','唐','唐诗','tang','','[]','亭午四鄰睡，院中唯鳥鳴。',48,'全唐诗/poet.tang.31000.json','["亭午四鄰睡，院中唯鳥鳴。", "當門塞鴻去，欹枕世人情。", "地燥蒼苔裂，天涼晚月生。", "歸家豈不願，辛苦未知名。"]'),
('41c4e72f-862d-4550-b42e-483f9e217c9c','夏日蒲津寺居二首 一','薛能','唐','唐诗','tang','','[]','日日閑車馬，誰來訪此身。',48,'全唐诗/poet.tang.31000.json','["日日閑車馬，誰來訪此身。", "一門兼鶴靜，四院與僧鄰。", "雨室牆穿溜，風窗筆染塵。", "空餘氣長在，天子用平人。"]'),
('d90fd3ab-601b-4e1a-b29f-25604787a265','夏日蒲津寺居二首 二','薛能','唐','唐诗','tang','','[]','故國有如夢，省來長遠遊。',48,'全唐诗/poet.tang.31000.json','["故國有如夢，省來長遠遊。", "清晨起閑院，疎雨似深秋。", "宿寢書稜疊，行吟杖跡稠。", "天晴豈能出，春暖未更裘。"]'),
('8cdc4b09-0392-4b11-8180-1679c517cb75','北都題崇福寺','薛能','唐','唐诗','tang','','[]','此地潛龍寺，何基即帝臺。',48,'全唐诗/poet.tang.31000.json','["此地潛龍寺，何基即帝臺。", "細花庭樹蔭，清氣殿門開。", "長老多相識，旬休暫一來。", "空空亦擬解，干進幸無媒。"]'),
('c9489529-9285-4797-b41e-be5b13788c22','題龍興寺','薛能','唐','唐诗','tang','','[]','高戶列禪房，松門到上方。',48,'全唐诗/poet.tang.31000.json','["高戶列禪房，松門到上方。", "像開祇樹嶺，人施蜀城香。", "地遍磷磷石，江移孑孑檣。", "林僧語不盡，身役事梁王。"]'),
('9138bf74-5a90-4b43-b30f-4150cc9158fc','題大雲寺西閣','薛能','唐','唐诗','tang','','[]','閣臨偏險寺當山，獨坐西城笑滿顏。',64,'全唐诗/poet.tang.31000.json','["閣臨偏險寺當山，獨坐西城笑滿顏。", "四野有歌行路樂，五營無戰射堂閑。", "鼙和調角秋空外，砧辦征衣落照間。", "方擬殺身酬聖主，敢於高處戀鄉關。"]'),
('2f55264b-06f6-46b2-a56e-c9e7b831ef53','舟行至平羌','薛能','唐','唐诗','tang','','[]','貔虎直沙壖，嚴更護早眠。',48,'全唐诗/poet.tang.31000.json','["貔虎直沙壖，嚴更護早眠。", "簇霜孤驛樹，落日下江船。", "暫去非吳起，終休愛魯連。", "平羌無一術，候吏莫加籩。"]'),
('f2b4b678-ca99-4bcc-a233-823edcf10281','題開元寺閣','薛能','唐','唐诗','tang','','[]','一閣見一郡，亂流仍亂山。',48,'全唐诗/poet.tang.31000.json','["一閣見一郡，亂流仍亂山。", "未能終日住，尤愛暫時閑。", "唱棹吳門去，啼林杜宇還。", "高僧不可羨，西景掩禪關。"]'),
('4f948988-6a95-4aa2-9cb7-434a69325507','凌雲寺','薛能','唐','唐诗','tang','','[]','像閣與山齊，何人致石梯。',48,'全唐诗/poet.tang.31000.json','["像閣與山齊，何人致石梯。", "萬煙生聚落，一崦露招提。", "齋月人來上，殘陽鴿去栖。", "從邊亦已極，烽火是沈黎。"]'),
('68f05db6-01db-4cd1-8d32-7c6e7756cb5f','石堂溪','薛能','唐','唐诗','tang','','[]','三面接漁樵，前門向郡橋。',48,'全唐诗/poet.tang.31000.json','["三面接漁樵，前門向郡橋。", "岸沙崩橘樹，山徑入茶苗。", "夜擁軍煙合，春浮妓舸邀。", "此心無與醉，花影莫相燒。"]'),
('af091f2d-1eb6-4b68-b180-7aa8cfbae23d','荔枝樓','薛能','唐','唐诗','tang','','[]','高檻起邊愁，荔枝誰致樓。',48,'全唐诗/poet.tang.31000.json','["高檻起邊愁，荔枝誰致樓。", "會須敎匠坼，不欲見蠻陬。", "樹痺無春影，天連覺漢流。", "仲宣如可擬，即此是荆州。"]'),
('88b936ba-6466-47fc-81c4-c18a5ddf1689','聖岡','薛能','唐','唐诗','tang','','[]','古跡是何王，平身入石房。',48,'全唐诗/poet.tang.31000.json','["古跡是何王，平身入石房。", "遠村通後徑，一郡隔前岡。", "晝靜唯禪客，春來有女郎。", "獨醒迴不得，無事可焚香。"]'),
('fdc856e6-09cc-44bf-a4ad-b5badbc57951','蜀州鄭史君寄鳥觜茶因以贈答八韻','薛能','唐','唐诗','tang','','[]','鳥觜擷渾牙，精靈勝鏌鋣。',96,'全唐诗/poet.tang.31000.json','["鳥觜擷渾牙，精靈勝鏌鋣。", "烹嘗方帶酒，滋味更無茶。", "拒碾乾聲細，撐封利穎斜。", "銜蘆齊勁實，啄木聚菁華。", "鹽損添常誡，薑宜著更誇。", "得來拋道藥，攜去就僧家。", "旋覺前甌淺，還愁後信賒。", "千慙故人意，此惠敵丹砂。"]'),
('683e07bf-a042-480f-91d7-f543f64c8ef5','暇日寓懷寄朝中親友','薛能','唐','唐诗','tang','','[]','命與才違豈自由，我身何負我身愁。',64,'全唐诗/poet.tang.31000.json','["命與才違豈自由，我身何負我身愁。", "臨生白髮方監郡，遙恥青衣懶上樓。", "過客悶嫌疎妓樂，小兒憨愛□貔貅。", "閑吟一寄清朝侶，未必淮陰不拜侯。"]'),
('fcc2fc24-1296-4591-9cc4-7833dd8ab162','春日寓懷','薛能','唐','唐诗','tang','','[]','幽拙未謀身，無端患不均。',48,'全唐诗/poet.tang.31000.json','["幽拙未謀身，無端患不均。", "盜憎猶念物，花盡不知春。", "井邑常多弊，江山豈有神。", "犍爲何處在，一擬弔埋輪。"]'),
('e315b847-2750-4f01-b3aa-160d02357ccf','監郡犍爲舟中寓題寄同舍','薛能','唐','唐诗','tang','','[]','一寢閑身萬事空，任天敎作假文翁。',64,'全唐诗/poet.tang.31000.json','["一寢閑身萬事空，任天敎作假文翁。", "旗穿島樹孤舟上，家在山亭每日中。", "疊果盤飱丹橘地，若花牀席早梅風。", "佳期說盡君應笑，劉表尊前且不同。"]'),
('43d503b6-2234-45e1-9b70-8ef2f5411c94','江柳','薛能','唐','唐诗','tang','','[]','條綠似垂纓，離筵日照輕。',48,'全唐诗/poet.tang.31000.json','["條綠似垂纓，離筵日照輕。", "向人雖有態，傷我爲無情。", "橋遠孤臨水，牆低半出營。", "天津曾此見，亦是愴行行。"]'),
('2be3a317-bca8-4718-8c4d-35305b9e7be2','寄吉諫議','薛能','唐','唐诗','tang','','[]','將迎須學返抽身，合致蹉跎敢效顰。',64,'全唐诗/poet.tang.31000.json','["將迎須學返抽身，合致蹉跎敢效顰。", "性靜擬歸無上士，跡疎常負有情人。", "終憑二頃謀婚嫁，謬著千篇斷斧斤。", "聞說舊交賢且達，欲彈章甫自羞貧。"]'),
('eb744f11-b175-4dc8-b15c-af9acc547003','江上寄情','薛能','唐','唐诗','tang','','[]','天際歸舟浩蕩中，我關王澤道何窮。',64,'全唐诗/poet.tang.31000.json','["天際歸舟浩蕩中，我關王澤道何窮。", "未爲時彥徒經國，尚有邊兵恥佐戎。", "釀黍氣香村欲社，斫桑春盡野無風。", "年來斷定知休處，一樹繁花一畝宮。"]'),
('10b5ab74-51d6-4651-8c3e-6b4a59b7943d','平蓋觀','薛能','唐','唐诗','tang','','[]','巨柏與山高，玄門靜有猱。',48,'全唐诗/poet.tang.31000.json','["巨柏與山高，玄門靜有猱。", "春風開野杏，落日照江濤。", "白璧心難說，青雲世未遭。", "天涯望不極，誰識詠離騷。"]'),
('fa762606-0c71-442c-8916-f7585f53eaba','春霽','薛能','唐','唐诗','tang','','[]','久客孤舟上，天涯漱曉津。',48,'全唐诗/poet.tang.31000.json','["久客孤舟上，天涯漱曉津。", "野芳榿似柳，江霽雪和春。", "吏叫能驚鷺，官麤實害身。", "何當窮蜀境，却憶滯遊人。"]'),
('5a575f90-37ef-4b5e-82ac-32665a01a5d9','春居即事','薛能','唐','唐诗','tang','','[]','雲密露晨暉，西園獨掩扉。',48,'全唐诗/poet.tang.31000.json','["雲密露晨暉，西園獨掩扉。", "雨新臨斷火，春冷著單衣。", "榆莢奔風健，蘭芽負土肥。", "交親不是變，自作寄書稀。"]'),
('353d1f85-0c72-41dc-a327-0204ba52610a','邊城寓題','薛能','唐','唐诗','tang','','[]','孤蹇復飄零，天涯若墮螢。',48,'全唐诗/poet.tang.31000.json','["孤蹇復飄零，天涯若墮螢。", "東風吹痼疾，暖日極青冥。", "蠶市歸農醉，漁舟釣客醒。", "論邦苦不早，祗此負王庭。"]'),
('66f2fc5d-df4f-4a39-b5f6-27ce0825ea79','春日江居寓懷','薛能','唐','唐诗','tang','','[]','歸興乍離邊，蘭橈復錦川。',48,'全唐诗/poet.tang.31000.json','["歸興乍離邊，蘭橈復錦川。", "斫春槎枿樹，消雪土膏田。", "岸暖尋新菜，舟寒著舊綿。", "臨邛若箇是，欲向酒家眠。"]'),
('de9dd550-e50c-43b1-9132-b95191cce9fa','邊城作','薛能','唐','唐诗','tang','','[]','行止象分符，監州是戲儒。',48,'全唐诗/poet.tang.31000.json','["行止象分符，監州是戲儒。", "管排蠻戶遠，出箐鳥巢孤。", "北向秦何在，南來蜀已無。", "懷沙悔不及，只有便乘桴。"]'),
('e4695c33-7724-4958-9442-de565b98eda7','聞李夷遇下第東歸因以寄贈','薛能','唐','唐诗','tang','','[]','囊中書是居山寫，海畔家貧乞食還。',64,'全唐诗/poet.tang.31000.json','["囊中書是居山寫，海畔家貧乞食還。", "吾子莫愁登第晚，古人惟愛賤遊閑。", "舟行散適江亭上，郡宴歌吟蠟燭間。", "從此樂章休敘戰，漢兵無陣亦無蠻。"]'),
('04c61f91-42b2-4604-9209-f779f63af881','留題','薛能','唐','唐诗','tang','','[]','茶興復詩心，一甌還一吟。',48,'全唐诗/poet.tang.31000.json','["茶興復詩心，一甌還一吟。", "壓春甘蔗冷，喧雨荔枝深。", "驟去無遺恨，幽棲已徧尋。", "峨眉不可到，高處望千岑。"]'),
('e78a6ae1-1875-4239-8bd1-52955b515db5','春日北歸舟中有懷','薛能','唐','唐诗','tang','','[]','盡日遶盤飧，歸舟向蜀門。',48,'全唐诗/poet.tang.31000.json','["盡日遶盤飧，歸舟向蜀門。", "雨乾楊柳渡，山熱杏花村。", "淨鏡空山曉，孤燈極浦昏。", "邊城不是意，迴首未終恩。"]'),
('bf2c90b9-b679-4c61-8879-b1c2fa0487e0','初發嘉州寓題','薛能','唐','唐诗','tang','','[]','勞我是犍爲，南征又北移。',48,'全唐诗/poet.tang.31000.json','["勞我是犍爲，南征又北移。", "唯聞杜鵑夜，不見海棠時。", "在闇曾無負，含靈合有知。", "州人若愛樹，莫損召南詩。"]'),
('fc602fe2-1cc5-4eb6-a67e-8dc478e1579c','題漢州西湖','薛能','唐','唐诗','tang','','["\u897f\u6e56"]','西湖天下名，可以濯吾纓。',72,'全唐诗/poet.tang.31000.json','["西湖天下名，可以濯吾纓。", "況是攜家賞，從妨半驛程。", "嘗茶春味渴，斷酒晚懷清。", "盡得幽人趣，猶嫌守吏迎。", "重湌逢角暮，百事喜詩成。", "坐阻湘江謫，誰爲話政聲。"]'),
('84c5f343-c4d2-4442-80f3-b2b68b9913af','自廣漢遊三學山','薛能','唐','唐诗','tang','','[]','殘陽終日望棲賢，歸路攜家得訪禪。',64,'全唐诗/poet.tang.31000.json','["殘陽終日望棲賢，歸路攜家得訪禪。", "世缺一來應薄命，雨留三宿是前緣。", "詩題不忍離巖下，屐齒難忘在水邊。", "猨鳥可知僧可會，此心常似有香煙。"]'),
('57672af9-a6c0-42ea-8469-3889d698a0db','三學山開照寺','薛能','唐','唐诗','tang','','[]','盡室徧相將，中方上下方。',48,'全唐诗/poet.tang.31000.json','["盡室徧相將，中方上下方。", "夜深楠樹遠，春氣陌林香。", "聖跡留巖險，靈燈出混茫。", "何因將慧劒，割愛事空王。"]'),
('fa58b39f-33a7-4591-ac25-d0f8319102ef','雨霽北歸留題三學山','薛能','唐','唐诗','tang','','[]','遠樹平川半夕陽，錦城遙辨立危牆。',64,'全唐诗/poet.tang.31000.json','["遠樹平川半夕陽，錦城遙辨立危牆。", "閑思勝事多遺恨，却悔公心是謾忙。", "灌口闕尋慙遠客，峨嵋乖約負支郎。", "靈龕一望終何得，謬有人情滿蜀鄉。"]'),
('81b1a43e-e8ad-47f6-bc0d-c710eb2410d0','行次靈龕驛寄西蜀尚書','薛能','唐','唐诗','tang','','[]','北客推車指蜀門，乾陽知已近臨坤。',64,'全唐诗/poet.tang.31000.json','["北客推車指蜀門，乾陽知已近臨坤。", "從辭府郭常迴首，欲別封疆更感恩。", "援寡聖朝難望闕，暑催蠶麥得歸村。", "雷公解斸衝天氣，白日何辜遣戴盆。"]'),
('b66e3627-9533-4d55-b4c9-95a06579acf7','雨霽宿望喜驛','薛能','唐','唐诗','tang','','[]','風雷一罷思何清，江水依然浩浩聲。',64,'全唐诗/poet.tang.31000.json','["風雷一罷思何清，江水依然浩浩聲。", "飛鳥旋生啼鳥在，後人常似古人情。", "將來道路終須達，過去山川實不平。", "閑想更逢知舊否，館前楊柳種初成。"]'),
('7f463bd2-2250-4f2d-a391-78d236e1f695','籌筆驛','薛能','唐','唐诗','tang','','[]','葛相終宜馬革還，未開天意便開山。',48,'全唐诗/poet.tang.31000.json','["葛相終宜馬革還，未開天意便開山。", "生欺仲達徒增氣，死見王陽合厚顏。", "流運有功終是擾，陰符多術得非姦。"]'),
('3f03d99f-bc1b-4cb6-a35e-4cd056ec196f','通仙洞','薛能','唐','唐诗','tang','','[]','高龕險欲催，百尺洞門開。',48,'全唐诗/poet.tang.31000.json','["高龕險欲催，百尺洞門開。", "白日仙何在，清風客暫來。", "臨崖松直上，避石水低迴。", "賈掾曾空去，題詩豈易哉。"]'),
('85ffb77b-3a99-499f-a31d-d5f1d07c16b5','嘉陵驛見賈島舊題','薛能','唐','唐诗','tang','','[]','賈子命堪悲，唐人獨解詩。',48,'全唐诗/poet.tang.31000.json','["賈子命堪悲，唐人獨解詩。", "左遷今已矣，清絕更無之。", "畢竟吾猶許，商量衆莫疑。", "嘉陵四十字，一一是天資。"]'),
('b3f70ba0-ebf2-4bf2-af45-b8d1e208103a','嘉陵驛','薛能','唐','唐诗','tang','','[]','江濤千疊閣千層，銜尾相隨盡室登。',64,'全唐诗/poet.tang.31000.json','["江濤千疊閣千層，銜尾相隨盡室登。", "稠樹蔽山聞杜宇，午煙薰日食嘉陵。", "頻題石上程多破，暫歇泉邊起不能。", "如此幸非名利切，益州來日合攜僧。"]'),
('c9ee60b9-b4c4-4b73-b2ce-9ecaaf9807ef','嘉陵驛','薛能','唐','唐诗','tang','','[]','盡室可招魂，蠻餘出蜀門。',48,'全唐诗/poet.tang.31000.json','["盡室可招魂，蠻餘出蜀門。", "雹涼隨雨氣，江熱傍山根。", "蠶月繰絲路，農時碌碡村。", "干將磨欲盡，無位可酬恩。"]'),
('fc618ba9-e099-45bf-9834-91a7e6a2faa8','西縣途中二十韻','薛能','唐','唐诗','tang','','[]','野客誤桑麻，從軍帶鏌鋣。',264,'全唐诗/poet.tang.31000.json','["野客誤桑麻，從軍帶鏌鋣。", "豈論之白帝，未合過黃花。", "落日投江縣，征塵漱齒牙。", "蜀音連井絡，秦分隔褒斜。", "硤路商逢使，山郵雀啅蛇。", "憶歸臨角黍，良遇得新瓜。", "食久庭陰轉，行多屐齒窪。", "氣清巖下瀑，煙漫雨餘畬。", "黃鳥當蠶候，稀蒿雜麥查。", "汗涼風似雪，漿度蜜如沙。", "野色生肥芋，鄉儀擣散茶。", "梯航經杜宇，烽候徹苴咩。", "逗石流何險，通關運固賒。", "葛侯真竭澤，劉主合亡家。", "陷彼貪功吠，貽爲黷武誇。", "陣圖誰許可，廟貌我揄揶。", "閑事休徵漢，斯行且詠巴。", "音繁來有鐸，軏盡去無車。", "溢目看風景，清懷嘯月華。", "焰樵烹紫筍，腰簟憩烏紗。", "杞國憂尋悟，臨邛渴自加。", "移文莫有誚，必不滯天涯。"]'),
('20cf0cd4-1732-4be3-90c2-33f34096f514','西縣作','薛能','唐','唐诗','tang','','[]','三年西蜀去如沈，西縣西來出萬岑。',64,'全唐诗/poet.tang.31000.json','["三年西蜀去如沈，西縣西來出萬岑。", "樹石向聞清漢浪，水風初見綠萍陰。", "平郊不愛行增氣，好井無疑漱入心。", "從此漸知光景異，錦都廻首盡愁吟。"]'),
('80f3f685-cb25-42a9-a94c-4fdf6e59194d','分水嶺望靈寶峰','薛能','唐','唐诗','tang','','[]','千尋萬仞峰，靈寶號何從。',48,'全唐诗/poet.tang.31000.json','["千尋萬仞峰，靈寶號何從。", "盛立同吾道，貪程阻聖蹤。", "嶺奇應有藥，壁峭盡無松。", "那得休于是，蹉跎亦臥龍。"]'),
('4ed14233-782c-4837-9c21-d6b8de27518b','水簾吟','薛能','唐','唐诗','tang','','[]','萬滴相隨萬響兼，路塵天產盡旁霑。',64,'全唐诗/poet.tang.31000.json','["萬滴相隨萬響兼，路塵天產盡旁霑。", "源從顥氣何因絕，派助前溪豈覺添。", "豪客每來清夏葛，愁人才見認愁簷。", "嘉名已極終難稱，別是風流不是簾。"]'),
('476a7515-beaf-48c6-9ac7-30a806289b97','褒斜道中','薛能','唐','唐诗','tang','','[]','十驛褒斜到處慵，眼前常似接靈蹤。',64,'全唐诗/poet.tang.31000.json','["十驛褒斜到處慵，眼前常似接靈蹤。", "江遙旋入旁來水，山豁猶藏向後峰。", "鳥徑惡時應立虎，畬田閑日自燒松。", "行吟却笑公車役，夜發星馳半不逢。"]'),
('7a1456fc-1458-4bc8-b1ec-95a010d93b81','褒城驛有故元相公舊題詩因仰歎而作','薛能','唐','唐诗','tang','','[]','鄂相頃題應好池，題云萬竹與千棃。',64,'全唐诗/poet.tang.31000.json','["鄂相頃題應好池，題云萬竹與千棃。", "我來已變當初地，前過應無繼此詩。", "敢歎臨行殊舊境，惟愁後事劣今時。", "閑吟四壁堪搔首，頻見青蘋白鷺鷥。"]'),
('f73d28ef-9d03-43ac-a2a9-18f7efe55726','題褒城驛池','薛能','唐','唐诗','tang','','[]','池館通秦檻向衢，舊聞佳賞此踟躕。',64,'全唐诗/poet.tang.31000.json','["池館通秦檻向衢，舊聞佳賞此踟躕。", "清涼不散亭猶在，事力何銷舫已無。", "釣客坐風臨島嶼，牧牛當雨食菰蒲。", "西川吟吏偏思葺，只恐歸尋水亦枯。"]'),
('631c54d9-ed1d-4e96-8394-021ab805c0d1','送崔學士赴東川','薛能','唐','唐诗','tang','','[]','羽人仙籍冠浮丘，欲作酇侯且蜀侯。',64,'全唐诗/poet.tang.31000.json','["羽人仙籍冠浮丘，欲作酇侯且蜀侯。", "導騎已多行劒閣，親軍全到近綿州。", "文翁勸學人應戀，魏絳和戎戍自休。", "唯有夜罇懽莫厭，廟堂他日少閑遊。"]'),
('999dd198-0503-496e-9a0a-2a0f4414584d','海棠','薛能','唐','唐诗','tang','','[]','酷烈復離披，玄功莫我知。',120,'全唐诗/poet.tang.31000.json','["酷烈復離披，玄功莫我知。", "青苔浮落處，暮柳間開時。", "帶醉遊人插，連陰被叟移。", "晨前清露濕，晏後惡風吹。", "香少傳何許，妍多畫半遺。", "島蘇漣水脉，庭綻粒松枝。", "偶汎因沈硯，閑飄欲亂碁。", "遶山生玉壘，和郡徧坤維。", "負賞慙休飲，牽吟分失飢。", "明年應不見，留此贈巴兒。"]'),
('918ace29-2ca6-4146-9993-0a9dac3f5835','詠夾逕菊','薛能','唐','唐诗','tang','','[]','夾逕盡黃英，不通人竝行。',72,'全唐诗/poet.tang.31000.json','["夾逕盡黃英，不通人竝行。", "幾曾相對綻，元自兩行生。", "叢比高低等，香連左右幷。", "畔搖風勢斷，中夾日華明。", "間隔蛩吟隔，交橫蝶亂橫。", "頻應泛桑落，摘處近前楹。"]'),
('f046f5b8-ac87-4fe5-8791-72a4c73cf0f0','碧鮮亭春題竹','薛能','唐','唐诗','tang','','[]','竹少竹更重，碧鮮疆更名。',48,'全唐诗/poet.tang.31000.json','["竹少竹更重，碧鮮疆更名。", "有欄常凭立，無徑獨穿行。", "夕月陰何亂，春風葉盡輕。", "已聞圖畫客，兼寫薛先生。"]'),
('58ff6be6-3f77-4ab2-b666-4b148d1bae90','竹逕','薛能','唐','唐诗','tang','','[]','盤逕入依依，旋驚幽鳥飛。',48,'全唐诗/poet.tang.31000.json','["盤逕入依依，旋驚幽鳥飛。", "尋多苔色古，踏碎籜聲微。", "鞭節橫妨戶，枝梢動拂衣。", "前溪聞到處，應接釣魚磯。"]'),
('9458886b-b242-4dea-b299-6f435fa11ccb','新柳','薛能','唐','唐诗','tang','','[]','輕輕須重不須輕，衆木難成獨早成。',64,'全唐诗/poet.tang.31000.json','["輕輕須重不須輕，衆木難成獨早成。", "柔性定勝剛性立，一枝還引萬枝生。", "天鍾和氣元無力，時遇風光別有情。", "誰道少逢知己用，將軍因此建雄名。"]'),
('fcbce961-5f45-4684-b8ec-c7ad497c1a13','牡丹四首 一','薛能','唐','唐诗','tang','','[]','異色稟陶甄，常疑主者偏。',144,'全唐诗/poet.tang.31000.json','["異色稟陶甄，常疑主者偏。", "衆芳殊不類，一笑獨奢妍。", "顆折羞含嬾，藂虛隱陷圓。", "亞心堆勝被，美色豔於蓮。", "品格如寒食，精光似少年。", "種堪收子子，價合易賢賢。", "迥秀應無妬，奇香稱有仙。", "深陰宜映幕，富貴助開筵。", "蜀水爭能染，巫山未可憐。", "數難忘次第，立困戀傍邊。", "逐日愁風雨，和星祝夜天。", "且從留盡賞，離此便歸田。"]'),
('0f26f6d3-1404-40c9-8215-9a4658635435','牡丹四首 二','薛能','唐','唐诗','tang','','[]','萬朵照初筵，狂遊憶少年。',168,'全唐诗/poet.tang.31000.json','["萬朵照初筵，狂遊憶少年。", "曉光如曲水，顏色似西川。", "白向庚辛受，朱從造化研。", "衆開成伴侶，相笑極神仙。", "見焰寧勞火，聞香不帶煙。", "自高輕月桂，非偶賤池蓮。", "影接彫盤動，藂遭惡草偏。", "招歡憂事阻，就臥覺情牽。", "四面宜綈錦，當頭稱管弦。", "泊來鶯定憶，粉擾蝶何顛。", "蘇息承朝露，滋榮仰霽天。", "壓欄多盡好，敵國貴宜然。", "未落須迷醉，因茲任病纏。", "人誰知極物，空負感麟篇。"]'),
('4f5526e1-3419-41e3-8c98-824d05c344a3','牡丹四首 三','薛能','唐','唐诗','tang','','[]','去年零落暮春時，淚濕紅牋怨別離。',64,'全唐诗/poet.tang.31000.json','["去年零落暮春時，淚濕紅牋怨別離。", "常恐便隨巫峽散，何因重有武陵期。", "傳情每向馨香得，不語還應彼此知。", "欲就欄邊安枕席，夜深閑共說相思。"]'),
('f257cfa8-0bf5-4def-bcfe-3eb334896b72','牡丹四首 四','薛能','唐','唐诗','tang','','[]','牡丹愁爲牡丹飢，自惜多情欲瘦羸。',64,'全唐诗/poet.tang.31000.json','["牡丹愁爲牡丹飢，自惜多情欲瘦羸。", "濃豔冷香初蓋後，好風乾雨正開時。", "吟蜂遍坐無閑蘂，醉客曾偷有折枝。", "京國別來誰占翫，此花光景屬吾詩。"]'),
('d535dbb0-7b9e-4396-9d86-717098deeb18','使院栽葦','薛能','唐','唐诗','tang','','[]','戛戛復差差，一叢千萬枝。',48,'全唐诗/poet.tang.31000.json','["戛戛復差差，一叢千萬枝。", "格如僧住處，栽得吏閑時。", "筍自廳中出，根從府外移。", "從軍無宿例，空想夜風吹。"]'),
('8c3b1442-6043-4896-ba6f-507c542f6439','失鶴二首 一','薛能','唐','唐诗','tang','','[]','偶背雕籠與我違，四方端佇竟忘歸。',64,'全唐诗/poet.tang.31000.json','["偶背雕籠與我違，四方端佇竟忘歸。", "誰家白日雲間見，何處滄洲雨裏飛。", "曾啄稻粱殘粒在，舊翹泥潦半蹤稀。", "憑人轉覺多相誤，盡道皤然作令威。"]'),
('b98f192e-32d0-4201-98fa-9ffaed303fbd','失鶴二首 二','薛能','唐','唐诗','tang','','[]','華表翹風未可期，變丁投衛兩堪疑。',64,'全唐诗/poet.tang.31000.json','["華表翹風未可期，變丁投衛兩堪疑。", "應緣失路防人損，空有歸心最我知。", "但見空籠拋夕月，若何無樹宿荒陂。", "不然直道高空外，白水青山屬臘師。"]'),
('03e4f87c-442b-461b-b1bd-94e569cd4748','答賈支使寄鶴','薛能','唐','唐诗','tang','','[]','瑞羽奇姿踉蹌形，稱爲仙馭過清冥。',64,'全唐诗/poet.tang.31000.json','["瑞羽奇姿踉蹌形，稱爲仙馭過清冥。", "何年厚祿曾居衛，幾世前身本姓丁。", "幸有遠雲兼遠水，莫臨華表望華亭。", "勞君贈我清歌侶，將去田園夜坐聽。"]'),
('7c5ae326-1ccf-458e-8787-8cb6bbdb8de3','陳州刺史寄鶴','薛能','唐','唐诗','tang','','[]','臨風高視聳奇形，渡海沖天想盡經。',64,'全唐诗/poet.tang.31000.json','["臨風高視聳奇形，渡海沖天想盡經。", "因得羽儀來合浦，便無魂夢去華亭。", "春飛見境乘桴切，夜唳聞時醉枕醒。", "南守欲知多少重，撫毛千萬喚丁丁。"]'),
('fad94711-e545-4a3b-822d-ced27a8cfc4c','孔雀','薛能','唐','唐诗','tang','','[]','偶有功名正俗才，靈禽何事降瑤臺。',64,'全唐诗/poet.tang.31000.json','["偶有功名正俗才，靈禽何事降瑤臺。", "天仙黼黻毛應是，宮后屏幃尾忽開。", "曾處嶂中真霧隱，每過庭下似春來。", "佳人爲我和衫拍，遣作傞傞送一杯。"]'),
('68e50695-e4c1-4426-bb7a-844c91ec4a14','鄜州進白野鵲','薛能','唐','唐诗','tang','','[]','輕毛疊雪翅開霜，紅觜能深練尾長。',64,'全唐诗/poet.tang.31000.json','["輕毛疊雪翅開霜，紅觜能深練尾長。", "名應玉符朝北闕，色柔金性瑞西方。", "不憂雲路填河遠，爲對天顏送喜忙。", "從此定知栖息處，月宮瓊樹是仙鄉。"]'),
('1c8d29b5-19cd-4ea0-be5b-81a62849f9a9','早蟬','薛能','唐','唐诗','tang','','[]','不見上庭樹，日高聲忽吟。',48,'全唐诗/poet.tang.31000.json','["不見上庭樹，日高聲忽吟。", "他人豈無耳，遠客自關心。", "暫落還因雨，橫飛亦向林。", "分明去年意，從此漸聞砧。"]'),
('21ea4119-61ac-466f-a213-12e142367f09','申湖','薛能','唐','唐诗','tang','','[]','昔年依峽寺，每日見申湖。',96,'全唐诗/poet.tang.31000.json','["昔年依峽寺，每日見申湖。", "下淚重來此，知心一已無。", "雨霖舟色暗，岸拔木形枯。", "舊境深相惱，新春宛不殊。", "方來尋熟侶，起去恨驚鳧。", "忍事花何笑，喧吟瀑正麤。", "堪憂從宦到，倍遣曩懷孤。", "上馬終回首，傍人怪感吁。"]'),
('b4636285-4584-486f-8b92-1192ac91983a','謝劉相寄天柱茶','薛能','唐','唐诗','tang','','[]','兩串春團敵夜光，名題天柱印維揚。',64,'全唐诗/poet.tang.31000.json','["兩串春團敵夜光，名題天柱印維揚。", "偷嫌曼倩桃無味，搗覺嫦娥藥不香。", "惜恐被分緣利市，盡應難覓爲供堂。", "麤官寄與真拋却，賴有詩情合得嘗。"]'),
('3816c063-78bf-4c2b-a95b-34c41e858712','題後集','薛能','唐','唐诗','tang','','[]','詩源何代失澄清，處處狂波汙後生。',64,'全唐诗/poet.tang.31000.json','["詩源何代失澄清，處處狂波汙後生。", "常感道孤吟有淚，却緣風壞語無情。", "難甘惡少欺韓信，枉被諸侯殺禰衡。", "縱到緱山也無益，四方聯絡盡蛙聲。"]'),
('8afbf6d1-854d-4d11-9b9e-ac1a7224b5df','秋晚送無可上人','薛能','唐','唐诗','tang','','[]','半夜覺松雨，照書燈悄然。',48,'全唐诗/poet.tang.31000.json','["半夜覺松雨，照書燈悄然。", "河聲纔淅瀝，舊業近潺湲。", "坐滴寒更盡，吟驚宿鶴遷。", "相思不相見，日短復愁牽。"]'),
('44143931-90d0-4137-b3aa-a7a24442916d','贈源寂禪師','薛能','唐','唐诗','tang','','[]','缾鉢鎮隨腰，怡然處寂寥。',48,'全唐诗/poet.tang.31000.json','["缾鉢鎮隨腰，怡然處寂寥。", "門禪從北祖，僧格似南朝。", "性近徒相許，緣多媿未銷。", "何傳能法慧，此岸要津橋。"]'),
('150741f5-a2c3-4a9f-8f6e-401232d39302','贈禪師','薛能','唐','唐诗','tang','','[]','嗜慾本無性，此生長在禪。',48,'全唐诗/poet.tang.31000.json','["嗜慾本無性，此生長在禪。", "九州空有路，一室獨多年。", "鳴磬微塵落，移缾濕地圓。", "相尋偶同宿，星月坐忘眠。"]'),
('932041d0-4755-40d0-92a8-2b5ad1ea352f','夏日青龍寺尋僧二首 一','薛能','唐','唐诗','tang','','[]','帝里欲何待，人間無闕遺。',48,'全唐诗/poet.tang.31000.json','["帝里欲何待，人間無闕遺。", "不能安舊隱，都屬擾明時。", "違理須齊辱，雄圖豈藉知。", "縱橫悉已悞，斯語是吾師。"]'),
('0291f9c5-7edb-42e6-9203-3e1cf3608bdd','夏日青龍寺尋僧二首 二','薛能','唐','唐诗','tang','','[]','得官殊未喜，失計是忘愁。',48,'全唐诗/poet.tang.31000.json','["得官殊未喜，失計是忘愁。", "不是無心速，焉能有自由。", "涼風盈夏扇，蜀茗半形甌。", "笑向權門客，應難見道流。"]'),
('220a2648-e3ad-4015-9126-86a498b19703','寄題巨源禪師','薛能','唐','唐诗','tang','','[]','風雨禪思外，應殘木槿花。',48,'全唐诗/poet.tang.31000.json','["風雨禪思外，應殘木槿花。", "何年別鄉土，一衲代袈裟。", "日氣侵瓶暖，雷聲動枕斜。", "還當掃樓影，天晚自煎茶。"]'),
('cf8d762b-47fb-4980-b607-c0192be75491','題河中亭子','薛能','唐','唐诗','tang','','[]','河擘雙流島在中，島中亭上正南空。',64,'全唐诗/poet.tang.31000.json','["河擘雙流島在中，島中亭上正南空。", "蒲根舊浸臨關道，沙色遙飛傍苑風。", "晴見樹卑知岳大，晚聞車亂覺橋通。", "無窮勝事應須宿，霜白蒹葭月在東。"]'),
('46363da9-21bd-4264-a42b-de9ca9c437a8','逢友人邊遊迴','薛能','唐','唐诗','tang','','[]','遊子新從絕塞迴，自言曾上李陵臺。',32,'全唐诗/poet.tang.31000.json','["遊子新從絕塞迴，自言曾上李陵臺。", "尊前語盡北風起，秋色蕭條胡雁來。"]'),
('89fe9ccb-a211-431f-bb99-1314656edd3f','春雨','薛能','唐','唐诗','tang','','[]','電闊照潺潺，驚流往復還。',72,'全唐诗/poet.tang.31000.json','["電闊照潺潺，驚流往復還。", "遠聲如有洞，迷色似無山。", "利物乾坤內，幷風竹樹間。", "靜思來朔漠，愁望滿柴關。", "迸濕消塵慮，吹風觸疾顏。", "誰知草茅逕，霑此尚虛閑。"]'),
('99365897-a87c-4fc7-b36a-9b687f847aa1','夏雨','薛能','唐','唐诗','tang','','[]','何處發天涯，風雷一道賒。',48,'全唐诗/poet.tang.31000.json','["何處發天涯，風雷一道賒。", "去聲隨地急，殘勢傍樓斜。", "透樹垂紅葉，霑塵帶落花。", "瀟湘無限思，閑看下蒹葭。"]'),
('1b3183b2-8f62-4300-9ee1-b89a723b9aea','秋夜山中述事','薛能','唐','唐诗','tang','','[]','初宵門未掩，獨坐對霜空。',48,'全唐诗/poet.tang.31000.json','["初宵門未掩，獨坐對霜空。", "極目故鄉月，滿溪寒草風。", "樵聲當嶺上，僧語在雲中。", "正恨歸期晚，蕭蕭聞塞鴻。"]'),
('2fa14c7f-f540-41c6-b510-314cf6a9a75e','長安道','薛能','唐','唐诗','tang','','[]','汲汲復營營，東西連兩京。',72,'全唐诗/poet.tang.31000.json','["汲汲復營營，東西連兩京。", "關繻古若在，山岳累應成。", "各自有身事，不相知姓名。", "交馳兼衆類，分散入重城。", "此去應無盡，萬方人旋生。", "空餘片言苦，來往覓劉楨。"]'),
('f2e11d25-2030-4754-9924-c9d0c17b3bf0','酬泗州韋中丞埇上日寄贈兼次本韻','薛能','唐','唐诗','tang','','[]','魯儒相悟欲成空，學盡文章不見功。',64,'全唐诗/poet.tang.31000.json','["魯儒相悟欲成空，學盡文章不見功。", "官自掖垣飄海上，鎮從隨岸入山中。", "嘗遭火發瞿雲宅，爭得天如老氏弓。", "何意杜陵懷寶客，也隨迷路出關東。"]'),
('a7e61e1f-e5da-4924-950b-0eeda938c055','泛觴池','薛能','唐','唐诗','tang','','[]','通咽遠華罇，泛觴名自君。',48,'全唐诗/poet.tang.31000.json','["通咽遠華罇，泛觴名自君。", "淨看籌見影，輕動酒生紋。", "細滴隨杯落，來聲就浦分。", "便應半酣後，清冷漱兼雲。"]'),
('12cc527e-28e0-4e0f-ac6a-b0b29ff0ce4a','荔枝','薛能','唐','唐诗','tang','','[]','顆如松子色如櫻，未識蹉跎欲半生。',32,'全唐诗/poet.tang.31000.json','["顆如松子色如櫻，未識蹉跎欲半生。", "歲杪監州曾見樹，時新入座久聞名。"]'),
('cf379d92-0456-4a9d-b0f9-eac0d86833cc','丁巳上元日放三雉','薛能','唐','唐诗','tang','','[]','嬰網雖皆困，褰籠喜共歸。',24,'全唐诗/poet.tang.31000.json','["嬰網雖皆困，褰籠喜共歸。", "無心期爾報，相見莫驚飛。"]'),
('5d8cf66e-f9c8-4ead-98b0-7df7c811e412','寓題','薛能','唐','唐诗','tang','','[]','王澤猶來雅在新，尚詞微事可愁人。',32,'全唐诗/poet.tang.31000.json','["王澤猶來雅在新，尚詞微事可愁人。", "淫哇滿眼關雎弱，猶賀清朝有此身。"]'),
('6df8c412-98ba-4e49-b4df-a4ccb373761f','望蜀亭','薛能','唐','唐诗','tang','','[]','樹簇烟迷蜀國深，嶺頭分界戀登臨。',32,'全唐诗/poet.tang.31000.json','["樹簇烟迷蜀國深，嶺頭分界戀登臨。", "前軒一望無他處，從此西川只在心。"]'),
('b1f6fbb8-8d72-4c58-a4c1-1a515a3ea09b','游嘉州後溪','薛能','唐','唐诗','tang','','[]','山屐經過滿逕蹤，隔溪遙見夕陽舂。',32,'全唐诗/poet.tang.31000.json','["山屐經過滿逕蹤，隔溪遙見夕陽舂。", "當時諸葛成何事，只合終身作臥龍。"]'),
('ace729f4-de76-4b78-b067-18029f3ba3dc','自諷','薛能','唐','唐诗','tang','','[]','千題萬詠過三旬，忘食貪魔作瘦人。',32,'全唐诗/poet.tang.31000.json','["千題萬詠過三旬，忘食貪魔作瘦人。", "行處便吟君莫笑，就中詩病不任春。"]'),
('deb6904f-a200-435c-96a4-0a18eee66e9a','乞假歸題候館','薛能','唐','唐诗','tang','','[]','僕帶雕弓馬似飛，老萊衣上著戎衣。',32,'全唐诗/poet.tang.31000.json','["僕帶雕弓馬似飛，老萊衣上著戎衣。", "郵亭不暇吟山水，塞外經年皆未歸。"]'),
('ae07da10-1611-4d09-ab1b-668174ed07ab','監郡犍爲將歸使府登樓寓題','薛能','唐','唐诗','tang','','[]','幾日監臨向蜀春，錯拋歌酒強憂人。',32,'全唐诗/poet.tang.31000.json','["幾日監臨向蜀春，錯拋歌酒強憂人。", "江樓一望西歸去，不負嘉州只負身。"]'),
('0c4ce05a-8390-4f51-87f0-2485cf3fff22','過象耳山二首 一','薛能','唐','唐诗','tang','','[]','一色青松幾萬栽，異香薰路帶花開。',32,'全唐诗/poet.tang.31000.json','["一色青松幾萬栽，異香薰路帶花開。", "山門欲別心潛願，更到蜀中還到來。"]'),
('98bbdf4d-d139-4aa1-ad85-f5c8884e1d7d','過象耳山二首 二','薛能','唐','唐诗','tang','','[]','到處逢山便欲登，自疑身作往來僧。',32,'全唐诗/poet.tang.31000.json','["到處逢山便欲登，自疑身作往來僧。", "徒行至此三千里，不是有緣應不能。"]'),
('580c66f7-8653-4e62-9cdf-24f3b662369f','聖燈','薛能','唐','唐诗','tang','','[]','莽莽空中稍稍燈，坐看迷濁變[清澄]。',34,'全唐诗/poet.tang.31000.json','["莽莽空中稍稍燈，坐看迷濁變[清澄]。", "須知火盡煙無益，一夜欄邊說向僧。"]'),
('413d4b5c-fbe3-4600-a40b-8d4e420405fc','過昌利觀有懷','薛能','唐','唐诗','tang','','[]','萬仞雲峯八石泉，李君仙後更誰仙。',32,'全唐诗/poet.tang.31000.json','["萬仞雲峯八石泉，李君仙後更誰仙。", "我來駐馬人何問，老柏無多不種田。"]'),
('9d9df24b-d5b8-40d7-861e-90e1cd230f2a','蜀路','薛能','唐','唐诗','tang','','[]','劒閣緣雲拂斗魁，疾風生樹過龍媒。',32,'全唐诗/poet.tang.31000.json','["劒閣緣雲拂斗魁，疾風生樹過龍媒。", "前程憩罷知無益，但是駑蹄亦到來。"]'),
('281d1378-d0e8-49c3-9915-57b6994fae0e','山下偶作','薛能','唐','唐诗','tang','','[]','零雨霑山百草香，樹梢高頂盡斜陽。',32,'全唐诗/poet.tang.31000.json','["零雨霑山百草香，樹梢高頂盡斜陽。", "橫流巨石皆堪住，何事無僧有石房。"]'),
('08d05dcc-9355-4b5f-9c33-43be2826e1ca','伏牛山','薛能','唐','唐诗','tang','','[]','虎蹲峰狀屈名牛，落日連村好望秋。',32,'全唐诗/poet.tang.31000.json','["虎蹲峰狀屈名牛，落日連村好望秋。", "不爲時危耕不得，一犁風雨便歸休。"]'),
('d74fd5a2-480a-486f-8be1-f41acacd51fb','老圃堂','薛能','唐','唐诗','tang','','[]','邵平瓜地接吾廬，穀雨乾時偶自鋤。',32,'全唐诗/poet.tang.31000.json','["邵平瓜地接吾廬，穀雨乾時偶自鋤。", "昨日春風欺不在，就牀吹落讀殘書。"]'),
('3b2fef66-69fd-4be7-b9c8-263ec345282d','春題','薛能','唐','唐诗','tang','','[]','柳莫搖搖花莫開，此心因病亦成灰。',32,'全唐诗/poet.tang.31000.json','["柳莫搖搖花莫開，此心因病亦成灰。", "人生只有家園樂，及取春農歸去來。"]'),
('207fcfd4-0d58-4721-8840-61c2677c84e9','幷州寓懷','薛能','唐','唐诗','tang','','[]','人多知遇獨難求，人負知音獨愛酬。',32,'全唐诗/poet.tang.31000.json','["人多知遇獨難求，人負知音獨愛酬。", "常恐此心無樂處，枉稱年少在幷州。"]'),
('b0c30762-824e-444a-98b7-4c21597e3f39','中秋旅舍','薛能','唐','唐诗','tang','','[]','雲卷庭虛月逗空，一方秋草盡鳴蟲。',32,'全唐诗/poet.tang.31000.json','["雲卷庭虛月逗空，一方秋草盡鳴蟲。", "是時兄弟正南北，黃葉滿階來去風。"]'),
('f07a2c0a-2ee3-4e4c-8c67-b13079494901','符亭二首 一','薛能','唐','唐诗','tang','','[]','符亭之地雅離羣，萬古懸泉一旦新。',32,'全唐诗/poet.tang.31000.json','["符亭之地雅離羣，萬古懸泉一旦新。", "若念農桑也如此，縣人應得似行人。"]'),
