('370684bf-dd34-4d02-9ea7-e42789a0cca0','題于公花園','薛能','唐','唐诗','tang','','[]','含桃莊主後園深，繁實初成靜掃陰。',32,'全唐诗/poet.tang.31000.json','["含桃莊主後園深，繁實初成靜掃陰。", "若使明年花可待，應須惱破事花心。"]'),
('038b65eb-9b5b-40af-86de-e02947a3b47e','登城','薛能','唐','唐诗','tang','','[]','偶作閑身上古城，路人遙望不相驚。',32,'全唐诗/poet.tang.31000.json','["偶作閑身上古城，路人遙望不相驚。", "無端將吏逡巡至，又作都頭一隊行。"]'),
('348706f7-15b7-4622-96be-bcef4f3369ec','好客','薛能','唐','唐诗','tang','','[]','好客連宵在醉鄉，蠟煙紅暖勝春光。',32,'全唐诗/poet.tang.31000.json','["好客連宵在醉鄉，蠟煙紅暖勝春光。", "誰人肯信山僧語，寒雨唯煎治氣湯。"]'),
('c3902f9b-b4b5-4171-b8da-62758500aabf','贈普恭禪師','薛能','唐','唐诗','tang','','[]','一日迢迢每一飡，我心難伏我無難。',32,'全唐诗/poet.tang.31000.json','["一日迢迢每一飡，我心難伏我無難。", "南簷十月繩牀暖，背卷真經向日看。"]'),
('873c2154-67e3-4223-9d08-83b011608bd8','贈無表禪師','薛能','唐','唐诗','tang','','[]','笠戴圓陰楚地椶，磬敲清響蜀山銅。',32,'全唐诗/poet.tang.31000.json','["笠戴圓陰楚地椶，磬敲清響蜀山銅。", "秋來說偈寅朝殿，爽爽楊枝滿手風。"]'),
('447e806a-406e-49b7-bca5-45978db07e68','彭門偶題','薛能','唐','唐诗','tang','','[]','淮王西舍固非夫，柳惲偏州未是都。',32,'全唐诗/poet.tang.31000.json','["淮王西舍固非夫，柳惲偏州未是都。", "直到春秋諸列國，擁旄才子也應無。"]'),
('46605d7a-4f84-4900-9017-210f267a64fa','嘲趙璘','薛能','唐','唐诗','tang','','[]','巡關每傍摴蒲局，望月還登乞巧樓。',32,'全唐诗/poet.tang.31000.json','["巡關每傍摴蒲局，望月還登乞巧樓。", "第一莫敎嬌太過，緣人衣帶上人頭。"]'),
('5f44cd6d-266d-4232-a075-51d87b80dfe5','句','薛能','唐','唐诗','tang','','[]','百首如一首，卷初如卷終。',64,'全唐诗/poet.tang.31000.json','["百首如一首，卷初如卷終。", "坐久僕頭出，語多僧齒寒。", "西塞長雲盡，南湖片月斜。", "李白終無取，陶潛固不刊。", "我身若在開元日，爭遣名爲李翰林。"]'),
('d03b763c-fd98-4e42-b4b8-3d62030aa7eb','早春','劉威','唐','唐诗','tang','','[]','曉來庭戶外，草樹似依依。',48,'全唐诗/poet.tang.31000.json','["曉來庭戶外，草樹似依依。", "一夜東風起，萬山春色歸。", "冰消泉派動，日暖露珠晞。", "已醞看花酒，嬌鶯莫預飛。"]'),
('f3f657ed-4a19-4456-a596-ab719f5cacc6','傷春感懷','劉威','唐','唐诗','tang','','[]','花飛惜不得，年長更堪悲。',48,'全唐诗/poet.tang.31000.json','["花飛惜不得，年長更堪悲。", "春盡有歸日，老來無去時。", "風前千片雪，鏡裏數莖絲。", "腸斷青山暮，獨攀楊柳枝。"]'),
('45dc8ca6-5d43-4e30-84f6-45feda11d5ed','閏三月','劉威','唐','唐诗','tang','','[]','三年皆一閏，此閏勝常時。',48,'全唐诗/poet.tang.31000.json','["三年皆一閏，此閏勝常時。", "莫怪花開晚，都緣春盡遲。", "節分炎氣近，律應蕙風移。", "夢得成胡蝶，芳菲幸不遺。"]'),
('810dbe7f-09aa-45d5-b727-7b761660a70c','早秋遊湖上亭','劉威','唐','唐诗','tang','','[]','危亭秋尚早，野思已無窮。',48,'全唐诗/poet.tang.31000.json','["危亭秋尚早，野思已無窮。", "竹葉一尊酒，荷香四座風。", "曉煙孤嶼外，歸鳥夕陽中。", "漸愛湖光冷，移舟月滿空。"]'),
('14703bf5-d8a6-4107-a57c-07add19ecd85','宿漁家','劉威','唐','唐诗','tang','','[]','竹屋清江上，風煙四五家。',48,'全唐诗/poet.tang.31000.json','["竹屋清江上，風煙四五家。", "水園分芰葉，鄰界認蘆花。", "雨到魚翻浪，洲迴鳥傍沙。", "月明何處去，片片席帆斜。"]'),
('8cf41d1b-b03d-408a-804f-43a6e4dae6ac','旅中早秋','劉威','唐','唐诗','tang','','[]','金威生止水，爽氣遍遙空。',48,'全唐诗/poet.tang.31000.json','["金威生止水，爽氣遍遙空。", "草色蕭條路，槐花零落風。", "夜來萬里月，覺後一聲鴻。", "莫問前程事，颯然沙上蓬。"]'),
('871701ca-3791-454c-a3e7-34f91aa8951b','早秋西歸有懷','劉威','唐','唐诗','tang','','[]','求歸方有計，惜別更堪愁。',48,'全唐诗/poet.tang.31000.json','["求歸方有計，惜別更堪愁。", "上馬江城暮，出郊山戍秋。", "暗銷何限事，白盡去年頭。", "莫怪頻惆悵，異鄉難再遊。"]'),
('484e4b8b-1f12-4c49-b5a2-717d8d1b9685','冬夜旅懷','劉威','唐','唐诗','tang','','[]','寒窗危竹枕，月過半牀陰。',48,'全唐诗/poet.tang.31000.json','["寒窗危竹枕，月過半牀陰。", "嫩葉不歸夢，晴蟲成苦吟。", "酒無通夜力，事滿五更心。", "寂寞誰相似，殘燈與素琴。"]'),
('8298cc54-e826-4ca8-bf6b-8285dbce5378','塞上作','劉威','唐','唐诗','tang','','[]','蕭蕭隴水側，落日客愁中。',48,'全唐诗/poet.tang.31000.json','["蕭蕭隴水側，落日客愁中。", "古塞一聲笛，長沙千里風。", "鳥無棲息處，人愛戰爭功。", "數夜城頭月，彎彎如引弓。"]'),
('36ec25f7-53f6-4bf5-ad93-ef3ee28c4761','秋日寄陳景孚秀才','劉威','唐','唐诗','tang','','[]','征車日已遠，物候尚淒淒。',48,'全唐诗/poet.tang.31000.json','["征車日已遠，物候尚淒淒。", "風葉青桐落，露花紅槿低。", "心隨秦國遠，夢到楚山迷。", "却恨銜蘆鴈，秋飛不向西。"]'),
('c8da3899-c3ad-4b5f-ab8a-2b6ab3ca02da','冬日送友人西歸','劉威','唐','唐诗','tang','','[]','北風吹別思，杳杳度雲山。',48,'全唐诗/poet.tang.31000.json','["北風吹別思，杳杳度雲山。", "滿望是歸處，一生猶未閑。", "知音方見譽，浮宦久相關。", "空有心如月，同居千里還。"]'),
('fa752425-61bf-4baf-b534-608c2001b353','感寓','劉威','唐','唐诗','tang','','[]','海竭山移歲月深，分明齊得世人心。',64,'全唐诗/poet.tang.31000.json','["海竭山移歲月深，分明齊得世人心。", "顏回徒恨少成古，彭祖何曾老至今。", "須向道中平貴賤，還從限內任浮沈。", "他年免似驪山鬼，信有蓬萊不可尋。"]'),
('85fcb8b2-075f-4635-95b5-c14e815fabdc','七夕','劉威','唐','唐诗','tang','','[]','烏鵲橋成上界通，千秋靈會此宵同。',64,'全唐诗/poet.tang.31000.json','["烏鵲橋成上界通，千秋靈會此宵同。", "雲收喜氣星樓曉，香拂輕塵玉殿空。", "翠輦不行青草路，金鑾徒候白榆風。", "綵盤花閣無窮意，只在遊絲一縷中。"]'),
('f8d24ac9-126d-4870-8599-9173734f7686','晚春陪王員外東塘遊宴','劉威','唐','唐诗','tang','','[]','水綠山青春日長，政成因暇泛回塘。',64,'全唐诗/poet.tang.31000.json','["水綠山青春日長，政成因暇泛回塘。", "初移柳岸笙歌合，欲過蘋洲羅綺香。", "共濟已驚依玉樹，隨流還許醉金觴。", "一聲畫角嚴城暮，雲雨分時滿路光。"]'),
('49234525-7774-497c-9d13-0c70403e9b74','遊東湖黃處士園林','劉威','唐','唐诗','tang','','[]','偶向東湖更向東，數聲雞犬翠微中。',64,'全唐诗/poet.tang.31000.json','["偶向東湖更向東，數聲雞犬翠微中。", "遙知楊柳是門處，似隔芙蓉無路通。", "樵客出來山帶雨，漁舟過去水生風。", "物情多與閑相稱，所恨求安計不同。"]'),
('024a6b65-b543-41cc-89eb-af2f33164db1','題許子正處士新池','劉威','唐','唐诗','tang','','[]','坐愛風塵日已西，功成得與化工齊。',64,'全唐诗/poet.tang.31000.json','["坐愛風塵日已西，功成得與化工齊。", "巧分孤島思何遠，欲似五湖心易迷。", "漸有野禽來試水，又憐春草自侵隄。", "那堪更到芙蓉拆，晚夕香聯桃李蹊。"]'),
('fb760b4c-60d5-46e3-82df-c0edf0ac55ee','旅懷','劉威','唐','唐诗','tang','','[]','物態人心漸渺茫，十年徒學釣滄浪。',64,'全唐诗/poet.tang.31000.json','["物態人心漸渺茫，十年徒學釣滄浪。", "老將何面還吾土，夢有驚魂在楚鄉。", "自是一身嫌苟合，誰憐今日欲佯狂。", "無名無位却無事，醉落烏紗臥夕陽。"]'),
('e9dbd1b1-59b8-407c-869f-aaf7f96f53ea','早秋歸','劉威','唐','唐诗','tang','','[]','數口飄零身未迴，夢魂遙斷越王臺。',64,'全唐诗/poet.tang.31000.json','["數口飄零身未迴，夢魂遙斷越王臺。", "家書欲寄鴈飛遠，客恨正深秋又來。", "風解綠楊三署冷，月當銀漢四山開。", "茫茫歸路在何處，砧杵一聲心已摧。"]'),
('996c3dca-9022-4c10-bd7a-dc189359052c','歐陽示新詩因貽四韻','劉威','唐','唐诗','tang','','[]','衝戛瑤瓊得至音，數篇清越應南金。',64,'全唐诗/poet.tang.31000.json','["衝戛瑤瓊得至音，數篇清越應南金。", "都由苦思無休日，已證前賢不到心。", "風入寒松聲自古，水歸滄海意皆深。", "欲知字字驚神鬼，一氣秋時試夜吟。"]'),
('20c1476c-fbf9-4134-8ccb-8b16b09251d3','尉遲將軍','劉威','唐','唐诗','tang','','[]','天仗擁門希授鉞，重臣入夢豈安金。',64,'全唐诗/poet.tang.31000.json','["天仗擁門希授鉞，重臣入夢豈安金。", "江河定後威風在，社稷危來寄託深。", "扶病暫將弓試力，感恩重與劍論心。", "明妃若遇英雄世，青塚何由怨陸沈。"]'),
('b41a2ac6-bb1b-48e2-9da5-c75b3164e8c9','贈歐陽秀才','劉威','唐','唐诗','tang','','[]','桐上知音日下身，道光誰不仰清塵。',64,'全唐诗/poet.tang.31000.json','["桐上知音日下身，道光誰不仰清塵。", "偶來水館逢爲客，舊熟詩名似故人。", "永日空驚滄海闊，何年重見白頭新。", "權門要路應行遍，閑伴山夫一夜貧。"]'),
('03cee168-b83e-4483-89f3-a27a200e5f2a','贈道者','劉威','唐','唐诗','tang','','[]','五雲深處有真仙，歲月催多却少年。',64,'全唐诗/poet.tang.31000.json','["五雲深處有真仙，歲月催多却少年。", "入郭不知今世事，賣丹猶覓古時錢。", "閑尋白鹿眠瑤草，暗摘紅桃去洞天。", "時向人間深夜坐，鬼神長在藥囊邊。"]'),
('8dd3c1be-a415-4895-b77c-e3e454593219','贈道者','劉威','唐','唐诗','tang','','[]','道帔輕裾三島雲，綠髯長占鏡中春。',64,'全唐诗/poet.tang.31000.json','["道帔輕裾三島雲，綠髯長占鏡中春。", "高風已駕祥鸞馭，浮世休驚野馬塵。", "過海獨辭王母面，度關誰識老聃身。", "儒生也愛長生術，不見人間大笑人。"]'),
('289759a9-5897-415d-a4d7-4a4e59a3035c','遣懷寄歐陽秀才','劉威','唐','唐诗','tang','','[]','地上江河天上烏，百年流轉只須臾。',64,'全唐诗/poet.tang.31000.json','["地上江河天上烏，百年流轉只須臾。", "平生閑過日將日，欲老始知吾負吾。", "似豹一班時或有，如龜三顧豈全無。", "古來晚達人何限，莫笑空枝猶望蘇。"]'),
('c8420503-eea9-47b8-a839-04d8d4f9cd7e','送元秀才入道','劉威','唐','唐诗','tang','','[]','不教榮樂損天機，願逐鸞皇次第飛。',64,'全唐诗/poet.tang.31000.json','["不教榮樂損天機，願逐鸞皇次第飛。", "明月滿時開道帔，俗塵飄處脫儒衣。", "只攜仙籍還金洞，便與時流隔翠微。", "空有緘題報親愛，一千年後始西歸。"]'),
('d25ad1fe-c20e-494b-9fbf-234bd6de9d6c','三閭大夫','劉威','唐','唐诗','tang','','[]','三閭一去湘山老，煙水悠悠痛古今。',64,'全唐诗/poet.tang.31000.json','["三閭一去湘山老，煙水悠悠痛古今。", "青史已書殷鑒在，詞人勞詠楚江深。", "竹移低影潛貞節，月入中流洗恨心。", "再引離騷見微旨，肯敎漁父會昇沈。"]'),
('493f71a1-febe-4c30-ab39-163afd3c387f','傷曾秀才馬','劉威','唐','唐诗','tang','','[]','買得龍媒越水濆，輕桃細杏色初分。',64,'全唐诗/poet.tang.31000.json','["買得龍媒越水濆，輕桃細杏色初分。", "秋歸未過陽關日，夜魄忽銷陰塞雲。", "吳練已知隨影沒，朔風猶想帶嘶聞。", "臨軒振策休惆悵，坐致煙霄只在君。"]'),
('4cb7a007-7ef8-487d-a000-aa47b2381cab','噴玉泉冥會詩八首 白衣叟途中吟二首 一','李玖','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u5ff5"]','春草萋萋春水綠，野棠開盡飄香玉。',32,'全唐诗/poet.tang.31000.json','["春草萋萋春水綠，野棠開盡飄香玉。", "繡嶺宮前鶴髮人，猶唱開元太平曲。"]'),
('c5df52bd-c35e-4d7f-bf3f-779d4fed5aec','噴玉泉冥會詩八首 白衣叟途中吟二首 二','李玖','唐','唐诗','tang','','[]','厭世逃名者，誰能荅姓名。',24,'全唐诗/poet.tang.31000.json','["厭世逃名者，誰能荅姓名。", "曾聞王樂否，眷取路傍情。"]'),
('ff7188b2-7f76-4197-a68b-f7f86d8271e0','噴玉泉冥會詩八首 白衣叟述甘棠館西楹詩','李玖','唐','唐诗','tang','','[]','浮雲淒慘日微明，沈痛將軍負罪名。',64,'全唐诗/poet.tang.31000.json','["浮雲淒慘日微明，沈痛將軍負罪名。", "白晝叫閽無近戚，縞衣飲氣只門生。", "佳人暗泣填宮淚，廐馬連嘶換主聲。", "六合茫茫皆漢土，此身無處哭田橫。"]'),
('7d67904a-b7bb-4b9b-9f68-4495b7582f87','噴玉泉冥會詩八首 白衣叟噴玉泉感舊遊書懷','李玖','唐','唐诗','tang','','[]','樹色川光向晚晴，舊曾遊處事分明。',64,'全唐诗/poet.tang.31000.json','["樹色川光向晚晴，舊曾遊處事分明。", "鼠穿月榭荆榛合，草掩花園畦壠平。", "迹陷黃沙仍未寤，罪標青簡竟何名。", "傷心谷口東流水，猶噴當時寒玉聲。"]'),
('3406400f-2968-42f3-b8c2-d86a1110bcca','噴玉泉冥會詩八首 四丈夫同賦 一','李玖','唐','唐诗','tang','','[]','鳥啼鶯語思何窮，一世榮華一夢中。',64,'全唐诗/poet.tang.31000.json','["鳥啼鶯語思何窮，一世榮華一夢中。", "李固有冤藏蠹簡，鄧攸無子續清風。", "文章高韻傳流水，絲管遺音託草蟲。", "春月不知人事改，閑垂光影照洿宮。"]'),
('152eed2d-cad2-48e0-99c6-dee08508c5d4','噴玉泉冥會詩八首 四丈夫同賦 二','李玖','唐','唐诗','tang','','[]','桃蹊李徑盡荒涼，訪舊尋新益自傷。',64,'全唐诗/poet.tang.31000.json','["桃蹊李徑盡荒涼，訪舊尋新益自傷。", "雖有衣衾藏李固，終無表疏雪王章。", "羈魂尚覺霜風冷，朽骨徒驚月桂香。", "天爵竟爲人爵悞，誰能高叫問蒼蒼。"]'),
('de058199-5b27-4b87-a078-d6dfab9d5283','噴玉泉冥會詩八首 四丈夫同賦 三','李玖','唐','唐诗','tang','','[]','落花寂寂草綿綿，雲影山光盡宛然。',66,'全唐诗/poet.tang.31000.json','["落花寂寂草綿綿，雲影山光盡宛然。", "壞室基摧新石鼠，瀦宮水引故山泉。", "青雲自致慚天爵，白首同[歸]感昔賢。", "惆悵林間中夜月，孤光曾照讀書筵。"]'),
('4a865837-f2a7-4c0a-a5ce-8b2896663827','噴玉泉冥會詩八首 四丈夫同賦 四','李玖','唐','唐诗','tang','','[]','新荆棘路舊衡門，又駐高車會一尊。',64,'全唐诗/poet.tang.31000.json','["新荆棘路舊衡門，又駐高車會一尊。", "寒骨未沾新雨露，春風不長敗蘭蓀。", "丹誠豈分埋幽壤，白日終希照覆盆。", "珍重昔年金谷友，共來泉際話幽魂。"]'),
('a44dc3e3-bee8-4523-a1d8-3288fdf0f825','下第歸宜春酬黃頗餞別','潘唐','唐','唐诗','tang','','[]','聖代澄清雨露均，獨懷惆悵出咸秦。',64,'全唐诗/poet.tang.31000.json','["聖代澄清雨露均，獨懷惆悵出咸秦。", "承明未薦相如賦，故國猶慚季子貧。", "御苑鐘聲臨遠水，都門樹色背行塵。", "一從此地曾攜手，益羨江頭桃李春。"]'),
('5164d760-c21f-4e5c-9d3f-67032ab8ccb7','題泐潭','裴休','唐','唐诗','tang','','[]','泐潭形勝地，祖塔在雲湄。',48,'全唐诗/poet.tang.31000.json','["泐潭形勝地，祖塔在雲湄。", "浩劫有窮日，真風無墜時。", "歲華空自老，消息竟誰知。", "到此輕塵慮，功名自可遺。"]'),
('e9c7b7b4-11e4-491a-81d7-8f3eff674928','贈黃蘖山僧希運','裴休','唐','唐诗','tang','','[]','曾傳達士心中印，額有圓珠七尺身。',64,'全唐诗/poet.tang.31000.json','["曾傳達士心中印，額有圓珠七尺身。", "挂錫十年棲蜀水，浮杯今日渡漳濱。", "一千龍象隨高步，萬里香華結勝因。", "擬欲事師爲弟子，不知將法付何人。"]'),
('44517169-5297-4342-a322-9353c0d329cd','登望京樓賦','令狐綯','唐','唐诗','tang','','[]','夷門一鎮五經秋，未得朝天不免愁。',32,'全唐诗/poet.tang.31000.json','["夷門一鎮五經秋，未得朝天不免愁。", "因上此樓望京國，便名樓作望京樓。"]'),
('2def3636-f6a8-4cbd-8eec-49e944e6b24e','享太廟樂章','夏侯孜','唐','唐诗','tang','','[]','於鑠令主，聖祚重昌。',40,'全唐诗/poet.tang.31000.json','["於鑠令主，聖祚重昌。", "興起敎義，申明典章。", "俗尚素朴，人皆樂康。", "積德可報，流慶無疆。"]'),
('8100633a-14fe-47d6-b018-e6341dc437b8','和重陽錫宴御製詩','魏謩','唐','唐诗','tang','','[]','四方無事去，宸豫杪秋來。',24,'全唐诗/poet.tang.31000.json','["四方無事去，宸豫杪秋來。", "八水寒光起，千山霽色開。"]'),
('63263b60-508c-4daa-8f71-7d017e2d453c','賀王僕射放榜','周墀','唐','唐诗','tang','','[]','文場三化魯儒生，三十餘年振重名。',64,'全唐诗/poet.tang.31000.json','["文場三化魯儒生，三十餘年振重名。", "曾忝木雞誇羽翼，又陪金馬入蓬瀛。", "雖欣月桂居先折，更羨春蘭最後榮。", "欲到龍門看風雨，關防不許暫離營。"]'),
('c69e1496-2c52-4632-9bd5-505488cb9f4a','酬李常侍立秋日奉詔祭嶽見寄','周墀','唐','唐诗','tang','','[]','秋祠靈嶽奉尊罍，風過深林古柏開。',64,'全唐诗/poet.tang.31000.json','["秋祠靈嶽奉尊罍，風過深林古柏開。", "蓮掌月高珪幣列，金天雨露鬼神陪。", "質明三獻雖終禮，祈壽千年別上杯。", "豈是瑣才能祀事，洪農太守主張來。"]'),
('bcd4d29e-5e2b-45f2-9c7c-f1f50932a87d','寄華州周侍郎立秋日奉詔祭嶽詩','李景讓','唐','唐诗','tang','','[]','關河豁靜曉雲開，承詔秋祠太守來。',64,'全唐诗/poet.tang.31000.json','["關河豁靜曉雲開，承詔秋祠太守來。", "山霽蓮花添翠黛，路陰桐葉少塵埃。", "朱轓入廟威儀肅，玉佩昇壇步武回。", "往歲今朝幾時事，謝君非重我非才。"]'),
('633ff2e6-edbc-4e31-87ea-c233f5b8f470','句','李景讓','唐','唐诗','tang','','[]','成都十萬戶，拋若一鴻毛。',12,'全唐诗/poet.tang.31000.json','["成都十萬戶，拋若一鴻毛。"]'),
('c8b5578d-ebd4-41f9-a0e2-6fc5cf53f1b6','續夢中十韻','鄭顥','唐','唐诗','tang','','[]','間歲流虹節，歸軒出禁扃。',120,'全唐诗/poet.tang.31000.json','["間歲流虹節，歸軒出禁扃。", "奔波陶畏景，蕭灑夢殊庭。", "境象非曾到，崇嚴昔未經。", "日斜烏斂翼，風動鶴飄翎。", "異苑人爭集，涼臺筆不停。", "石門霧露白，玉殿莓苔青。", "若匪災先兆，何緣思入冥。", "御爐虛仗馬，華蓋負云亭。", "白日成千古，金縢閟九齡。", "小臣哀絕筆，湖上泣青萍。"]'),
('809ea1ce-bc9d-4ffa-82da-323b7b6009cc','揚州送人','鄭顥','唐','唐诗','tang','','[]','桂檝木蘭舟，楓江竹箭流。',48,'全唐诗/poet.tang.31000.json','["桂檝木蘭舟，楓江竹箭流。", "故人從此去，望遠不勝愁。", "落日低帆影，歸風引櫂謳。", "思君折楊柳，淚盡武昌樓。"]'),
('03dbc38b-82e8-4c7e-9e4e-92239a64e52a','置酒','鄭顥','唐','唐诗','tang','','[]','酒熟人須飲，春還鬢已秋。',48,'全唐诗/poet.tang.31000.json','["酒熟人須飲，春還鬢已秋。", "願逢千日醉，得逭百年愁。", "卒卒周姬旦，棲棲魯孔丘。", "平生能幾日，不及且遨遊。"]'),
('599897c4-0fbf-4317-aa8e-9b4eac949cb9','重陽宴東觀山亭和從事盧順之','張固','唐','唐诗','tang','','[]','亂山青翠郡城東，爽節憑高一望通。',64,'全唐诗/poet.tang.31000.json','["亂山青翠郡城東，爽節憑高一望通。", "交友會時絲管合，羽觴飛處笑言同。", "金英耀彩晴雲外，玉樹凝霜暮雨中。", "高詠已勞潘岳思，醉歡慙道自車公。"]'),
('c459a7f6-7383-4ba2-b37d-581af3a1c888','獨秀山','張固','唐','唐诗','tang','','[]','孤峰不與衆山儔，直入青雲勢未休。',32,'全唐诗/poet.tang.31000.json','["孤峰不與衆山儔，直入青雲勢未休。", "會得乾坤融結意，擎天一柱在南州。"]'),
('9dc1bf87-dc4b-47ae-9c49-e57c8cb338ba','長門怨','劉臯','唐','唐诗','tang','','[]','營營孤思通，寂寂長門夜。',48,'全唐诗/poet.tang.31000.json','["營營孤思通，寂寂長門夜。", "妾妬亦知非，君恩那不借。", "攜琴就玉階，調悲聲未諧。", "將心寄明月，流影入君懷。"]'),
('328353d9-9592-461e-9cf7-23aaf3278024','宿日觀東房詩','李質','唐','唐诗','tang','','[]','曾入桃溪路，仙源信少雙。',48,'全唐诗/poet.tang.31000.json','["曾入桃溪路，仙源信少雙。", "洞霞飄素練，蘚壁畫陰窗。", "古木愁撐月，危峰欲墮江。", "自吟空向寂，誰共倒秋缸。"]'),
('6c1665f4-6069-4138-a632-748594019a13','贈副戎','南卓','唐','唐诗','tang','','[]','翱翔曾在玉京天，墮落江南路幾千。',32,'全唐诗/poet.tang.31000.json','["翱翔曾在玉京天，墮落江南路幾千。", "從事不須輕縣宰，滿身猶帶御爐煙。"]'),
('041d1573-4861-4954-8588-483813699dfc','命妓盛小叢歌餞崔侍御還闕','李訥','唐','唐诗','tang','','[]','繡衣奔命去情多，南國佳人斂翠娥。',32,'全唐诗/poet.tang.31000.json','["繡衣奔命去情多，南國佳人斂翠娥。", "曾向敎坊聽國樂，爲君重唱盛叢歌。"]'),
('fb7f3217-29dc-4db3-ae21-918a6fb16cd8','李尚書命妓歌餞有作奉酬','崔元範','唐','唐诗','tang','','[]','羊公留宴峴山亭，洛浦高歌五夜情。',32,'全唐诗/poet.tang.31000.json','["羊公留宴峴山亭，洛浦高歌五夜情。", "獨向柏臺爲老吏，可憐林木響餘聲。"]'),
('06e5cedf-c395-497f-82c2-030f029f9ad7','和李尚書命妓歌餞崔侍御','楊知至','唐','唐诗','tang','','[]','燕趙能歌有幾人，爲花回雪似含顰。',32,'全唐诗/poet.tang.31000.json','["燕趙能歌有幾人，爲花回雪似含顰。", "聲隨御史西歸去，誰伴文翁怨九春。"]'),
('0e786fff-7dcb-4ba8-92b6-fc847895c08d','覆落後呈同年','楊知至','唐','唐诗','tang','','[]','由來梁鴈與冥鴻，不合翩翩向碧空。',64,'全唐诗/poet.tang.31000.json','["由來梁鴈與冥鴻，不合翩翩向碧空。", "寒谷謾勞鄒氏律，長天獨遇宋都風。", "此時泣玉情雖異，他日銜環事亦同。", "二月春光正搖蕩，無因得醉杏園中。"]'),
('ae85d8a3-368c-45d3-8d80-87c5f4a55d5d','送韋覲謫潘州','李明遠','唐','唐诗','tang','','[]','北鳥飛不到，南人誰去遊。',48,'全唐诗/poet.tang.31000.json','["北鳥飛不到，南人誰去遊。", "天涯浮瘴水，嶺外向潘州。", "草木春秋暮，猨猱日夜愁。", "定知遷客淚，應只對君流。"]'),
('6c28eb6a-8b42-4620-b354-a1fdc0dfc40d','前望江麴令頌德','蕭縝','唐','唐诗','tang','','[]','政績雖殊道且同，無辭買石紀前功。',32,'全唐诗/poet.tang.31000.json','["政績雖殊道且同，無辭買石紀前功。", "誰論重德光青史，過里猶歌臥轍風。"]'),
('ccff905a-706e-4da7-8ba5-2ada7121f184','重陽東觀席上贈侍郎張固','盧順之','唐','唐诗','tang','','[]','渡江旌斾動魚龍，令節開筵上碧峰。',64,'全唐诗/poet.tang.31000.json','["渡江旌斾動魚龍，令節開筵上碧峰。", "翡翠巢低巖桂小，茱萸房濕露香濃。", "白雲郊外無塵事，黃菊筵中盡醉容。", "好是謝公高興處，夕陽歸騎出疎松。"]'),
('885563d2-7709-4281-9da7-ac3b0edfa006','責漢水辭','李善夷','唐','唐诗','tang','','[]','漢之廣兮，風波四起。',94,'全唐诗/poet.tang.31000.json','["漢之廣兮，風波四起。", "雖有風波，不如蹄涔之水。", "蹄涔之水，不爲下國而傾天子。", "漢之深兮，其隄莫量。", "雖云莫量，不如行潦之汪。", "行潦之汪，不爲下國而溺天王。", "漢之美者曰魴，吾雖饑不食其魴，恐污吾之饑腸。"]'),
('b78a8472-7a4d-44ac-9599-931876a69d40','大隄曲','李善夷','唐','唐诗','tang','','[]','酒旗相望大隄頭，隄下連牆隄上樓。',32,'全唐诗/poet.tang.31000.json','["酒旗相望大隄頭，隄下連牆隄上樓。", "日暮行人爭渡急，槳聲幽軋滿中流。"]'),
('9d30af02-1a4f-4dd6-9756-5b5a0568261f','金燈','盧溵','唐','唐诗','tang','','[]','疎莖秋擁翠，幽豔夕添紅。',48,'全唐诗/poet.tang.31000.json','["疎莖秋擁翠，幽豔夕添紅。", "有月長燈在，無煙燼火同。", "香濃初受露，勢庳不知風。", "應笑金臺上，先隨曉漏終。"]'),
('458e1358-a003-481f-9a53-a4836419dcfa','和李尚書命妓餞崔侍御','盧溵','唐','唐诗','tang','','[]','烏臺上客紫髯公，共捧天書靜境中。',32,'全唐诗/poet.tang.31000.json','["烏臺上客紫髯公，共捧天書靜境中。", "桃朵不辭歌白苧，耶溪暮雨起樵風。"]'),
('b0de6aed-cdba-4567-9b8a-e2195c315d55','對酒','趙牧','唐','唐诗','tang','','[]','雲翁耕扶桑，種黍養日烏。',144,'全唐诗/poet.tang.31000.json','["雲翁耕扶桑，種黍養日烏。", "手挼六十花甲子，循環落落如弄珠。", "長繩繫日未是愚，有翁臨鏡捋白鬚。", "飢魂弔骨吟古書，馮唐八十無高車。", "人生如雲在須臾，何乃自苦八尺軀。", "裂衣換酒且爲娛，勸君朝飲一瓢。", "夜飲一壺，杞天崩。", "雷騰騰，桀非堯是何足憑。", "桐君桂父豈勝我，醉裏白龍多上昇。", "菖蒲花開魚尾定，金丹始可延君命。"]'),
('dea5bed7-7241-475a-b705-57e485598f87','南歌子詞三首 一','裴諴','唐','唐诗','tang','','[]','不是廚中丳，爭知{炙火=肉}裏心。',29,'全唐诗/poet.tang.31000.json','["不是廚中丳，爭知{炙火=肉}裏心。", "井邊銀釧落，展轉恨還深。"]'),
('fac70547-dcd4-442d-bced-1b1fb21237fd','南歌子詞三首 二','裴諴','唐','唐诗','tang','','[]','不信長相憶，擡頭問取天。',24,'全唐诗/poet.tang.31000.json','["不信長相憶，擡頭問取天。", "風吹荷葉動，無夜不搖蓮。"]'),
('0496f2e5-4641-496a-bb5f-e29dce50ba64','南歌子詞三首 三','裴諴','唐','唐诗','tang','','[]','簳蠟爲紅燭，情知不自由。',24,'全唐诗/poet.tang.31000.json','["簳蠟爲紅燭，情知不自由。", "細絲斜結網，爭奈眼相鉤。"]'),
('e9a123ac-c724-442f-8686-05fc32ab767c','新添聲楊柳枝詞 一','裴諴','唐','唐诗','tang','','[]','思量大是惡姻緣，只得相看不得憐。',32,'全唐诗/poet.tang.31000.json','["思量大是惡姻緣，只得相看不得憐。", "願作琵琶槽那畔，得他長抱在胷前。"]'),
('b477a845-5886-4311-af1c-c80aad5e5852','新添聲楊柳枝詞 二','裴諴','唐','唐诗','tang','','[]','獨房蓮子沒人看，偷折蓮時命也𢬵。',32,'全唐诗/poet.tang.31000.json','["獨房蓮子沒人看，偷折蓮時命也𢬵。", "若有所由來借問，但道偷蓮是下官。"]'),
('49f4d48e-ce28-4470-a353-7e445cd9a76c','夏杪登越王樓臨涪江望雪山寄朝中知友','于興宗','唐','唐诗','tang','','[]','巴西西北樓，堪望亦堪愁。',48,'全唐诗/poet.tang.31000.json','["巴西西北樓，堪望亦堪愁。", "山亂江迴遠，川清樹欲秋。", "晴明中雪嶺，煙靄下漁舟。", "寫寄朝天客，知余恨獨遊。"]'),
('87a74baf-db59-478d-9017-4c45aa6b82d7','東陽涵碧亭','于興宗','唐','唐诗','tang','','[]','高低竹雜松，積翠復留風。',24,'全唐诗/poet.tang.31000.json','["高低竹雜松，積翠復留風。", "路劇陰溪裏，寒生暑氣中。"]'),
('ef9aa030-e68d-4f23-bac4-b11fb14b4fd3','奉酬綿州中丞以江山小圖遠垂賜及兼寄詩','李朋','唐','唐诗','tang','','[]','巴江與雪山，井邑共迴環。',48,'全唐诗/poet.tang.31000.json','["巴江與雪山，井邑共迴環。", "圖寫丹青內，分明煙靄間。", "移君名郡興，助我小齋閑。", "日想登臨處，高蹤不可攀。"]'),
('ad7b5a89-1483-4a68-896c-8f9858501779','奉酬于中丞登越王樓見寄之什','楊牢','唐','唐诗','tang','','[]','劒外書來日，驚忙自折封。',72,'全唐诗/poet.tang.31000.json','["劒外書來日，驚忙自折封。", "丹青得山水，強健慰心胸。", "事少勝諸郡，江迴見幾重。", "寧悲久作別，且似一相逢。", "詩合焚香詠，愁應賴酒濃。", "庾樓寒更憶，腸斷雪千峰。"]'),
('6acc507d-b716-4f23-ba3b-c4747d82769d','贈舍弟','楊牢','唐','唐诗','tang','','[]','秦雲蜀浪兩堪愁，爾養晨昏我遠遊。',64,'全唐诗/poet.tang.31000.json','["秦雲蜀浪兩堪愁，爾養晨昏我遠遊。", "千里客心難寄夢，兩行鄉淚爲君流。", "早驅風雨知龍聖，餓食魚鰕覺虎羞。", "袖裏鏌鋣光似水，丈夫不合等閑休。"]'),
('83611bbb-8060-4599-b986-eddb78bd50cd','句','楊牢','唐','唐诗','tang','','[]','蝦𢋙欲喫月，保讓常敎圓。',52,'全唐诗/poet.tang.31000.json','["蝦𢋙欲喫月，保讓常敎圓。", "心明外不察，月向懷中圓。", "羅幃若不卷，誰道中無人。", "魁形下方天頂亞，二十四寸窗中月。"]'),
('b929881e-5b10-4218-917b-3908b654adf7','和綿州于中丞登越王樓見寄','李續','唐','唐诗','tang','','[]','早年登此樓，退想不勝愁。',48,'全唐诗/poet.tang.31000.json','["早年登此樓，退想不勝愁。", "地遠二千里，時將四十秋。", "邅迍多失路，華皓任虛舟。", "詩酒雖堪使，何因得共遊。"]'),
('6288ee91-8336-42d4-baf8-da52e9af2a65','和綿州于中丞登越王樓作','李汶濡','唐','唐诗','tang','','[]','珍重巴西守，殷勤寄遠情。',48,'全唐诗/poet.tang.31000.json','["珍重巴西守，殷勤寄遠情。", "劒峰當戶碧，詩韻滿樓清。", "日照涪川闊，煙籠雪嶠明。", "徵黃看即及，莫歎滯江城。"]'),
('394a5ba3-c0e5-4237-b403-ca61997714bc','和于中丞夏杪登越王樓望雪山見寄','田章','唐','唐诗','tang','','[]','志乖多感物，臨眺更增愁。',48,'全唐诗/poet.tang.31000.json','["志乖多感物，臨眺更增愁。", "暑候雖云夏，江聲已似秋。", "雪遙難辨木，村近好維舟。", "莫恨歸朝晚，朝簪擬勝遊。"]'),
('2505789c-8f1b-4687-b8c7-5b7eebc6f1c9','和綿州于中丞登越王樓作','薛蒙','唐','唐诗','tang','','[]','左綿江上樓，五馬此銷愁。',48,'全唐诗/poet.tang.31000.json','["左綿江上樓，五馬此銷愁。", "暑退千山雪，風來萬木秋。", "邅迴猶刺郡，繫滯似維舟。", "即有徵黃日，名川莫厭遊。"]'),
('60371035-d60b-4644-b11d-175b8156d546','和綿州于中丞登越王樓作','李鄴','唐','唐诗','tang','','[]','長聽巴西事，看圖勝所聞。',48,'全唐诗/poet.tang.31000.json','["長聽巴西事，看圖勝所聞。", "江樓明返照，雪嶺亂晴雲。", "景象詩情在，幽奇筆跡分。", "使君徒說好，不祗怨離羣。"]'),
('7a4622eb-c07a-4c0e-9e33-1abe592615d0','和綿州于中丞登越王樓作二首 一','于瓌','唐','唐诗','tang','','[]','樓因藩邸號，川勢似依樓。',48,'全唐诗/poet.tang.31000.json','["樓因藩邸號，川勢似依樓。", "顯敞含清暑，嵐光入素秋。", "山宜姑射貌，江泛李膺舟。", "郢曲思朋執，輕紗畫勝遊。"]'),
('18bb6383-5f0f-4cee-a93e-8997bed2663a','和綿州于中丞登越王樓作二首 二','于瓌','唐','唐诗','tang','','[]','極目郡城樓，浮雲拂檻愁。',48,'全唐诗/poet.tang.31000.json','["極目郡城樓，浮雲拂檻愁。", "政成多暇日，詩思動先秋。", "遠霽千巖雪，隨波一葉舟。", "昔曾窺粉繪，今願許陪遊。"]'),
('371766bd-0e6d-40ed-ac46-91eb42ae44a8','和于中丞登越王樓','王嚴','唐','唐诗','tang','','[]','雉堞臨朱檻，登茲便散愁。',50,'全唐诗/poet.tang.31000.json','["雉堞臨朱檻，登茲便散愁。", "蟬聲怨炎夏，山色報新秋。", "江轉穿雲樹，心閑隨葉舟。", "仲[宣]徒有歎，謝守幾追遊。"]'),
('baccb10c-17de-41e1-9805-5e1dae11b8bf','題越王樓寄獻中丞使君','劉暌','唐','唐诗','tang','','[]','朱軒迥壓碧煙州，昔歲賢王是勝遊。',64,'全唐诗/poet.tang.31000.json','["朱軒迥壓碧煙州，昔歲賢王是勝遊。", "山簇劒峰朝闕遠，水如巴字遶城流。", "人間物象分千里，天上笙歌醉五侯。", "今日登臨無限意，同霑惠化自銷愁。"]'),
('45b5ee1e-f6da-4f8d-84ab-19241ccb1631','秋日登越王樓獻于中丞','李渥','唐','唐诗','tang','','[]','越王曾牧劒南州，因向城隅建此樓。',64,'全唐诗/poet.tang.31000.json','["越王曾牧劒南州，因向城隅建此樓。", "橫玉遠開千嶠雪，暗雷下聽一江流。", "畫簷先弄朝陽色，朱檻低臨衆木秋。", "徒學仲宣聊四望，且將詞賦好依劉。"]'),
('eac7b2d1-e127-439e-a44d-fe34bab71429','洋州于中丞頃牧左綿題詩越王樓上朝賢繼和輙課四韻','劉璐','唐','唐诗','tang','','[]','隔政代君侯，多慚跡令猷。',48,'全唐诗/poet.tang.31000.json','["隔政代君侯，多慚跡令猷。", "山光來戶牖，江鳥滿汀洲。", "雅韻徵朝客，清詞寫郡樓。", "至今謠未已，注意在洋州。"]'),
('44c30f00-d622-4664-8b24-6510310fd1ad','和于中丞登越王樓作','盧栯','唐','唐诗','tang','','[]','圖[畫]越王樓，開緘慰別愁。',50,'全唐诗/poet.tang.31000.json','["圖[畫]越王樓，開緘慰別愁。", "山光涵雪冷，水色帶江秋。", "雲島孤征鴈，煙帆一葉舟。", "嚮風舒霽景，如伴謝公遊。"]'),
('cf3c1df5-f8f0-4d09-a062-d81369bc6f54','飛鴻響遠音','李體仁','唐','唐诗','tang','','[]','漠漠微霜夕，翩翩出渚鴻。',72,'全唐诗/poet.tang.31000.json','["漠漠微霜夕，翩翩出渚鴻。", "清聲流逈野，高韻入寥空。", "舊質經寒塞，殘音響遠風。", "縈雲猶類網，避月尚疑弓。", "弱羽雖能振，丹霄竟未通。", "欲知多怨思，聽取暮煙中。"]'),
('db11089a-c221-4b07-b5d6-d37a299c8bea','春愁','韓琮','唐','唐诗','tang','','[]','金烏長飛玉兔走，青鬢長青古無有。',64,'全唐诗/poet.tang.31000.json','["金烏長飛玉兔走，青鬢長青古無有。", "秦娥十六語如弦，未解貪花惜楊柳。", "吳魚嶺鴈無消息，水誓蘭情別來久。", "勸君年少莫遊春，煖風遲日濃於酒。"]'),
('02fc56ef-7e3e-44d2-8251-eeb352170cdc','牡丹','韓琮','唐','唐诗','tang','','[]','殘花何處藏，盡在牡丹房。',48,'全唐诗/poet.tang.31000.json','["殘花何處藏，盡在牡丹房。", "嫩蘂包金粉，重葩結繡囊。", "雲凝巫峽夢，簾閉景陽粧。", "應恨年華促，遲遲待日長。"]'),
('0923419a-0eef-4cb1-84fd-31374c32e8a0','興平縣野中得落星石移置縣齋','韓琮','唐','唐诗','tang','','[]','的的墮芊蒼，茫茫不記年。',48,'全唐诗/poet.tang.31000.json','["的的墮芊蒼，茫茫不記年。", "幾逢疑虎將，應逐犯牛仙。", "擇地依蘭畹，題詩間錦錢。", "何時成五色，却上女媧天。"]'),
('96afd27a-b059-4d11-9430-d3bf951080a3','題商山店','韓琮','唐','唐诗','tang','','[]','商山驛路幾經過，未到仙娥見謝娥。',64,'全唐诗/poet.tang.31000.json','["商山驛路幾經過，未到仙娥見謝娥。", "紅錦機頭拋皓腕，綠雲鬟下送橫波。", "佯嗔阿母留賓客，暗爲王孫換綺羅。", "碧澗門前一條水，豈知平地有天河。"]'),
('f0a5bff1-a091-44d7-8a36-2248b7f079c8','風','韓琮','唐','唐诗','tang','','[]','競持飄忽意何窮，爲盛爲衰半不同。',64,'全唐诗/poet.tang.31000.json','["競持飄忽意何窮，爲盛爲衰半不同。", "偃草喜逢新雨後，鳴條愁聽曉霜中。", "涼飛玉管來秦甸，暗褭花枝入楚宮。", "莫見東風便無定，滿帆還有濟川功。"]'),
('a9ecbe5e-0a4f-47f0-8d7f-cf5e09269c76','雲','韓琮','唐','唐诗','tang','','[]','深惹離情靄落暉，如車如蓋早依依。',64,'全唐诗/poet.tang.31000.json','["深惹離情靄落暉，如車如蓋早依依。", "山頭觸石應常在，天際從龍自不歸。", "莫向隙窗籠夜月，好來仙洞濕行衣。", "春風淡蕩無心後，見說襄王夢亦稀。"]'),
('b3816727-d65b-4d4d-aa2e-987c3963759a','露','韓琮','唐','唐诗','tang','','[]','長隨聖澤墮堯天，濯遍幽蘭葉葉鮮。',64,'全唐诗/poet.tang.31000.json','["長隨聖澤墮堯天，濯遍幽蘭葉葉鮮。", "纔喜輕塵銷陌上，已愁新月到堦前。", "文騰要地成非久，珠綴秋荷偶得圓。", "幾處花枝抱離恨，曉風殘月正澘然。"]'),
('a2a24c7b-8dd9-48e1-af11-c55f62911741','霞','韓琮','唐','唐诗','tang','','[]','應是行雲未擬歸，變成春態媚晴暉。',64,'全唐诗/poet.tang.31000.json','["應是行雲未擬歸，變成春態媚晴暉。", "深如綺色斜分閣，碎似花光散滿衣。", "天際欲銷重慘淡，鏡中閑照正依稀。", "曉來何處低臨水，無限鴛鴦妬不飛。"]'),
('b0411d3f-e7de-4f9f-b85a-3f579009a09b','潁亭','韓琮','唐','唐诗','tang','','[]','潁上新亭瞰一川，幾重舊址敞幽關。',64,'全唐诗/poet.tang.31000.json','["潁上新亭瞰一川，幾重舊址敞幽關。", "寒聲北下當軒水，翠影西來撲檻山。", "遠目靜隨孤鶴去，高情常共白雲閑。", "知君久負巢由志，早晚相忘寂寞間。"]'),
('38210d93-9a4a-41fb-a79c-d7ed0383618b','詠馬','韓琮','唐','唐诗','tang','','[]','曾經伯樂識長鳴，不似龍行不敢行。',64,'全唐诗/poet.tang.31000.json','["曾經伯樂識長鳴，不似龍行不敢行。", "金埒未登嘶若是，鹽車猶駕瘦何驚。", "難逢王濟知音癖，欲就燕昭買駿名。", "早晚飛黃引同皂，碧雲天上作鸞鳴。"]'),
('e34d5d1c-c3bb-43a2-906b-48116b8cdf28','題圭峰下長孫家林亭','韓琮','唐','唐诗','tang','','[]','趙國林亭二百年，綠苔如毯葛如煙。',64,'全唐诗/poet.tang.31000.json','["趙國林亭二百年，綠苔如毯葛如煙。", "閑期竹色搖霜看，醉惜松聲枕月眠。", "出樹圭峰寒壓坐，入籬沙瀨碧流天。", "明知富貴非身物，莫爲金章墮地仙。"]'),
('416bb99b-e2b4-4c5b-828f-4c50907ee901','牡丹','韓琮','唐','唐诗','tang','','[]','桃時杏日不爭濃，葉帳陰成始放紅。',64,'全唐诗/poet.tang.31000.json','["桃時杏日不爭濃，葉帳陰成始放紅。", "曉豔遠分金掌露，暮香深惹玉堂風。", "名移蘭杜千年後，貴擅笙歌百醉中。", "如夢如仙忽零落，暮霞何處綠屏空。"]'),
('8dd828ea-c32d-4734-87c3-175f3174f868','雨','韓琮','唐','唐诗','tang','','[]','陰雲拂地散絲輕，長得爲霖濟物名。',64,'全唐诗/poet.tang.31000.json','["陰雲拂地散絲輕，長得爲霖濟物名。", "夜浦漲歸天塹闊，春風灑入御溝平。", "軒車幾處歸頻濕，羅綺何人去欲生。", "不及流他荷葉上，似珠無數轉分明。"]'),
('f91be4f6-cbc2-4da5-8f3f-4569a4622121','京西即事','韓琮','唐','唐诗','tang','','[]','秋草河蘭起陣雲，涼州唯向管弦聞。',64,'全唐诗/poet.tang.31000.json','["秋草河蘭起陣雲，涼州唯向管弦聞。", "豺狼毳幕三千帳，貔虎金戈十萬軍。", "候騎北來驚有說，戍樓西望悔爲文。", "昭陽亦待平安火，誰握旌旗不見勳。"]'),
('f4ea9961-4b3b-4659-9430-c1c38eb68858','公子行','韓琮','唐','唐诗','tang','','[]','紫袖長衫色，銀蟬半臂花。',96,'全唐诗/poet.tang.31000.json','["紫袖長衫色，銀蟬半臂花。", "帶裝盤水玉，鞍繡坐雲霞。", "別殿承恩澤，飛龍賜渥洼。", "控羅青褭轡，鏤象碧熏葩。", "意氣傾歌舞，闌珊走鈿車。", "袖障雲縹緲，釵轉鳳欹斜。", "珠卷迎歸箔，雕籠晃醉紗。", "唯無難夜日，不得似仙家。"]'),
('10a8cd10-771d-4a0f-b491-7f0c3761ea16','秋晚信州推院親友或責無書即事寄答','韓琮','唐','唐诗','tang','','[]','官信安仁拙，書非叔夜慵。',144,'全唐诗/poet.tang.31000.json','["官信安仁拙，書非叔夜慵。", "謬馳驄馬傳，難附鯉魚封。", "萬里勞何補，千年運忝逢。", "不量橫草力，虛慕入雲蹤。", "潔水空澄鑑，持鉛亦礪鋒。", "月寒深夜桂，霜凜近秋松。", "憲摘無逃魏，冤申得夢馮。", "問貍將挾虎，殲蠆敢虞蜂。", "商吹移砧調，春華改鏡容。", "歸期方畹積，愁思暮山重。", "仙鼠猶驚燕，莎雞欲變蛩。", "唯應碧湘浦，雲落及芙蓉。"]'),
('7f536116-335a-487f-b456-d7d129bb0b5f','晚春江晴寄友人','韓琮','唐','唐诗','tang','','["\u6000\u4eba", "\u601d\u4e61", "\u5199\u666f"]','晚日低霞綺，晴山遠畫眉。',24,'全唐诗/poet.tang.31000.json','["晚日低霞綺，晴山遠畫眉。", "春青河畔草，不是望鄉時。"]'),
('277b46a7-7c5c-4f88-a293-b9279e642c61','涼州詞','韓琮','唐','唐诗','tang','','[]','樹發花如錦，鶯啼柳若絲。',24,'全唐诗/poet.tang.31000.json','["樹發花如錦，鶯啼柳若絲。", "更游歡宴地，悲見別離時。"]'),
('fb8cc45e-84e2-4bc9-8e14-a1f5d87d69c6','莫春滻水送別','韓琮','唐','唐诗','tang','','["\u9001\u522b", "\u66ae\u6625"]','綠暗紅稀出鳳城，暮雲樓閣古今情。',32,'全唐诗/poet.tang.31000.json','["綠暗紅稀出鳳城，暮雲樓閣古今情。", "行人莫聽宮前水，流盡年光是此聲。"]'),
('d3815943-d2d4-481b-bf06-b45042a28f6b','駱谷晚望','韓琮','唐','唐诗','tang','','[]','秦川如畫渭如絲，去國還家一望時。',32,'全唐诗/poet.tang.31000.json','["秦川如畫渭如絲，去國還家一望時。", "公子王孫莫來好，嶺花多是斷腸枝。"]'),
('99a3ed20-0274-4da6-aefd-aaa87c432436','二月二日遊洛源','韓琮','唐','唐诗','tang','','[]','舊苑新晴草似苔，人還香在踏青迴。',32,'全唐诗/poet.tang.31000.json','["舊苑新晴草似苔，人還香在踏青迴。", "今朝此地成惆悵，已後逢春更莫來。"]'),
('bab10b33-b489-4d53-8d64-573557467a96','柳','韓琮','唐','唐诗','tang','','[]','折柳歌中得翠條，遠移金殿種青霄。',32,'全唐诗/poet.tang.31000.json','["折柳歌中得翠條，遠移金殿種青霄。", "上陽宮女含聲送，不忿先歸舞細腰。"]'),
('a9fec98a-86b3-44aa-b82b-5d35f02506ec','楊柳枝','韓琮','唐','唐诗','tang','','[]','梁苑隋堤事已空，萬條猶舞舊春風。',32,'全唐诗/poet.tang.31000.json','["梁苑隋堤事已空，萬條猶舞舊春風。", "那堪更想千年後，誰見楊花入漢宮。"]'),
('854a38ee-fbe5-4a2d-88de-b2b288c0d828','楊柳枝詞','韓琮','唐','唐诗','tang','','[]','枝鬬纖腰葉鬬眉，春來無處不如絲。',32,'全唐诗/poet.tang.31000.json','["枝鬬纖腰葉鬬眉，春來無處不如絲。", "霸陵原上多離別，少有長條拂地垂。"]'),
('8a5633e7-ea63-49e4-9011-025e0ab77c5d','和襄陽徐相公商賀徐副使加章綬','王傳','唐','唐诗','tang','','[]','朱紫聯輝照日新，芳菲全屬斷金人。',64,'全唐诗/poet.tang.31000.json','["朱紫聯輝照日新，芳菲全屬斷金人。", "華筵重處宗盟地，白雪飛時郢曲春。", "仙府色饒攀桂侶，蓮花光讓握蘭身。", "自憐亦是膺門客，吟想恩榮氣益振。"]'),
('97f2abd5-6481-4a5d-b6d7-c6953e1184da','和李尚書命妓餞崔侍御','盧鄴','唐','唐诗','tang','','[]','何郎載酒別賢侯，更吐歌珠宴庾樓。',32,'全唐诗/poet.tang.31000.json','["何郎載酒別賢侯，更吐歌珠宴庾樓。", "莫道江南不同醉，即陪舟檝上京游。"]'),
('bfb41112-dbe6-4161-abd4-bb1d1714f6fa','松','陸肱','唐','唐诗','tang','','[]','雪霜知勁質，今古占嘉名。',48,'全唐诗/poet.tang.31000.json','["雪霜知勁質，今古占嘉名。", "斷砌盤根遠，疎林偃蓋清。", "鶴棲何代色，僧老四時聲。", "鬱鬱心彌久，煙高萬井生。"]'),
('7035cfc5-c312-43ed-9ac3-18aaad4e5753','贈王福娘','崔澹','唐','唐诗','tang','','[]','怪得清風送異香，娉婷仙子曳霓裳。',32,'全唐诗/poet.tang.31000.json','["怪得清風送異香，娉婷仙子曳霓裳。", "惟應錯認偷桃客，曼倩曾爲漢侍郎。"]'),
('48e170f1-e03b-48c7-85cd-7cfb4691f678','荅問讀書居','莫宣卿','唐','唐诗','tang','','[]','書屋倚麒麟，不同牛馬路。',48,'全唐诗/poet.tang.31000.json','["書屋倚麒麟，不同牛馬路。", "牀頭萬卷書，溪上五龍渡。", "井汲冽寒泉，桂花香玉露。", "茅簷無外物，只見青雲護。"]'),
('840f7753-2fba-403a-8b4b-af57e38ec1b0','百官乘月早朝聽殘漏','莫宣卿','唐','唐诗','tang','','[]','建禮儼朝冠，重門耿夜闌。',72,'全唐诗/poet.tang.31000.json','["建禮儼朝冠，重門耿夜闌。", "碧空蟾魄度，清禁漏聲殘。", "候曉車輿合，凌霜劍佩寒。", "星河猶皎皎，銀箭尚珊珊。", "杳靄祥光起，霏微瑞氣攢。", "忻逢聖明代，長願接鵷鸞。"]'),
('f3b83061-2908-40ac-bdb9-8a58df4afc03','賦得水懷珠','莫宣卿','唐','唐诗','tang','','[]','長川含媚色，波底孕靈珠。',72,'全唐诗/poet.tang.31000.json','["長川含媚色，波底孕靈珠。", "素魄生蘋末，圓規照水隅。", "淪漣冰彩動，蕩漾瑞光鋪。", "迥夜星同貫，清秋岸不枯。", "江妃思在掌，海客亦忘軀。", "合浦當還日，恩威信已敷。"]'),
('594a31ff-f917-43fd-9459-ef50f021cb49','句','莫宣卿','唐','唐诗','tang','','[]','我本南山鳳，豈同凡鳥羣。',12,'全唐诗/poet.tang.31000.json','["我本南山鳳，豈同凡鳥羣。"]'),
('20db53d8-dd6b-4cee-806f-e05c4d5d08d4','和李尚書命妓餞崔侍御','封彥卿','唐','唐诗','tang','','[]','蓮府纔爲綠水賓，忽乘驄馬入咸秦。',34,'全唐诗/poet.tang.31000.json','["蓮府纔爲綠水賓，忽乘驄馬入咸秦。", "爲君唱作西[河]調，日暮偏傷去住人。"]'),
('b5780704-16c4-49f5-ad54-77d291382d63','一','封彥卿','唐','唐诗','tang','','[]','湘川狺狺兮俗獷且佷，利殺業偷兮吏莫之馴。',38,'全唐诗/poet.tang.31000.json','["湘川狺狺兮俗獷且佷，利殺業偷兮吏莫之馴。", "繄釋氏兮易暴使仁，釋何在兮釋在斯文。"]'),
('9b595f2d-e885-4dc2-ba20-ff39908a3740','二','封彥卿','唐','唐诗','tang','','[]','湘水滔滔兮四望何依，猨狖騰拏兮雲樹飛飛。',36,'全唐诗/poet.tang.31000.json','["湘水滔滔兮四望何依，猨狖騰拏兮雲樹飛飛。", "月沈浦兮煙暝山，檣席卷兮櫓牀閑。"]'),
('e1d08dbc-b71f-47b2-9128-aeb328bade5e','三','封彥卿','唐','唐诗','tang','','[]','湘川超忽兮落日晼晼，松覆秋亭兮蘭被春苑。',37,'全唐诗/poet.tang.31000.json','["湘川超忽兮落日晼晼，松覆秋亭兮蘭被春苑。", "上人去兮幾千里，何日同遊兮湘川水。"]'),
('973f08db-e7bb-401d-a3f9-8c71ebea21cf','和柯古窮居苦日喜雨','韋蟾','唐','唐诗','tang','','[]','貞機澹少思，雅尚防多僻。',120,'全唐诗/poet.tang.31000.json','["貞機澹少思，雅尚防多僻。", "攬葛猶不畏，勞形同處瘠。", "頭焦詎是焚，背汗寧關炙。", "方欣見潤礎，那虞悲鑠石。", "道與古人期，情難物外適。", "幾懷朱邸綬，頗曠金門籍。", "清奧已蕭蕭，陳柯將槭槭。", "玉律詩調正，瓊巵酒腸窄。", "衣桁襲中單，浴牀拋下綌。", "黎侯寓於衛，六義非凡格。"]'),
('81d913a7-6d74-4e44-8a9c-c481251861c9','岳麓道林寺','韋蟾','唐','唐诗','tang','','[]','石門逈接蒼梧野，愁色陰深二妃寡。',160,'全唐诗/poet.tang.31000.json','["石門逈接蒼梧野，愁色陰深二妃寡。", "廣殿崔嵬萬壑間，長廊詰曲千巖下。", "靜聽林飛念佛鳥，細看壁畫馱經馬。", "暖日斜明螮蝀梁，濕烟散冪鴛鴦瓦。", "北方部落檀香塑，西國文書貝葉寫。", "壞欄迸竹醉好題，窄路垂藤困堪把。", "沈裴筆力鬬雄壯，宋杜詞源兩風雅。", "他方居士來施齋，彼岸上人投結夏。", "悲我未離擾擾徒，勸我休學悠悠者。", "何時得與劉遺民，同入東林遠公社。"]'),
('0e212fa0-d4b7-417f-bc85-448ec72499d3','上元三首 一','韋蟾','唐','唐诗','tang','','[]','新正圓月夜，尤重看燈時。',48,'全唐诗/poet.tang.31000.json','["新正圓月夜，尤重看燈時。", "累塔嫌沙細，成文訝筆遲。", "歸牛疑燧落，過鴈悞書遲。", "生惜蘭膏燼，還爲隔歲期。"]'),
('d21330b6-b2fe-4c32-b757-cb6c0351ad43','上元三首 二','韋蟾','唐','唐诗','tang','','[]','舉燭光纔起，揮毫勢競分。',48,'全唐诗/poet.tang.31000.json','["舉燭光纔起，揮毫勢競分。", "點時驚墜石，挑處接崩雲。", "辭異秦丞相，銘非竇冠軍。", "唯愁殘焰落，逢玉亦俱焚。"]'),
('a276029b-e627-4297-897e-49409009d997','上元三首 三','韋蟾','唐','唐诗','tang','','[]','多寶神光動，生金瑞色浮。',48,'全唐诗/poet.tang.31000.json','["多寶神光動，生金瑞色浮。", "照人低入郭，伴月夜當樓。", "熏穴應無取，焚林固有求。", "夜闌陪玉帳，不見九枝留。"]'),
('8cd7ca9a-96c2-4aad-a410-b848a6859bdb','梅','韋蟾','唐','唐诗','tang','','[]','高樹臨溪豔，低枝隔竹繁。',48,'全唐诗/poet.tang.31000.json','["高樹臨溪豔，低枝隔竹繁。", "何須是桃李，然後欲忘言。", "擬折魂先斷，須看眼更昏。", "誰知南陌草，却解望王孫。"]'),
('6758c58e-ac5a-4529-810a-06e04b49de95','送盧潘尚書之靈武','韋蟾','唐','唐诗','tang','','[]','賀蘭山下果園成，塞北江南舊有名。',64,'全唐诗/poet.tang.31000.json','["賀蘭山下果園成，塞北江南舊有名。", "水木萬家朱戶暗，弓刀千隊鐵衣鳴。", "心源落落堪爲將，膽氣堂堂合用兵。", "却使六番諸子弟，馬前不信是書生。"]'),
('e2e3aa67-2e6c-4fa1-86ba-b8b755051dc6','題僧壁','韋蟾','唐','唐诗','tang','','[]','一竹橫簷挂淨巾，竈無煙火地無塵。',32,'全唐诗/poet.tang.31000.json','["一竹橫簷挂淨巾，竈無煙火地無塵。", "剃頭未必知心法，要且閑於名利人。"]'),
('a078f0f6-b0fb-4c20-aafd-48b239bbf0c2','贈商山僧','韋蟾','唐','唐诗','tang','','[]','商嶺東西路欲分，兩間茅屋一溪雲。',32,'全唐诗/poet.tang.31000.json','["商嶺東西路欲分，兩間茅屋一溪雲。", "師言耳重知師意，人是人非不欲聞。"]'),
('f2c54bfc-5a09-46e3-8c12-4662af9aa973','長樂驛謔李湯給事題名','韋蟾','唐','唐诗','tang','','[]','渭水秦川拂眼明，希仁何事寡詩情。',32,'全唐诗/poet.tang.31000.json','["渭水秦川拂眼明，希仁何事寡詩情。", "只應學得虞姬壻，書字纔能記姓名。"]'),
('c01022d6-b4c9-4308-84ce-1606a267e0ea','句','韋蟾','唐','唐诗','tang','','[]','爭揮鉤弋手，競聳踏搖身。',24,'全唐诗/poet.tang.31000.json','["爭揮鉤弋手，競聳踏搖身。", "傷頰詎關舞，捧心非効嚬。"]'),
('af68f29f-064e-49a1-9854-dcd6e849efc0','賦得壽星見','盧渥','唐','唐诗','tang','','[]','玄象今何應，時和政亦平。',72,'全唐诗/poet.tang.31000.json','["玄象今何應，時和政亦平。", "祥爲一人壽，色映九霄明。", "皎潔垂銀漢，光芒近斗城。", "含規同月滿，表瑞得天清。", "甘露盈條降，非煙向日生。", "無如此嘉祉，率土荷秋成。"]'),
('c08330b2-62f4-4919-bdde-c51106d045fe','題嘉祥驛','盧渥','唐','唐诗','tang','','[]','交親榮餞洛城空，秉鉞戎裝上將同。',64,'全唐诗/poet.tang.31000.json','["交親榮餞洛城空，秉鉞戎裝上將同。", "星使自天丹詔下，雕鞍照地數程中。", "馬嘶靜谷聲偏響，斾映晴山色更紅。", "到後定知人易化，滿街棠樹有遺風。"]'),
('b4feb429-ed11-403f-aaa5-34085cbcbd2e','九華山','郭夔','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','巖翠凌雲出迥然，岧嶤萬丈倚秋天。',64,'全唐诗/poet.tang.31000.json','["巖翠凌雲出迥然，岧嶤萬丈倚秋天。", "暮風飄送當軒色，曉霧斜飛入檻煙。", "簾捲倚屏雙影聚，鏡開朱戶九條懸。", "畫圖何必家家有，自有畫圖來目前。"]'),
('4ab815e6-0b0a-4999-a02f-102decdfccf2','送莫仲節狀元歸省','柳珪','唐','唐诗','tang','','[]','青驄聚送謫仙人，南國榮親不及君。',64,'全唐诗/poet.tang.31000.json','["青驄聚送謫仙人，南國榮親不及君。", "椰子味從今日近，鷓鴣聲向舊山聞。", "孤猨夜呌三湘月，匹馬時侵五嶺雲。", "想到故鄉應臘過，藥欄猶有異花薰。"]'),
('e789504b-5f99-4982-b9d4-c651658e8995','津陽門詩','鄭嵎','唐','唐诗','tang','','[]','津陽門北臨通逵，雪風獵獵飄酒旗。',384,'全唐诗/poet.tang.31000.json','["津陽門北臨通逵，雪風獵獵飄酒旗。", "泥寒欵段蹶不進，疲童退問前何爲。", "酒家顧客催解裝，案前羅列樽與巵。", "青錢瑣屑安足數，白醪軟美甘如飴。", "開壚引滿相獻酬，枯腸渴肺忘朝飢。", "愁憂似見出門去，漸覺春色入四肢。", "主翁移客挑華燈，雙肩隱膝烏帽欹。", "笑云鮐老不爲禮，飄蕭雪鬢雙垂頤。", "問余何往凌寒曦，顧翁枯朽郎豈知。", "翁曾豪盛客不見，我自爲君陳昔時。", "時平親衛號羽林，我纔十五爲孤兒。", "射熊搏虎衆莫敵，彎弧出入隨佽飛。", "此時初創觀風樓，簷高百尺堆華榱。", "樓南更起鬬雞殿，晨光出影相參差。", "其年十月移禁仗，山下櫛比羅百司。", "朝元閣成老君見，會昌縣以新豐移。", "幽州曉進供奉馬，玉珂寶勒黃金羈。", "五王扈駕夾城路，傳聲校獵渭水湄。", "羽林六軍各出射，籠山絡野張罝維。", "彫弓繡韣不知數，翻身滅沒皆蛾眉。", "赤鷹黃鶻雲中來，妖狐狡兔無所依。", "人煩馬殆禽獸盡，百里腥膻禾黍稀。", "暖山度臘東風微，宮娃賜浴長湯池。", "刻成玉蓮噴香液，漱迴煙浪深逶迤。"]'),
('6888771c-0035-44d4-a643-a63de93cb9f5','春日即事','崔櫓','唐','唐诗','tang','','[]','一百五日又欲來，梨花梅花參差開。',64,'全唐诗/poet.tang.31000.json','["一百五日又欲來，梨花梅花參差開。", "行人自笑不歸去，瘦馬獨吟真可哀。", "杏酪漸香鄰舍粥，榆煙將變舊爐灰。", "畫橋春煖清歌夜，肯信愁腸日九迴。"]'),
('2a0b1ac1-e3f6-4ab7-8b7d-626e5efbbdd1','春晚岳陽言懷二首 一','崔櫓','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','煙花零落過清明，異國光陰老客情。',64,'全唐诗/poet.tang.31000.json','["煙花零落過清明，異國光陰老客情。", "雲夢夕陽愁裏色，洞庭春浪坐來聲。", "天邊一與舊山別，江上幾看芳草生。", "獨倚闌干意難寫，暮笳嗚咽調孤城。"]'),
('2611bd4a-0cca-46d2-8fed-25809965bda6','春晚岳陽言懷二首 二','崔櫓','唐','唐诗','tang','','[]','翠煙如鈿柳如環，晴倚南樓獨看山。',64,'全唐诗/poet.tang.31000.json','["翠煙如鈿柳如環，晴倚南樓獨看山。", "江國草花三月暮，帝城塵夢一年間。", "虛舟尚歎縈難解，飛鳥空慚倦未還。", "何似不羈詹父伴，睡煙歌月老潺潺。"]'),
('33ea037e-2b8c-41fa-8cc4-64c630bff399','過蠻溪渡','崔櫓','唐','唐诗','tang','','[]','綠楊如髮雨如煙，立馬危橋獨喚船。',64,'全唐诗/poet.tang.31000.json','["綠楊如髮雨如煙，立馬危橋獨喚船。", "山口斷雲迷舊路，渡頭芳草憶前年。", "身隨遠道徒悲梗，詩賣明時不直錢。", "歸去楚臺還有計，釣船春雨日高眠。"]'),
('e992683a-6cc0-4e22-8f48-9125879db9dd','岸梅','崔櫓','唐','唐诗','tang','','[]','含情含怨一枝枝，斜壓漁家短短籬。',64,'全唐诗/poet.tang.31000.json','["含情含怨一枝枝，斜壓漁家短短籬。", "惹袖尚餘香半日，向人如訴雨多時。", "初開偏稱雕梁畫，未落先愁玉笛吹。", "行客見來無去意，解帆煙浦爲題詩。"]'),
('ee8dab2b-89ba-4d6c-936f-b044dde69523','重陽日次荆南路經武寧驛','崔櫓','唐','唐诗','tang','','[]','茱萸冷吹溪口香，菊花倒遶山脚黃。',64,'全唐诗/poet.tang.31000.json','["茱萸冷吹溪口香，菊花倒遶山脚黃。", "家山去此強百里，弟妹待我醉重陽。", "風健旱鴻高曉景，露清圓碧照秋光。", "莫看時節年年好，暗送搔頭逐手霜。"]'),
('1374cea5-5c8b-4afc-8d09-edf0b2f78e81','述懷','崔櫓','唐','唐诗','tang','','[]','白首成何事，無歡可替悲。',24,'全唐诗/poet.tang.31000.json','["白首成何事，無歡可替悲。", "空餘酒中興，猶似少年時。"]'),
('8d649c2c-c094-491a-90be-53512bd5ef1d','三月晦日送客','崔櫓','唐','唐诗','tang','','[]','野酌亂無巡，送君兼送春。',24,'全唐诗/poet.tang.31000.json','["野酌亂無巡，送君兼送春。", "明年春色至，莫作未歸人。"]'),
('a9af6d93-8514-4d85-b8c8-0ac656e318db','華清宮三首 一','崔櫓','唐','唐诗','tang','','[]','草遮回蹬絕鳴鑾，雲樹深深碧殿寒。',32,'全唐诗/poet.tang.31000.json','["草遮回蹬絕鳴鑾，雲樹深深碧殿寒。", "明月自來還自去，更無人倚玉欄干。"]'),
('66930c4d-ac8b-40a3-8cd0-3b62393621f1','華清宮三首 二','崔櫓','唐','唐诗','tang','','[]','障掩金雞蓄禍機，翠華西拂蜀雲飛。',32,'全唐诗/poet.tang.31000.json','["障掩金雞蓄禍機，翠華西拂蜀雲飛。", "珠簾一閉朝元閣，不見人歸見燕歸。"]'),
('b55aaea9-b95c-4135-b978-1f1927ce1cc0','華清宮三首 三','崔櫓','唐','唐诗','tang','','[]','門橫金鎖悄無人，落日秋聲渭水濱。',32,'全唐诗/poet.tang.31000.json','["門橫金鎖悄無人，落日秋聲渭水濱。", "紅葉下山寒寂寂，濕雲如夢雨如塵。"]'),
('8f693478-960f-471e-8ba3-ae1e2d91a9c8','題雲夢亭','崔櫓','唐','唐诗','tang','','[]','薄煙如夢雨如塵，霜景晴來卻勝春。',32,'全唐诗/poet.tang.31000.json','["薄煙如夢雨如塵，霜景晴來卻勝春。", "好住池西紅葉樹，何年今日伴何人。"]'),
('bf519daa-eccb-4adf-ad87-0b8946a2719a','有酒失於虔州陸郎中肱以詩謝之','崔櫓','唐','唐诗','tang','','[]','醉時顛蹶醒時羞，麴糵推人不自由。',32,'全唐诗/poet.tang.31000.json','["醉時顛蹶醒時羞，麴糵推人不自由。", "叵耐一雙窮相眼，不堪花卉在前頭。"]'),
('e7a591b0-7101-4fa1-ba22-a6bfe5fe00dc','聞笛','崔櫓','唐','唐诗','tang','','[]','銀河漾漾月暉暉，樓礙星邊織女機。',32,'全唐诗/poet.tang.31000.json','["銀河漾漾月暉暉，樓礙星邊織女機。", "橫玉叫雲天似水，滿空霜逐一聲飛。"]'),
('d3d29ca8-addb-47f7-b7da-050eba1f7bb9','山路見花','崔櫓','唐','唐诗','tang','','[]','曉紅初拆露香新，獨立空山冷笑人。',32,'全唐诗/poet.tang.31000.json','["曉紅初拆露香新，獨立空山冷笑人。", "春意自知無主惜，恣風吹逐馬蹄塵。"]'),
('8b02bba6-59b2-44b9-8766-c581a55ccc64','暮春對花','崔櫓','唐','唐诗','tang','','[]','病香無力被風欺，多在青苔少在枝。',32,'全唐诗/poet.tang.31000.json','["病香無力被風欺，多在青苔少在枝。", "馬上行人莫回首，斷君腸是欲殘時。"]'),
('6595e0a9-cc53-4b80-b030-e7b74de97cc0','句','崔櫓','唐','唐诗','tang','','[]','強半瘦因前夜雪，數枝愁向晚天來。',80,'全唐诗/poet.tang.31000.json','["強半瘦因前夜雪，數枝愁向晚天來。", "無人解把無塵袖，盛取殘香盡日憐。", "一番春雨吹巢冷，半朵山花咽觜香。", "雲生柱礎降龍地，露洗林巒放鶴天。", "菱葉乍翻人採後，荇花初沒舸行時。"]'),
('628527d2-e757-437e-86cd-88daa0a48338','烏夜號','李羣玉','唐','唐诗','tang','','[]','層波隔夢渚，一望青楓林。',96,'全唐诗/poet.tang.31000.json','["層波隔夢渚，一望青楓林。", "有鳥在其間，達曉自悲吟。", "是時月黑天，四野煙雨深。", "如聞生離哭，其聲痛人心。", "悄悄夜正長，空山響哀音。", "遠客不可聽，坐愁華髮侵。", "既非蜀帝魂，恐是桓山禽。", "四子各分散，母聲猶至今。"]'),
('a85ae87e-c49e-4b8d-af9b-4def60bc555e','昇仙操','李羣玉','唐','唐诗','tang','','[]','嬴女去秦宮，瓊笙飛碧空。',72,'全唐诗/poet.tang.31000.json','["嬴女去秦宮，瓊笙飛碧空。", "鳳臺閉煙霧，鸞吹飄天風。", "復聞周太子，亦遇浮丘公。", "叢簧發天弄，輕舉紫霞中。", "濁世不久駐，清都路何窮。", "一去霄漢上，世人那得逢。"]'),
('d7bd5b2d-55c0-42fb-a451-e2dc688a2686','雨夜呈長官','李羣玉','唐','唐诗','tang','','[]','遠客坐長夜，雨聲孤寺秋。',96,'全唐诗/poet.tang.31000.json','["遠客坐長夜，雨聲孤寺秋。", "請量東海水，看取淺深愁。", "愁窮重於山，終年壓人頭。", "朱顏與芳景，暗赴東波流。", "鱗翼思風水，青雲方阻修。", "孤燈冷素豔，蟲響寒房幽。", "借問陶淵明，何物號忘憂。", "無因一酩酊，高枕萬情休。"]'),
('530ef76a-4fa3-476b-8ae5-24b469c1dcd7','小弟艎南遊近書來','李羣玉','唐','唐诗','tang','','[]','湘南客帆稀，遊子寡消息。',96,'全唐诗/poet.tang.31000.json','["湘南客帆稀，遊子寡消息。", "經時停尺素，望盡雲邊翼。", "笑言頻夢寐，獨立想容色。", "落景無來人，修江入天白。", "停停倚門念，瑟瑟風雨夕。", "何處泊扁舟，迢遰湍波側。", "秋歸舊窗竹，永夜一淒寂。", "吟爾鶺鴒篇，中宵慰相憶。"]'),
('db3993e8-4e3c-4a20-9665-d500360e246b','贈方處士','李羣玉','唐','唐诗','tang','','[]','白衣方外人，高閑溪中鶴。',48,'全唐诗/poet.tang.31000.json','["白衣方外人，高閑溪中鶴。", "無心戀稻粱，但以林泉樂。", "赤霄終得意，天池俟飛躍。", "歲晏入帝鄉，期君在寥廓。"]'),
('ba1740b3-c2bf-4591-b539-b9e66b68ea6d','秋怨','李羣玉','唐','唐诗','tang','','[]','瑟瑟涼海氣，西來送愁容。',96,'全唐诗/poet.tang.31000.json','["瑟瑟涼海氣，西來送愁容。", "金風死綠蕙，玉露生寒松。", "所思在溟碧，無因一相逢。", "登樓睇去翼，目盡滄波重。", "虛窗度流螢，斜月啼幽蛩。", "疎紅落殘豔，冷水凋芙蓉。", "歲暮空太息，年華逐遺踪。", "凝情耿不寐，攬涕起疎慵。"]'),
('b1c9f0ed-ed3c-429a-b5fc-416083b335b2','感春','李羣玉','唐','唐诗','tang','','[]','春情不可狀，豔豔令人醉。',48,'全唐诗/poet.tang.31000.json','["春情不可狀，豔豔令人醉。", "暮水綠楊愁，深窗落花思。", "吳宮新暖日，海燕雙飛至。", "秋思逐煙光，空濛滿天地。"]'),
('a29d2129-1f90-4c70-bcda-383046feb5de','山中秋夕','李羣玉','唐','唐诗','tang','','[]','抱琴出南樓，氣爽浮雲滅。',48,'全唐诗/poet.tang.31000.json','["抱琴出南樓，氣爽浮雲滅。", "松風吹天簫，竹路踏碎月。", "後山鶴唳定，前浦荷香發。", "境寂良夜深，了與人間別。"]'),
('404322da-384b-43c6-b893-725402b463a0','將遊羅浮登廣陵楞伽臺別羽客','李羣玉','唐','唐诗','tang','','[]','清遠登高臺，晃朗縱覽歷。',144,'全唐诗/poet.tang.31000.json','["清遠登高臺，晃朗縱覽歷。", "濯泉喚仙風，於此盪靈魄。", "冷光邀遠目，百里見海色。", "送雲歸蓬壺，望鶴滅秋碧。", "波瀾收日氣，天自回澄寂。", "百越落掌中，十洲點空白。", "身居飛鳥上，口詠玄元籍。", "飄如出塵籠，想望吹簫客。", "冥冥人間世，歌笑不足惜。", "朅來羅浮巔，披雲煉瓊液。", "謝公雲岑興，可以躡高跡。", "吾將抱瑤琴，絕境縱所適。"]'),
('f4167338-a88d-42bf-b436-35a768b4b778','盧溪道中','李羣玉','唐','唐诗','tang','','[]','曉發潺湲亭，夜宿潺湲水。',48,'全唐诗/poet.tang.31000.json','["曉發潺湲亭，夜宿潺湲水。", "風篁掃石瀨，琴聲九十里。", "光奔覺來眼，寒落夢中耳。", "曾向三峽行，巴江亦如此。"]'),
('8c9bdc93-aa10-43a6-9c24-b46e941f4dbf','湖中古愁三首 一','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','涼風西海來，直渡洞庭水。',48,'全唐诗/poet.tang.31000.json','["涼風西海來，直渡洞庭水。", "翛翛木葉下，白浪連天起。", "蘅蘭委皓雪，百草一時死。", "摧殘負志人，感歎何窮已。"]'),
('32083c21-f38b-4576-93f8-7dda5f34ff6b','湖中古愁三首 二','李羣玉','唐','唐诗','tang','','[]','昔我覩雲夢，窮秋經汨羅。',48,'全唐诗/poet.tang.31000.json','["昔我覩雲夢，窮秋經汨羅。", "靈均竟不返，怨氣成微波。", "奠桂開古祠，朦朧入幽蘿。", "落日瀟湘上，淒涼吟九歌。"]'),
('614ec9da-1be9-4d6e-813b-a029127f32c3','湖中古愁三首 三','李羣玉','唐','唐诗','tang','','[]','南雲哭重華，水死悲二女。',48,'全唐诗/poet.tang.31000.json','["南雲哭重華，水死悲二女。", "天邊九點黛，白骨迷處所。", "朦朧波上瑟，清夜降北渚。", "萬古一雙魂，飄飄在煙雨。"]'),
('2c667c63-e96a-41c7-8185-9284534a31fa','別狄佩','李羣玉','唐','唐诗','tang','','[]','翠竹不著花，鳳雛長忍飢。',72,'全唐诗/poet.tang.31000.json','["翠竹不著花，鳳雛長忍飢。", "未開丹霄翮，空把碧梧枝。", "聖人奏雲韶，祥鳳一來儀。", "文章耀白日，衆鳥莫敢窺。", "鬱抑不自言，凡鳥何由知。", "當看九千仞，飛出太平時。"]'),
('7af80c94-ce50-4394-8c4b-ca5bb9be4186','古鏡','李羣玉','唐','唐诗','tang','','[]','明月何處來，朦朧在人境。',120,'全唐诗/poet.tang.31000.json','["明月何處來，朦朧在人境。", "得非軒轅作，妙絕世莫竝。", "瑤匣開旭日，白電走孤影。", "泓澄一尺天，徹底寒霜景。", "冰輝凜毛髮，使我肝膽冷。", "忽驚行深幽，面落九秋井。", "雲天入掌握，爽朗神魂淨。", "不必負局仙，金沙發光炯。", "陰沈蓄靈怪，可與天地永。", "恐爲悲龍吟，飛去在俄頃。"]'),
('a86c6de0-4b6c-4841-86e1-4a9924b9761f','我思何所在','李羣玉','唐','唐诗','tang','','[]','我思何所在，乃在陽臺側。',72,'全唐诗/poet.tang.31000.json','["我思何所在，乃在陽臺側。", "良宵相望時，空此明月色。", "歸魂泊湘雲，飄蕩去不得。", "覺來理舟檝，波浪春湖白。", "煙光浩楚秋，瑤草不忍摘。", "因書天末心，繫此雙飛翼。"]'),
('5c430f15-548e-491d-a1cc-8e03d067655c','送蕭綰之桂林','李羣玉','唐','唐诗','tang','','[]','蘭香佩蘭人，弄蘭蘭江春。',144,'全唐诗/poet.tang.31000.json','["蘭香佩蘭人，弄蘭蘭江春。", "爾爲蘭林秀，芳藻驚常倫。", "燦燦鳳池裔，一毛今再新。", "竹花不給口，憔悴清湘濱。", "一朝南溟飛，彩翮不可親。", "蒼梧雲水晚，離思空凝顰。", "我亦縱煙櫂，西浮彭蠡津。", "丈夫未虎變，落魄甘風塵。", "大禹惜寸陰，況我無才身。", "流光銷道路，以此生嗟辛。", "萬里闊分袂，相思杳難申。", "桂水秋更碧，寄書西上鱗。"]'),
('5d77e4e4-856f-4eac-a140-43ceb4cb7e67','感興四首 一','李羣玉','唐','唐诗','tang','','[]','子雲吞白鳳，遂吐太玄書。',48,'全唐诗/poet.tang.31000.json','["子雲吞白鳳，遂吐太玄書。", "幽微十萬字，枝葉何扶疎。", "婉孌猛虎口，甘言累其初。", "一覩美新作，斯瑕安可除。"]'),
('5c1b91a7-53c5-4c92-b4de-965158b853ea','感興四首 二','李羣玉','唐','唐诗','tang','','[]','昔竊不死藥，奔空有嫦娥。',48,'全唐诗/poet.tang.31000.json','["昔竊不死藥，奔空有嫦娥。", "盈盈天上豔，孤潔棲金波。", "織女了無語，長宵隔銀河。", "軋軋揮素手，幾時停玉梭。"]'),
('3cf4326c-6369-43ba-95bc-2ae73da4a51f','感興四首 三','李羣玉','唐','唐诗','tang','','[]','洞房三五夕，金釭凝焰滅。',48,'全唐诗/poet.tang.31000.json','["洞房三五夕，金釭凝焰滅。", "美人抱雲和，斜倚紗窗月。", "沈吟想幽夢，閨思深不說。", "弦冷玉指寒，含顰待明發。"]'),
('5f5228be-2f54-4d0a-8856-2016c6086f51','感興四首 四','李羣玉','唐','唐诗','tang','','[]','朔雁銜邊秋，寒聲落燕代。',48,'全唐诗/poet.tang.31000.json','["朔雁銜邊秋，寒聲落燕代。", "先驚愁人耳，顏髮潛消改。", "凝雲蔽洛浦，夢寐勞光彩。", "天邊無書來，相思淚成海。"]'),
('3442a4b4-c259-49d4-a36e-e187d6212da0','將之吳越留別坐中文酒諸侶','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','秋色滿水國，江湖興蕭然。',132,'全唐诗/poet.tang.31000.json','["秋色滿水國，江湖興蕭然。", "氛埃斂八極，萬里淨澄鮮。", "涔浦縱孤櫂，吳門渺三千。", "迴隨衡陽雁，南入洞庭天。", "早聞陸士龍，矯掌跨山川。", "非思鱸魚膾，且弄五湖船。", "暝泊遠浦霞，曉飯蘆洲煙。", "風流訪王謝，佳境恣洄沿。", "霜剪別岸柳，香枯北池蓮。", "歲華坐搖落，寂寂感流年。", "明朝即漂萍，離憾無由宣。"]'),
('760d0a75-788f-4cb8-a91a-b7f58eb8a898','大雲池泛舟','李羣玉','唐','唐诗','tang','','[]','九月蓮花死，萍枯霜水清。',72,'全唐诗/poet.tang.31000.json','["九月蓮花死，萍枯霜水清。", "船浮天光遠，櫂拂翠瀾輕。", "古木□□□，了無煙靄生。", "游鱗泳皎潔，洞見逍遙情。", "漁父一曲歌，滄浪遂知名。", "未知斯水上，可以濯吾纓。"]'),
('12f8cd5b-d88f-4bd4-b198-a00da4f1be6d','送友人之峽','李羣玉','唐','唐诗','tang','','[]','東吳有賦客，願識陽臺仙。',48,'全唐诗/poet.tang.31000.json','["東吳有賦客，願識陽臺仙。", "彩毫飛白雲，不減郢中篇。", "楚水五月浪，輕舟入暮煙。", "巫雲多感夢，桂檝早回旋。"]'),
('c2dc6859-8cc9-49fd-a5dd-73c15437a51d','登宜春醉宿景星寺寄鄭判官兼簡空上人','李羣玉','唐','唐诗','tang','','[]','曉發碧水陽，暝宿金山寺。',192,'全唐诗/poet.tang.31000.json','["曉發碧水陽，暝宿金山寺。", "松風灑寒雨，淅瀝醒餘醉。", "夜中香積飯，蔬粒俱精異。", "境寂滅塵愁，神高得詩思。", "皎皎滎陽子，芳春富才義。", "漲海豁心源，冰壺見門地。", "碧霄有鳩序，未展聯行翅。", "俱笑一尺繩，三年絆騏驥。", "摧藏擔簦客，鬱抑胸襟事。", "名業爾未從，臨風嘿舒志。", "一身渺雲嶺，中夜空涕泗。", "側枕對孤燈，衾寒不成寐。", "糧薪極桂玉，大道生榛刺。", "耻息惡木陰，難書劒歌意。", "揚鞭入莽蒼，山驛凌煙翠。", "越鳥日南飛，芳音願相次。"]'),
('8be4c7b2-39b9-49d4-a8d7-6aeb97cc095e','江樓獨酌懷從叔','李羣玉','唐','唐诗','tang','','[]','水國發爽氣，川光靜高秋。',72,'全唐诗/poet.tang.31000.json','["水國發爽氣，川光靜高秋。", "酣歌金尊醁，送此清風愁。", "楚色忽滿目，灘聲落西樓。", "雲翻天邊葉，月弄波上鉤。", "芳意長搖落，蘅蘭謝汀洲。", "長吟碧雲合，悵望江之幽。"]'),
('8cb080ad-48cf-4187-a6ea-d6b431945387','登章華樓','李羣玉','唐','唐诗','tang','','[]','楚子故宮地，蒼然雲水秋。',96,'全唐诗/poet.tang.31000.json','["楚子故宮地，蒼然雲水秋。", "我來覽從事，落景空生愁。", "伯業沒荆棘，雄圖成古丘。", "沈吟問鼎語，但見東波流。", "征鴻引鄉心，一去何悠悠。", "晴湖碧雲晚，暝色空高樓。", "迢遰趨遠嶠，微茫入孤舟。", "空路不堪望，西風白浪稠。"]'),
('93485a55-27ee-4f7b-a6a0-128ac61a858c','驄馬','李羣玉','唐','唐诗','tang','','[]','浮雲何權奇，絕足世未知。',96,'全唐诗/poet.tang.31000.json','["浮雲何權奇，絕足世未知。", "長嘶清海風，蹀躞振雲絲。", "由來渥洼種，本是蒼龍兒。", "穆滿不再活，無人崑閬騎。", "若識躍嶠怯，寧勞耀金羈。", "青芻與白水，空笑駑駘肥。", "伯樂儻一見，應驚耳長垂。", "當思八荒外，逐日向瑤池。"]'),
('857e4e1c-5a8b-4152-965c-f8781faf916c','贈方處士兼以寫別','李羣玉','唐','唐诗','tang','','[]','天與雲鶴情，人間恣詩酒。',168,'全唐诗/poet.tang.31000.json','["天與雲鶴情，人間恣詩酒。", "龍宮奉採覓，澒洞一千首。", "清如南薰絲，韻若黃鍾吼。", "喜於風騷地，忽見陶謝手。", "籍籍九江西，篇篇在人口。", "芙蓉爲芳菲，未落諸花後。", "所知心眼大，別自開戶牖。", "才力似風鵬，誰能算升斗。", "無營傲雲竹，琴帙靜爲友。", "鸞鳳戢羽儀，騏驥在郊藪。", "鏡湖春水綠，越客憶歸否。", "白衣四十秋，逍遙一何久。", "此身無定跡，又逐浮雲走。", "離思書不窮，殘陽落江柳。"]'),
('ae9523d9-de43-4d8f-9add-0e990804c7d0','湘西寺霽夜','李羣玉','唐','唐诗','tang','','[]','雨過琉璃宮，佳興浩清絕。',72,'全唐诗/poet.tang.31000.json','["雨過琉璃宮，佳興浩清絕。", "松風冷晴灘，竹路踏碎月。", "月波蕩如水，氣爽星朗滅。", "皓夜千樹寒，崢嶸萬巖雪。", "後山鶴唳斷，前池荷香發。", "境寂涼夜深，神思空飛越。"]'),
('68686207-a94d-4f61-9a7c-90c517aba3ee','傷思','李羣玉','唐','唐诗','tang','','[]','八月白露濃，芙蓉抱香死。',48,'全唐诗/poet.tang.31000.json','["八月白露濃，芙蓉抱香死。", "紅枯金粉墮，寥落寒塘水。", "西風團葉下，疊縠參差起。", "不見櫂歌人，空垂綠房子。"]'),
('9e8e6700-a4f4-4a7d-a5ca-823312ad46c6','送鄭京昭之雲安','李羣玉','唐','唐诗','tang','','[]','君吟高唐賦，路過巫山渚。',72,'全唐诗/poet.tang.31000.json','["君吟高唐賦，路過巫山渚。", "莫令巫山下，幽夢惹雲雨。", "往事幾千年，芬菲今尚傳。", "空留荆王館，巖嶂深蒼然。", "楚水五月浪，輕舟入蘋煙。", "送君揚檝去，愁絕郢城篇。"]'),
('3ab89901-9d1d-4476-89b0-249c6716fc30','送處士自番禺東遊便歸蘇臺別業','李羣玉','唐','唐诗','tang','','[]','啞軋暮江上，櫓聲搖落心。',144,'全唐诗/poet.tang.31000.json','["啞軋暮江上，櫓聲搖落心。", "宛陵三千里，路指吳雲深。", "蓴菜動歸興，忽然聞會吟。", "南浮龍川月，東下敬亭岑。", "多君詠逍遙，結蘿碧溪陰。", "高籠華表鶴，靜對幽蘭琴。", "汗漫江海思，傲然抽冠簪。", "歸嶼未云寂，還家應追尋。", "二陸文苑秀，岧嶤懷所欽。", "惜我入洛晚，不睹雙南金。", "江左風流盡，名賢成古今。", "送君無限意，別酒但加斟。"]'),
('e0636722-7ab2-456a-aeee-48d366755146','法華微上人盛話金山境勝舊遊在目吟成此篇','李羣玉','唐','唐诗','tang','','[]','江上青蓮宮，人間蓬萊島。',48,'全唐诗/poet.tang.31000.json','["江上青蓮宮，人間蓬萊島。", "煙霞與波浪，隱暎樓臺好。", "潮門梵音靜，海日天光早。", "願與靈鷲人，吟經此終老。"]'),
('a5fb9e03-9aca-4f5b-a906-672e30fcec3d','洞庭入澧江寄巴丘故人','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','四月桑半枝，吳蠶初弄絲。',48,'全唐诗/poet.tang.31000.json','["四月桑半枝，吳蠶初弄絲。", "江行好風日，燕舞輕波時。", "去事旋成夢，來歡難預期。", "唯憑東流水，日夜寄相思。"]'),
('070d66a9-c9a0-44a3-be22-af612fac4861','自澧浦東遊江表途出巴丘投員外從公虞','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','短翮後飛者，前攀鸞鶴翔。',288,'全唐诗/poet.tang.31000.json','["短翮後飛者，前攀鸞鶴翔。", "力微應萬里，矯首空蒼蒼。", "誰昔探花源，考槃西岳陽。", "高風動商洛，綺皓無馨香。", "一朝下蒲輪，清輝照巖廊。", "孤醒立衆醉，古道何由昌。", "經術震浮盪，國風掃齊梁。", "文襟即玄圃，筆下成琳琅。", "霞水散吟嘯，松筠奉琴觴。", "冰壺避皎潔，武庫羞鋒鋩。", "小子書代耕，束髮頗自強。", "艱哉水投石，壯志空摧藏。", "十年侶龜魚，垂頭在沅湘。", "巴歌揜白雪，鮑肆埋蘭芳。", "騷雅道未喪，何憂名不彰。", "飢寒束困厄，默塞飛星霜。", "百志不成一，東波擲年光。", "塵生脫粟甑，萬里違高堂。", "中夜恨火來，焚燒九回腸。", "平明梁山淚，緣枕霑匡牀。", "依泊洞庭波，木葉忽已黃。", "哀碪擣秋色，曉月啼寒螿。", "復此櫂孤舟，雲濤浩茫茫。", "朱門待媒勢，短褐誰揄揚。"]'),
('6386abab-1d67-4389-b62a-25dafa71756a','洞庭驛樓雪夜讌集奉贈前湘州張員外','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','昔與張湘州，閑登岳陽樓。',192,'全唐诗/poet.tang.31000.json','["昔與張湘州，閑登岳陽樓。", "目窮衡巫表，興盡荆吳秋。", "擲筆落郢曲，巴人不能酬。", "是時簪裾會，景物窮冥搜。", "誤忝玳筵秀，得陪文苑遊。", "幾篇雲楣上，風雨沈銀鉤。", "□□□□□，□□□滄洲。", "童兒待郭伋，竹馬空遲留。", "路指雲漢津，誰能吟四愁。", "銀壺傲海雪，青管羅名謳。", "賤子迹未安，謀身拙如鳩。", "分隨煙霞老，豈有風雲求。", "不逐萬物化，但貽知己羞。", "方窮立命說，戰勝心悠悠。", "不然蹲會稽，鉤下三五牛。", "所期波濤助，燀赫呈吞舟。"]'),
('de0ff3d4-e404-4673-8181-d733be57d445','送鄭子寬棄官東遊便歸女几','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','八月湖浸天，揚帆入秋色。',144,'全唐诗/poet.tang.31000.json','["八月湖浸天，揚帆入秋色。", "岷峨雪氣來，寒漲瀟湘碧。", "子真冥鴻志，不逐籠下翼。", "九女疊雲屏，於焉恣栖息。", "新詩山水思，靜入陶謝格。", "困醉松花春，追攀紫煙客。", "相逢十年舊，嚬笑等歡慽。", "一飯玉露蔬，中腸展堆積。", "停食不盡意，傾意悵可惜。", "雲水一分飛，離憂洞庭側。", "迴車三鄉路，仙菊正堪摘。", "寄謝杜蘭香，何年別張碩。"]'),
('9db65641-29c3-4dc7-95d5-acc8e587bbf4','長沙九日登東樓觀舞 一','李羣玉','唐','唐诗','tang','','[]','南國有佳人，輕盈綠腰舞。',48,'全唐诗/poet.tang.31000.json','["南國有佳人，輕盈綠腰舞。", "華筵九秋暮，飛袂拂雲雨。", "翩如蘭苕翠，婉如游龍舉。", "越豔罷前溪，吳姬停白紵。"]'),
('8585ac55-69dd-47ef-92b8-006e47054cc2','長沙九日登東樓觀舞 二','李羣玉','唐','唐诗','tang','','[]','慢態不能窮，繁姿曲向終。',48,'全唐诗/poet.tang.31000.json','["慢態不能窮，繁姿曲向終。", "低回蓮破浪，凌亂雪縈風。", "墜珥時流盻，修裾欲遡空。", "唯愁捉不住，飛去逐驚鴻。"]'),
('17c8d423-0fc2-41b9-a961-1432f4157104','龍山人惠石廩方及團茶','李羣玉','唐','唐诗','tang','','[]','客有衡岳隱，遺余石廩茶。',120,'全唐诗/poet.tang.31000.json','["客有衡岳隱，遺余石廩茶。", "自云凌煙露，采掇春山芽。", "珪璧相壓疊，積芳莫能加。", "碾成黃金粉，輕嫩如松花。", "紅鑪爨霜枝，越兒斟井華。", "灘聲起魚眼，滿鼎漂清霞。", "凝澄坐曉燈，病眼如蒙紗。", "一甌拂昏寐，襟鬲開煩拏。", "顧渚與方山，誰人留品差。", "持甌默吟味，搖膝空咨嗟。"]'),
('281ee8e7-0bf6-422b-912c-3d7873e88f2c','宿鳥遠峽化臺遇風雨','李羣玉','唐','唐诗','tang','','[]','孤鶴長松顛，獨宿萬巖雨。',48,'全唐诗/poet.tang.31000.json','["孤鶴長松顛，獨宿萬巖雨。", "龍湫在石腳，引袂時一取。", "驚風折喬木，飛焰獵窗戶。", "半夜霹靂聲，高齋有人語。"]'),
('eed147ba-1ea7-4d41-b880-302f1eff3d74','岳陽春晚','李羣玉','唐','唐诗','tang','','[]','不覺春物老，塊然湖上樓。',48,'全唐诗/poet.tang.31000.json','["不覺春物老，塊然湖上樓。", "雲沙鷓鴣思，風日沅湘愁。", "去翼滅雲夢，來帆指昭丘。", "所嗟芳桂晚，寂寞對汀洲。"]'),
('d3649552-59e3-4167-b78d-8f013b5c77b6','漢陽春晚','李羣玉','唐','唐诗','tang','','[]','漢陽抱青山，飛樓暎湘渚。',48,'全唐诗/poet.tang.31000.json','["漢陽抱青山，飛樓暎湘渚。", "白雲蔽黃鶴，綠樹藏鸚鵡。", "憑高送春目，流恨傷千古。", "遐思禰衡才，令人怨黃祖。"]'),
('d87da7e0-93c4-4587-9464-85ee87f3afc7','將離澧浦置酒野嶼奉懷沈正字昆弟三人聯登高第','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','春月三改兔，花枝成綠陰。',144,'全唐诗/poet.tang.31000.json','["春月三改兔，花枝成綠陰。", "年光東流水，浩歎傷羈心。", "酌桂煙嶼晚，鴂鳴江草深。", "良圖一超忽，萬恨空相尋。", "上國刈翹楚，才微甘陸沈。", "無燈假貧女，有淚沾牛衾。", "衡岳三麒麟，各振黃鍾音。", "卿雲被文彩，芳價搖詞林。", "夫子芸閣英，養鱗湘水潯。", "晴沙踏蘭菊，隱几當青岑。", "明月洞庭上，悠揚挂離襟。", "停觴一搖筆，聊寄生芻吟。"]'),
('7fd9d980-5bab-4bee-b543-9983e5020b87','湘中別成威闍黎','李羣玉','唐','唐诗','tang','','[]','至哉彼上人，冰霜凜規則。',144,'全唐诗/poet.tang.31000.json','["至哉彼上人，冰霜凜規則。", "遊心杳何境，宴坐入冥默。", "解空與密行，名臘信崇德。", "吐論駕秋濤，龍宮發胸臆。", "羣迷行大夜，浩浩一昏黑。", "赤水千丈深，玄珠幾人得。", "持桮挹溟漲，至理安可測。", "寧假喻芭蕉，真成嗅薝蔔。", "松聲掃白月，霽夜來靜域。", "清梵罷法筵，天香滿衣襋。", "何方濟了岸，秪仗慈航力。", "願與十八賢，同棲翠蓮國。"]'),
('8721c066-db42-44da-be87-a1a76680992b','別尹鍊師','李羣玉','唐','唐诗','tang','','[]','吾家五千言，至道懸日月。',144,'全唐诗/poet.tang.31000.json','["吾家五千言，至道懸日月。", "若非函谷令，誰注流沙說。", "多君飛昇志，機悟獨超拔。", "學道玉笥山，燒丹白雲穴。", "南窮衡疑秀，采藥歷幽絕。", "夜臥瀑布風，朝行碧巖雪。", "洞宮四百日，玉籍恣探閱。", "徒以菌蟪姿，緬攀修真訣。", "塵籠罩浮世，遐思空飛越。", "一罷棋酒歡，離情滿寥泬。", "願騎紫蓋鶴，早向黃金闕。", "城市不可留，塵埃穢仙骨。"]'),
('1ac31558-9e7a-46cc-a268-d9fd3c3802e3','飯僧','李羣玉','唐','唐诗','tang','','[]','好讀天竺書，爲尋無生理。',144,'全唐诗/poet.tang.31000.json','["好讀天竺書，爲尋無生理。", "焚香面金偈，一室唯巾水。", "交信方外言，二三空門子。", "峻範照秋霜，高標揜僧史。", "清晨潔蔬茗，延請良有以。", "一落喧譁競，栖心願依止。", "奔曦入半百，冉冉頹濛汜。", "雲汎名利心，風輕是非齒。", "向爲情愛縛，未盡金仙旨。", "以靜制猨心，將虞瞥然起。", "綸巾與藜杖，此意真已矣。", "他日雲壑間，來尋幽居士。"]'),
('612449a3-c1fa-478b-bfa5-6daf76dac4bc','贈回雪','李羣玉','唐','唐诗','tang','','[]','回雪舞縈盈，縈盈若回雪。',48,'全唐诗/poet.tang.31000.json','["回雪舞縈盈，縈盈若回雪。", "腰支一把玉，秪恐風吹折。", "如能買一笑，滿斗量明月。", "安得金蓮花，步步承羅襪。"]'),
('a23b4c7c-255d-4a62-b221-4b62b42fcbcb','將之京國贈薛員外','李羣玉','唐','唐诗','tang','','[]','黃葉下空館，寂寥寒雨愁。',216,'全唐诗/poet.tang.31000.json','["黃葉下空館，寂寥寒雨愁。", "平居歲華晏，絡緯啼林幽。", "節物凋壯志，咄嗟不能休。", "空懷趙鞅歎，變化良無由。", "所思杳何如，側身仰皇州。", "蒼煙晦楚野，寒浪埋昭丘。", "趙壹賦命薄，陳思多世憂。", "翻然羨魚鳥，暢矣山川遊。", "薛公龍泉姿，其氣在斗牛。", "南冠束秀髮，白石勞悲謳。", "圭衮照崇閱，文儒嗣箕裘。", "曠然方寸地，霽海浮雲舟。", "澧浦一遺佩，郢南再悲秋。", "叫閽路既阻，浩蕩懷靈修。", "莫奏武溪笛，且登仲宣樓。", "亨通與否閉，物理相沈浮。", "天子坐宣室，夔龍奉謨猷。", "行當賜環去，豈作遺賢羞。"]'),
('36d31a8b-5a38-4bb4-89b4-92705c1123d2','送魏珪覲省','李羣玉','唐','唐诗','tang','','[]','木落楚色深，風高浪花白。',216,'全唐诗/poet.tang.31000.json','["木落楚色深，風高浪花白。", "送君飛一葉，鳥逝入空碧。", "猗歟白華秀，傷心倚門夕。", "不知雲漲遙，萬里看咫尺。", "蕭蕭青楓岸，去掩江山宅。", "離觴有黃花，節物助淒戚。", "瀟湘入𤃩桂，一路縈水石。", "煙蘿拂行舟，玉瀨鏘枕席。", "多君林泉趣，耽翫日成癖。", "長嘯凌清暉，襟情當雪滌。", "登龍屈指內，飛譽甚籍籍。", "未折月中枝，寧隨宋都鶂。", "曰余吞聲地，舉足傷瓦礫。", "見爾一開顏，溫明乃珠璧。", "春風到雲嶠，把酒時相憶。", "荳蔻花入船，鷓鴣啼送客。", "颺天與瘴海，此去備沿歷。", "珍重春官英，加餐數刀帛。"]'),
('0ccb5c9c-756b-4463-b39e-c53622326f39','始忝四座奏狀聞薦蒙恩授官旋進歌詩延英宣賜言懷紀事呈同館諸公二十四韻','李羣玉','唐','唐诗','tang','','[]','兩鬢有二毛，光陰流浪中。',288,'全唐诗/poet.tang.31000.json','["兩鬢有二毛，光陰流浪中。", "形骸日土木，志氣隨雲風。", "冥默楚江畔，蕭條林巷空。", "幽鳥事翔翥，斂翼依蒿蓬。", "一飯五放箸，愀然念途窮。", "孟門在步武，所向何由通。", "秖徵大易言，物否不可終。", "庶期白雪調，一奏驚凡聾。", "昨忝丞相召，揚鞭指冥鴻。", "姓名挂丹詔，文句飛天聰。", "解薜龍鳳署，懷鉛蘭桂叢。", "聲名仰聞見，煙漢陪高蹤。", "峨峨羣玉山，肅肅紫殿東。", "神飆泛鐘漏，佳氣浮筠松。", "自顧珉玞璞，何緣侶圭琮。", "羣賢垂重價，省已增磨礱。", "天子棲穆清，三台付夔龍。", "九霄降雨露，萬國望時雍。", "巍巍致君期，勛華將比崇。", "承天四柱石，嶷若窺衡嵩。", "日見帝道昇，謀猷垂景鍾。", "寰瀛納壽域，翔泳皆沖融。", "百神儼云亭，佇將告成功。", "吾徒事文藻，驤首歌登封。"]'),
('91a30d65-cd5e-40e7-b923-be3c706ad898','穆天子','李羣玉','唐','唐诗','tang','','[]','穆滿恣逸志，而輕天下君。',96,'全唐诗/poet.tang.31000.json','["穆滿恣逸志，而輕天下君。", "一朝得八駿，逐日西溟濆。", "寂漠崦嵫幽，絕迹留空文。", "三千閟宮豔，怨絕寧勝云。", "或言帝軒轅，乘龍凌紫氛。", "橋山葬弓劒，曖昧竟難分。", "不思五弦琴，作歌詠南薰。", "但聽西王母，瑤池吟白雲。"]'),
('6deaec83-a8cc-4d61-88de-31ae247c8cfc','廣州重別方處士之封川 一','李羣玉','唐','唐诗','tang','','[]','楚國傲名客，九州徧芳聲。',48,'全唐诗/poet.tang.31000.json','["楚國傲名客，九州徧芳聲。", "白衣謝簪紱，雲臥重巖扃。", "長波飛素舸，五月下南溟。", "大笑相逢日，天邊作酒星。"]'),
('30e6a74f-2234-4671-b8be-0fb8e8b589ce','廣州重別方處士之封川 二','李羣玉','唐','唐诗','tang','','[]','七年一雲雨，常恨輝容隔。',48,'全唐诗/poet.tang.31000.json','["七年一雲雨，常恨輝容隔。", "天末又分襟，離憂鬢堪白。", "顧回凌潮檝，且著登山屐。", "共期羅浮秋，與子醉海色。"]'),
('bedb7651-87b4-4c81-8786-bf88bca46b92','洞庭遇秋','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','塵愁老來顏，久與江山隔。',48,'全唐诗/poet.tang.31000.json','["塵愁老來顏，久與江山隔。", "逍遙澄湖上，洗眼見秋色。", "涼波弄輕櫂，湖月生遠碧。", "未減遙客情，西望杳何極。"]'),
('cfb1deb3-6c95-4534-8fd5-90edc67cdd7e','寄短書歌','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','骨肉萍蓬各天末，十度附書九不達。',64,'全唐诗/poet.tang.31000.json','["骨肉萍蓬各天末，十度附書九不達。", "孤臺冷眼無來人，楚水秦天莽空闊。", "翔雁橫秋過洞庭，西風落日浪崢嶸。", "三年音信凝顰外，一曲哀歌白髮生。"]'),
('e9a8c48b-ca6b-416a-b0da-664309a8e4da','王內人琵琶引','李羣玉','唐','唐诗','tang','','[]','檀槽一曲黃鍾羽，細撥紫雲金鳳語。',84,'全唐诗/poet.tang.31000.json','["檀槽一曲黃鍾羽，細撥紫雲金鳳語。", "萬里胡天海塞秋，分明彈出風沙愁。", "三千宮嬪推第一，斂黛傾鬟豔蘭室。", "嬴女停吹降浦簫，嫦娥淨揜空波瑟。", "翠幕橫雲蠟燄光，銀龍吐酒菊花香。", "皓魄翻。"]'),
('ba35eb27-da3d-4065-b0bc-5221951b43ed','醒起獨酌懷友','李羣玉','唐','唐诗','tang','','[]','西風靜夜吹蓮塘，芙蓉破紅金粉香。',48,'全唐诗/poet.tang.31000.json','["西風靜夜吹蓮塘，芙蓉破紅金粉香。", "摘花把酒弄秋芳，吳雲楚水愁茫茫。", "美人此夕不入夢，獨宿高樓明月涼。"]'),
('51f105d6-4a07-4476-a2c6-09fb4207cab1','競渡時在湖外偶爲成章','李羣玉','唐','唐诗','tang','','[]','雷奔電逝三千兒，彩舟畫檝射初暉。',64,'全唐诗/poet.tang.31000.json','["雷奔電逝三千兒，彩舟畫檝射初暉。", "喧江雷鼓鱗甲動，三十六龍銜浪飛。", "靈均昔日投湘死，千古沈魂在湘水。", "綠草斜煙日暮時，笛聲幽遠愁江鬼。"]'),
('ac5d0eeb-5cf7-4d43-a65d-a7a2b4b5d9e5','新荷','李羣玉','唐','唐诗','tang','','[]','田田八九葉，散點綠池初。',48,'全唐诗/poet.tang.31000.json','["田田八九葉，散點綠池初。", "嫩碧纔平水，圓陰已蔽魚。", "浮萍遮不合，弱荇繞猶疎。", "半在春波底，芳心卷未舒。"]'),
('85d5849f-c09a-4cf9-91b2-a795803e65ab','初月二首 一','李羣玉','唐','唐诗','tang','','[]','灩灩流光淺，娟娟汎露輕。',48,'全唐诗/poet.tang.31000.json','["灩灩流光淺，娟娟汎露輕。", "雲間龍爪落，簾上玉鉤明。", "桂樹枝猶小，仙人影未成。", "欲爲千里別，倚幌獨含情。"]'),
('fb04f64e-5473-4dc9-b800-c48fddf7f2b9','初月二首 二','李羣玉','唐','唐诗','tang','','[]','凝顰立戶前，細魄向娟娟。',36,'全唐诗/poet.tang.31000.json','["凝顰立戶前，細魄向娟娟。", "破鏡徒相問，刀頭恐隔年。", "輕輕搖遠水，脉脉下春煙。"]'),
('f0bc403a-eba8-4a13-869a-5e729e1391aa','石瀦','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','古岸陶爲器，高林盡一焚。',48,'全唐诗/poet.tang.31000.json','["古岸陶爲器，高林盡一焚。", "燄紅湘浦口，煙濁洞庭雲。", "迥野煤飛亂，遙空爆響聞。", "地形穿鑿勢，恐到祝融墳。"]'),
('f4725ac5-87e9-4734-aadb-60bb63e4e28a','雲安','李羣玉','唐','唐诗','tang','','[]','灘惡黃牛吼，城孤白帝秋。',48,'全唐诗/poet.tang.31000.json','["灘惡黃牛吼，城孤白帝秋。", "水寒巴字急，歌迥竹枝愁。", "樹暗荆王館，雲昏蜀客舟。", "瑤姬不可見，行雨在高丘。"]'),
('4c5ec95b-442c-4e6a-922b-4feb5956575b','石頭城','李羣玉','唐','唐诗','tang','','[]','伯業隨流水，寒蕪上古城。',48,'全唐诗/poet.tang.31000.json','["伯業隨流水，寒蕪上古城。", "長空橫海色，斷岸落潮聲。", "八極悲扶拄，五湖來止傾。", "東南天子氣，掃地入函京。"]'),
('84d35096-b9f6-424b-bc43-bd88defa5748','湖闊','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚色籠青草，秋風洗洞庭。',48,'全唐诗/poet.tang.31000.json','["楚色籠青草，秋風洗洞庭。", "夕霏生水寺，初月盡雲汀。", "櫂響來空闊，漁歌發杳冥。", "欲浮闌下艇，一到斗牛星。"]'),
('5b02711f-9cd0-413a-9f39-60a0a20624a1','失鶴','李羣玉','唐','唐诗','tang','','[]','瑤臺煙霧外，一去不迴心。',48,'全唐诗/poet.tang.31000.json','["瑤臺煙霧外，一去不迴心。", "清海蓬壺遠，秋風碧落深。", "墮翎留片雪，雅操入孤琴。", "豈是籠中物，雲蘿莫更尋。"]'),
('ac03417d-e395-4f6c-8cf3-640dde55d0bf','臘夜雪霽月彩交光開閣臨軒竟睡不得命家僕吹笙數曲獨引一壺奉寄江陵副使杜中丞','李羣玉','唐','唐诗','tang','','[]','月華臨霽雪，皓彩射貂裘。',48,'全唐诗/poet.tang.31000.json','["月華臨霽雪，皓彩射貂裘。", "桂酒寒無醉，銀笙凍不流。", "懷哉梁苑客，思作剡溪遊。", "竟夕吟瓊樹，川途恨阻修。"]'),
('a6477ca8-4805-4126-a70a-70de90f97074','長沙陪裴大夫登北樓','李羣玉','唐','唐诗','tang','','[]','巖嶂隨高步，琴尊奉勝遊。',48,'全唐诗/poet.tang.31000.json','["巖嶂隨高步，琴尊奉勝遊。", "金風吹綠簟，湘水入朱樓。", "朗抱雲開月，高情鶴見秋。", "登臨多暇日，非爲賦消憂。"]'),
('aae3bbd2-151b-48df-9b2c-748fc9b36f58','登蒲澗寺後二巖三首 一','李羣玉','唐','唐诗','tang','','[]','五仙騎五羊，何代降茲鄉。',48,'全唐诗/poet.tang.31000.json','["五仙騎五羊，何代降茲鄉。", "澗有堯年韭，山餘禹日糧。", "樓臺籠海色，草樹發天香。", "浩嘯波光裏，浮溟興甚長。"]'),
('70785904-72d3-4220-8cfa-2bd3c9a77997','登蒲澗寺後二巖三首 二','李羣玉','唐','唐诗','tang','','[]','行盡崎嶇路，驚從汗漫遊。',48,'全唐诗/poet.tang.31000.json','["行盡崎嶇路，驚從汗漫遊。", "青天豁眼快，碧海醒心秋。", "便欲尋河漢，因之犯斗牛。", "九霄身自致，何必遇浮丘。"]'),
('006a303a-707a-441d-a518-21a602bdcb03','登蒲澗寺後二巖三首 三','李羣玉','唐','唐诗','tang','','[]','南溟吞越絕，極望碧鴻濛。',48,'全唐诗/poet.tang.31000.json','["南溟吞越絕，極望碧鴻濛。", "龍渡潮聲裏，雷喧雨氣中。", "趙佗丘壠滅，馬援鼓鼙空。", "遐想魚鵬化，開襟九萬風。"]'),
('8fe6fd13-9ca6-4eb3-bd2d-ce57b1e4d7af','早鴻','李羣玉','唐','唐诗','tang','','[]','木落波浪動，南飛聞夜鴻。',48,'全唐诗/poet.tang.31000.json','["木落波浪動，南飛聞夜鴻。", "參差天漢霧，嘹唳月明風。", "野水蓮莖折，寒泥稻穗空。", "無令一行侶，相失五湖中。"]'),
('76a3a9b7-dc04-4d49-9fa0-3787cf29edbe','旅泊','李羣玉','唐','唐诗','tang','','[]','搖落江天裏，飄零倚客舟。',48,'全唐诗/poet.tang.31000.json','["搖落江天裏，飄零倚客舟。", "短篇纔遣悶，小釀不供愁。", "沙雨潮痕細，林風月影稠。", "書空閑度日，深擁破貂裘。"]'),
('1057eda6-000f-4488-8e02-6f17d05206cf','半醉','李羣玉','唐','唐诗','tang','','[]','處俗常如病，看花亦似秋。',48,'全唐诗/poet.tang.31000.json','["處俗常如病，看花亦似秋。", "若無時復酒，寧遣鎮長愁。", "漸覺身非我，都迷蝶與周。", "何煩五色藥，尊下即丹丘。"]'),
('d3a25ff7-c79b-490b-b98c-32bfcb65999f','晝寐','李羣玉','唐','唐诗','tang','','[]','筠桂晚蕭疎，任人嘲宰予。',48,'全唐诗/poet.tang.31000.json','["筠桂晚蕭疎，任人嘲宰予。", "鳥驚林下夢，風展枕前書。", "正作莊生蝶，誰知惠子魚。", "人間無樂事，直擬到華胥。"]'),
('9dd0a401-48b9-46a6-a407-191a9f45d974','晚蓮','李羣玉','唐','唐诗','tang','','[]','露冷芳意盡，稀疎空碧荷。',48,'全唐诗/poet.tang.31000.json','["露冷芳意盡，稀疎空碧荷。", "殘香隨暮雨，枯蘂墮寒波。", "楚客罷奇服，吳姬停櫂歌。", "涉江無可寄，幽恨竟如何。"]'),
('b1a5c3d8-1b8b-4cf5-bc40-fd37df62c1ff','將之番禺留別湖南府幕','李羣玉','唐','唐诗','tang','','[]','本乏煙霞志，那隨鴛鷺遊。',48,'全唐诗/poet.tang.31000.json','["本乏煙霞志，那隨鴛鷺遊。", "一枝仍未定，數粒欲何求。", "溟漲道途遠，荆吳雲雪愁。", "會登梅嶺翠，南翥入炎洲。"]'),
('c7fd18c1-183f-49b7-8bb2-d61bac37c1fe','宵民','李羣玉','唐','唐诗','tang','','[]','大雅無憂怨，宵民有愛憎。',48,'全唐诗/poet.tang.31000.json','["大雅無憂怨，宵民有愛憎。", "魯侯天不遇，臧氏爾何能。", "慘慘心如虺，營營舌似蠅。", "誰於銷骨地，一鑒玉壺冰。"]'),
('351b0052-533b-40d3-a321-bcbba6c8dd2b','吾道','李羣玉','唐','唐诗','tang','','[]','吾道成微哂，時情付絕言。',48,'全唐诗/poet.tang.31000.json','["吾道成微哂，時情付絕言。", "鳳兮衰已盡，犬也吠何繁。", "輕重憂衡曲，妍媸慮鏡昏。", "方忻耳目淨，誰到翟公門。"]'),
('72d4cb05-629b-4a9e-baee-6c46c3bdb37f','與三山人夜話','李羣玉','唐','唐诗','tang','','[]','靜談雲鶴趣，高會兩三賢。',48,'全唐诗/poet.tang.31000.json','["靜談雲鶴趣，高會兩三賢。", "酒思彈琴夜，茶芳向火天。", "兔裘堆膝暖，鳩杖倚牀偏。", "各厭池籠窄，相看意浩然。"]'),
('39622c84-f360-45e2-abb9-3a45bba5c28e','春寒','李羣玉','唐','唐诗','tang','','[]','撥火垂簾夕，將暄向冷天。',48,'全唐诗/poet.tang.31000.json','["撥火垂簾夕，將暄向冷天。", "悶斟壺酒暖，愁聽雨聲眠。", "處世心悠爾，干時思索然。", "春光看已半，明日又藏煙。"]'),
('44be7020-65f8-4887-b142-f276103aab2a','廣江驛餞筵留別','李羣玉','唐','唐诗','tang','','[]','別筵欲盡秋，一醉海西樓。',48,'全唐诗/poet.tang.31000.json','["別筵欲盡秋，一醉海西樓。", "夜雨寒潮水，孤燈萬里舟。", "酒飛鸚鵡重，歌送鷓鴣愁。", "惆悵三年客，難期此處遊。"]'),
('5260b2b8-0e1d-4949-97f0-59e3a7ee567a','桑落洲','李羣玉','唐','唐诗','tang','','[]','九江寒露夕，微浪北風生。',48,'全唐诗/poet.tang.31000.json','["九江寒露夕，微浪北風生。", "浦嶼漁人火，蒹葭鳧鴈聲。", "頹雲晦廬岳，微鼓辨湓城。", "遠憶天邊弟，曾從此路行。"]'),
('ad533ef4-17d9-4dcb-8ddc-1243c1073ef0','杜門','李羣玉','唐','唐诗','tang','','[]','且詠閑居賦，飛翔去未能。',48,'全唐诗/poet.tang.31000.json','["且詠閑居賦，飛翔去未能。", "春風花嶼酒，秋雨竹溪燈。", "世路變陵谷，時情驗友朋。", "達生書一卷，名利付春冰。"]'),
('296bb418-d75a-4e0b-b659-ae6b0620668d','池州封員外郡齋雙鶴丹頂霜翎仙態浮曠罷政之日因呈此章','李羣玉','唐','唐诗','tang','','[]','瀟灑二白鶴，對之高興清。',48,'全唐诗/poet.tang.31000.json','["瀟灑二白鶴，對之高興清。", "寒溪侶雲水，朱閣伴琴笙。", "顧慕稻粱惠，超遙江海情。", "應攜帝鄉去，仙闕看飛鳴。"]'),
('1d440b1f-0f4d-4c6c-8d57-308d35313799','經費拾遺所居呈封員外','李羣玉','唐','唐诗','tang','','[]','雲臥竟不起，少微空隕光。',48,'全唐诗/poet.tang.31000.json','["雲臥竟不起，少微空隕光。", "唯應孔北海，爲立鄭公鄉。", "舊館苔蘚合，幽齋松菊荒。", "空餘書帶草，日日上階長。"]'),
('18729cec-3cb8-4d8b-857f-6e0f1d51743c','送秦鍊師','李羣玉','唐','唐诗','tang','','[]','紫府靜沈沈，松軒思別琴。',48,'全唐诗/poet.tang.31000.json','["紫府靜沈沈，松軒思別琴。", "水流寧有意，雲汎本無心。", "錦洞桃花遠，青山竹葉深。", "不因時賣藥，何路更相尋。"]'),
('dcbb8b88-b714-4455-a08b-676173439020','湘陰縣送遷客北歸','李羣玉','唐','唐诗','tang','','[]','不須留薏苡，重遣世人疑。',48,'全唐诗/poet.tang.31000.json','["不須留薏苡，重遣世人疑。", "瘴染面如蘗，愁熏頭似絲。", "黃梅住雨外，青草過湖時。", "今日開湯網，冥飛亦未遲。"]'),
('df712798-3819-492a-b794-2b9f8ef93bf1','九日陪崔大夫讌清河亭','李羣玉','唐','唐诗','tang','','[]','玉醴浮金菊，雲亭敞玳筵。',48,'全唐诗/poet.tang.31000.json','["玉醴浮金菊，雲亭敞玳筵。", "晴山低畫浦，斜雁遠書天。", "謝朓離都日，殷公出守年。", "不知瑤水讌，誰和白雲篇。"]'),
('96901202-1995-48b6-812b-c8c6bb0ebb54','送房處士閑遊','李羣玉','唐','唐诗','tang','','[]','採藥陶貞白，尋山許遠遊。',48,'全唐诗/poet.tang.31000.json','["採藥陶貞白，尋山許遠遊。", "刀圭藏妙用，巖洞契冥搜。", "花月三江水，琴尊一葉舟。", "羨君隨野鶴，長揖稻粱愁。"]'),
('55d31c7b-1137-48c0-ad9d-6103ae1e4a04','贈花','李羣玉','唐','唐诗','tang','','[]','酒爲看花醞，花須趁酒紅。',48,'全唐诗/poet.tang.31000.json','["酒爲看花醞，花須趁酒紅。", "莫令芳樹晚，使我綠尊空。", "金谷園無主，桃源路不通。", "縱非乘露折，長短盡隨風。"]'),
('d5729608-776b-4123-b626-c5262834fa9e','洞庭風雨二首 一','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','面南一片黑，俄起北風顛。',48,'全唐诗/poet.tang.31000.json','["面南一片黑，俄起北風顛。", "浪潑巴陵樹，雷燒鹿角田。", "魚龍方簸蕩，雲雨正喧闐。", "想赭君山日，秦皇怒赫然。"]'),
('2c1dc03f-300a-4398-ba67-e09763ad1b5d','洞庭風雨二首 二','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','巨浸吞湘澧，西風忽怒號。',48,'全唐诗/poet.tang.31000.json','["巨浸吞湘澧，西風忽怒號。", "水將天共黑，雲與浪爭高。", "羽化思乘鯉，山漂欲抃鼇。", "陽烏猶曝翅，真恐濕蟠桃。"]'),
('25beae78-14ac-46b9-a7e0-f163678d0b2d','臨水薔薇','李羣玉','唐','唐诗','tang','','[]','堪愛復堪傷，無情不久長。',36,'全唐诗/poet.tang.31000.json','["堪愛復堪傷，無情不久長。", "浪搖千臉笑，風舞一叢芳。", "似濯文君錦，如窺漢女妝。"]'),
('6f5252d2-a84e-4f69-948d-d823672433cc','中秋維舟君山看月二首 一','李羣玉','唐','唐诗','tang','','[]','汗漫鋪澄碧，朦朧吐玉盤。',48,'全唐诗/poet.tang.31000.json','["汗漫鋪澄碧，朦朧吐玉盤。", "雨師清滓穢，川后掃波瀾。", "氣射繁星滅，光籠八表寒。", "來從雲漲迥，路上碧霄寬。"]'),
('64d0ffb7-437c-462a-ac97-fa1659a996c8','中秋維舟君山看月二首 二','李羣玉','唐','唐诗','tang','','[]','熠燿遊何處，蟾蜍食漸殘。',48,'全唐诗/poet.tang.31000.json','["熠燿遊何處，蟾蜍食漸殘。", "櫂翻銀浪急，林映白虹攢。", "練彩連河曉，冰暉壓樹乾。", "夜深高不動，天下仰頭看。"]'),
('2259ff3f-30e6-47e1-befa-bd6478b7b24d','桂州經佳人故居琪樹','李羣玉','唐','唐诗','tang','','[]','種樹人何在，攀枝空歎嗟。',48,'全唐诗/poet.tang.31000.json','["種樹人何在，攀枝空歎嗟。", "人無重見日，樹有每年花。", "滿院雀聲莫，半庭春景斜。", "東風不知恨，徧地落餘霞。"]'),
('22eea315-a2bc-455d-890a-8cf9834412d4','贈元紱','李羣玉','唐','唐诗','tang','','[]','相逢在總角，與子即同心。',48,'全唐诗/poet.tang.31000.json','["相逢在總角，與子即同心。", "隱石那知玉，披沙始遇金。", "蘭秋香不死，松晚翠方深。", "各保芳堅性，寧憂霜霰侵。"]'),
('a2ce4ac4-1f05-4fca-b78c-6f3b77470110','中秋廣江驛示韋益','李羣玉','唐','唐诗','tang','','[]','莫惜三更坐，難消萬里情。',48,'全唐诗/poet.tang.31000.json','["莫惜三更坐，難消萬里情。", "同看一片月，俱在廣州城。", "淚逐金波滿，魂隨夜鵲驚。", "支頤鄉思斷，無語到雞鳴。"]'),
('6617a865-a0cb-4c37-94cb-8407f6205104','九日越臺','李羣玉','唐','唐诗','tang','','[]','旭日高山上，秋天大海隅。',48,'全唐诗/poet.tang.31000.json','["旭日高山上，秋天大海隅。", "黃花羅粔籹，絳實簇茱萸。", "病久歡情薄，鄉遙客思孤。", "無心同落帽，天際望歸途。"]'),
('5761f729-fba0-4a0f-9443-62be1e40288d','中秋越臺看月','李羣玉','唐','唐诗','tang','','[]','海雨洗塵埃，月從空碧來。',48,'全唐诗/poet.tang.31000.json','["海雨洗塵埃，月從空碧來。", "水光籠草樹，練影挂樓臺。", "皓曜迷鯨目，晶熒失蚌胎。", "宵分凭檻望，應合見蓬萊。"]'),
('b484cb04-a647-420d-b690-2b7ecacc88c8','長沙開元寺昔與故長林許侍御題松竹聯句','李羣玉','唐','唐诗','tang','','[]','墻陰數行字，懷舊慘傷情。',48,'全唐诗/poet.tang.31000.json','["墻陰數行字，懷舊慘傷情。", "薜荔侵年月，莓苔壓姓名。", "逝川前後水，浮世短長生。", "獨立秋風暮，凝顰隔郢城。"]'),
('a7845167-8968-45a8-aa20-4265a08353d8','傷友','李羣玉','唐','唐诗','tang','','[]','玉棺來九天，鳧舃掩窮泉。',48,'全唐诗/poet.tang.31000.json','["玉棺來九天，鳧舃掩窮泉。", "蕪沒池塘嶼，淒涼翰墨筵。", "短期存大夢，舊好委浮煙。", "我有幽蘭曲，因君遂絕弦。"]'),
('bee4eaff-0fa8-421e-8c79-beb50fcba2d9','法性寺六祖戒壇','李羣玉','唐','唐诗','tang','','[]','初地無階級，餘基數尺低。',48,'全唐诗/poet.tang.31000.json','["初地無階級，餘基數尺低。", "天香開茉莉，梵樹落菩提。", "驚俗生真性，青蓮出淤泥。", "何人得心法，衣鉢在曹溪。"]'),
('1e86c6d6-5988-47f3-bd99-16f6e8125749','東湖二首 一','李羣玉','唐','唐诗','tang','','[]','晚景微雨歇，逍遙湖上亭。',48,'全唐诗/poet.tang.31000.json','["晚景微雨歇，逍遙湖上亭。", "波閑魚弄餌，樹靜鳥遺翎。", "性野難依俗，詩玄自入冥。", "何繇遂瀟灑，高枕對雲汀。"]'),
('5f6fb3c9-8c96-4466-98de-fb6cfdd75ed5','東湖二首 二','李羣玉','唐','唐诗','tang','','[]','雨氣消殘暑，蒼蒼月欲升。',48,'全唐诗/poet.tang.31000.json','["雨氣消殘暑，蒼蒼月欲升。", "林間風捲簟，欄下水搖燈。", "迥野垂銀鏡，層巒挂玉繩。", "重期浮小檝，來摘半湖菱。"]'),
('b43bb9bd-1791-42a1-bcda-1c0be2b43677','湖閣曉晴寄呈從翁二首 一','李羣玉','唐','唐诗','tang','','[]','嶺日開寒霧，湖光蕩霽華。',48,'全唐诗/poet.tang.31000.json','["嶺日開寒霧，湖光蕩霽華。", "風烏搖逕柳，水蝶戀幽花。", "蜀國地西極，吳門天一涯。", "輕舟欄下去，點點入湘霞。"]'),
('3f3b203b-0741-47ce-b926-153941ff07ad','湖閣曉晴寄呈從翁二首 二','李羣玉','唐','唐诗','tang','','[]','高秋憑遠檻，萬里看新晴。',48,'全唐诗/poet.tang.31000.json','["高秋憑遠檻，萬里看新晴。", "重霧披天急，千雲觸石輕。", "湖山四五點，湘雁兩三聲。", "遙想潘園裏，琴尊興轉清。"]'),
('ad3579b2-b079-4e15-a661-9228916601aa','同張明府遊漊水亭','李羣玉','唐','唐诗','tang','','[]','草色綠溪晚，梅香生縠文。',48,'全唐诗/poet.tang.31000.json','["草色綠溪晚，梅香生縠文。", "雲天斂餘霽，水木籠微曛。", "垂釣坐方嶼，幽禽時一聞。", "何當五柳下，酌醴吟庭筠。"]'),
('97c21e8e-0753-4981-9eb1-ff3dceba6251','七月十五夜看月','李羣玉','唐','唐诗','tang','','[]','朦朧南溟月，汹湧出雲濤。',48,'全唐诗/poet.tang.31000.json','["朦朧南溟月，汹湧出雲濤。", "下射長鯨眼，遙分玉兔毫。", "勢來星斗動，路越青冥高。", "竟夕瞻光彩，昂頭把白醪。"]'),
('ead059e1-1db7-4b16-8459-d4279af71de8','北風','李羣玉','唐','唐诗','tang','','[]','病髮乾垂枕，臨風強起梳。',48,'全唐诗/poet.tang.31000.json','["病髮乾垂枕，臨風強起梳。", "蝶飛魂尚弱，蟻鬬體猶虛。", "瘦骨呻吟後，羸容几杖初。", "庭幽行藥靜，涼暑翠筠疎。"]'),
('a59d1fc2-2703-4ce6-b58b-e0466b0aec48','遊玉芝觀','李羣玉','唐','唐诗','tang','','[]','尋仙向玉清，獨倚雪初晴。',48,'全唐诗/poet.tang.31000.json','["尋仙向玉清，獨倚雪初晴。", "木落寒郊迥，煙開疊嶂明。", "片雲盤鶴影，孤磬雜松聲。", "且共探玄理，歸途月未生。"]'),
('5997d689-ef60-4b20-837d-f75949653230','中秋夜南樓寄友人','李羣玉','唐','唐诗','tang','','[]','海月出銀浪，湖光射高樓。',48,'全唐诗/poet.tang.31000.json','["海月出銀浪，湖光射高樓。", "朗吟無淥酒，賤價買清秋。", "氣冷魚龍寂，輪高星漢幽。", "他鄉此夜客，對景餞多愁。"]'),
('5cff0192-56be-437c-a408-6dc780b99d97','三月五日陪裴大夫汎長沙東湖','李羣玉','唐','唐诗','tang','','[]','上巳餘風景，芳辰集遠坰。',72,'全唐诗/poet.tang.31000.json','["上巳餘風景，芳辰集遠坰。", "綵舟浮滉蕩，繡轂下娉婷。", "林榭回蔥蒨，笙歌轉杳冥。", "湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚翻穀雨萍。", "從今留勝會，誰肯畫蘭亭。"]'),
('ef3bc2d3-3f57-4b59-bec7-5da00f35d0bc','龜','李羣玉','唐','唐诗','tang','','[]','靜養千年壽，重泉自隱居。',96,'全唐诗/poet.tang.31000.json','["靜養千年壽，重泉自隱居。", "不應隨跛鼈，寧肯滯凡魚。", "靈腹唯玄露，芳巢必翠蕖。", "揚花輸蚌蛤，犇月恨蟾蜍。", "曳尾辭泥後，支牀得水初。", "冠山期不小，鑄印事寧虛。", "有志酬毛寶，無心畏豫且。", "他時清洛汭，會薦帝堯書。"]'),
('fb952cd6-744b-4ba9-a38a-d149929b52e3','長沙春望寄涔陽故人','李羣玉','唐','唐诗','tang','','[]','清明別後雨晴時，極浦空顰一望眉。',64,'全唐诗/poet.tang.31000.json','["清明別後雨晴時，極浦空顰一望眉。", "湖畔春山煙黯黯，雲中遠樹黑離離。", "依微水戍聞疎鼓，掩映河橋見酒旗。", "風暖草長愁自醉，行吟無處寄相思。"]'),
('d5bb15b9-1a39-42ee-bf20-810ce56f4e2d','金塘路中','李羣玉','唐','唐诗','tang','','[]','山連楚越復吳秦，蓬梗何年是住身。',64,'全唐诗/poet.tang.31000.json','["山連楚越復吳秦，蓬梗何年是住身。", "黃葉黃花古城路，秋風秋雨別家人。", "冰霜想度商於凍，桂玉愁居帝里貧。", "十口繫心拋不得，每回回首即長顰。"]'),
('9e1a656c-fab9-4ebd-9a6b-38b58234aaa9','自遣','李羣玉','唐','唐诗','tang','','[]','翻覆升沈百歲中，前途一半已成空。',64,'全唐诗/poet.tang.31000.json','["翻覆升沈百歲中，前途一半已成空。", "浮生暫寄夢中夢，世事如聞風裏風。", "修竹萬竿資闃寂，古書千卷要窮通。", "一壺濁酒暄和景，誰會陶然失馬翁。"]'),
('0e77066b-d350-48fb-a3d3-d5edd0c51555','送于少監自廣州還紫邏','李羣玉','唐','唐诗','tang','','[]','鳴臯山水似麻源，謝監東還憶故園。',64,'全唐诗/poet.tang.31000.json','["鳴臯山水似麻源，謝監東還憶故園。", "海嶠煙霞輕逸翰，洛川花木待回軒。", "宦情薄去詩千首，世事閑來酒一尊。", "明日中書見顏范，始應通籍入金門。"]'),
('67075277-91a3-48a9-817c-f6f9e81b6498','石門韋明府爲致東陽潭石鯽鱠','李羣玉','唐','唐诗','tang','','["\u592a\u6e56"]','錦鱗銜餌出清漣，暖日江亭動鱠筵。',64,'全唐诗/poet.tang.31000.json','["錦鱗銜餌出清漣，暖日江亭動鱠筵。", "疊雪亂飛消箸底，散絲繁灑拂刀前。", "太湖浪說朱衣鮒，漢浦休誇縮項鳊。", "雋味品流知第一，更勞霜橘助芳鮮。"]'),
('0ca2812b-a3a9-413e-8616-0eef0765111b','規公業在淨名得甚深義僕近獲顧長康月宮真影對戴安道所畫文殊走筆此篇以屈瞻禮','李羣玉','唐','唐诗','tang','','[]','五濁之世塵冥冥，達觀棲心于此經。',64,'全唐诗/poet.tang.31000.json','["五濁之世塵冥冥，達觀棲心于此經。", "但用須彌藏芥子，安知牛跡笑東溟。", "生公吐辯真無敵，顧氏傳神實有靈。", "今日淨開方丈室，一飛白足到茅亭。"]'),
('350f5dec-de1f-4507-9610-7d0acbac2051','玉真觀','李羣玉','唐','唐诗','tang','','[]','高情帝女慕乘鸞，紺髮初簪玉葉冠。',64,'全唐诗/poet.tang.31000.json','["高情帝女慕乘鸞，紺髮初簪玉葉冠。", "秋月無雲生碧落，素蕖寒露出清瀾。", "層城煙霧將歸遠，浮世塵埃久住難。", "一自簫聲飛去後，洞宮深掩碧瑤壇。"]'),
('2c8cb28a-4317-4f34-a566-86eb346a0079','辱綿州于中丞書信','李羣玉','唐','唐诗','tang','','[]','一緘垂露到雲林，中有孫陽念驥心。',64,'全唐诗/poet.tang.31000.json','["一緘垂露到雲林，中有孫陽念驥心。", "萬木自凋山不動，百川皆旱海長深。", "風標想見瑤臺鶴，詩韻如聞淥水琴。", "他日縱陪池上酌，已應難到暝猨吟。"]'),
('dcdd47f1-8510-4ac1-916f-752a6c4642c4','送崔使君蕭山禱雨甘澤遽降','李羣玉','唐','唐诗','tang','','[]','謝公一拜敬亭祠，五馬旋歸下散絲。',64,'全唐诗/poet.tang.31000.json','["謝公一拜敬亭祠，五馬旋歸下散絲。", "不假土龍呈夭矯，自然石燕起參差。", "預聽禾稼如雲語，應有空濛似霧時。", "已向爲霖報消息，潁川徵詔是前期。"]'),
('4c0e4542-8324-4e24-80b8-f1e7c0c34749','重經巴丘追感','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','昔年高接李膺歡，日汎仙舟醉碧瀾。',64,'全唐诗/poet.tang.31000.json','["昔年高接李膺歡，日汎仙舟醉碧瀾。", "詩句亂隨青草發，酒腸俱逐洞庭寬。", "浮生聚散雲相似，往事微茫夢一般。", "今日片帆城下去，秋風回首淚闌干。"]'),
('4cec5e03-f673-44f0-821d-07d0f479136b','湘陰江亭却寄友人','李羣玉','唐','唐诗','tang','','[]','湘岸初晴淑景遲，風光正是客愁時。',64,'全唐诗/poet.tang.31000.json','["湘岸初晴淑景遲，風光正是客愁時。", "幽花暮落騷人浦，芳草春深帝子祠。", "往事隔年如過夢，舊遊回首謾勞思。", "煙波自此扁舟去，小酌文園杳未期。"]'),
('989f733e-683d-4e77-9045-0ad22155ed95','哭郴州王使君','李羣玉','唐','唐诗','tang','','[]','銀章朱紱照雲驄，六換魚書惠化崇。',64,'全唐诗/poet.tang.31000.json','["銀章朱紱照雲驄，六換魚書惠化崇。", "瑤樹忽傾滄海裏，醉鄉翻在夜臺中。", "東山妓逐飛花散，北海尊隨逝水空。", "曾是綺羅筵上客，一來長慟向春風。"]'),
('255a6e05-bb84-447f-943f-5cb02538a04d','九日巴丘楊公臺上讌集','李羣玉','唐','唐诗','tang','','[]','淒淒霜日上高臺，水國秋深客思哀。',64,'全唐诗/poet.tang.31000.json','["淒淒霜日上高臺，水國秋深客思哀。", "萬疊銀山寒浪起，一行斜字早鴻來。", "誰家擣練孤城暮，何處題衣遠信回？", "江漢路長身不定，菊花三笑旅萍開。"]'),
('73e27159-4cc9-4e88-85da-4aa6eadfe2dc','奉和張舍人送秦鍊師歸岑公山','李羣玉','唐','唐诗','tang','','[]','仙翁歸臥翠微岑，一夜西風月峽深。',64,'全唐诗/poet.tang.31000.json','["仙翁歸臥翠微岑，一夜西風月峽深。", "松逕定知芳草合，玉書應念素塵侵。", "閑雲不繫東西影，野鶴寧知去住心。", "蘭浦蒼蒼春欲暮，落花流水怨離琴。"]'),
('c0f8f727-f4c9-4f9d-9235-3d1315206ac7','送陶少府赴選','李羣玉','唐','唐诗','tang','','[]','陶君官興本蕭疎，長傍青山碧水居。',64,'全唐诗/poet.tang.31000.json','["陶君官興本蕭疎，長傍青山碧水居。", "久向三茅窮藝術，仍傳五柳舊琴書。", "迹同飛鳥棲高樹，心似閑雲在太虛。", "自是葛洪求藥價，不關梅福戀簪裾。"]'),
('ef992371-a867-4a65-81d9-3fbb24233610','寄張祜','李羣玉','唐','唐诗','tang','','[]','越水吳山任興行，五湖雲月挂高情。',64,'全唐诗/poet.tang.31000.json','["越水吳山任興行，五湖雲月挂高情。", "不遊都邑稱平子，只向江東作步兵。", "昔歲芳聲到童稚，老來佳句徧公卿。", "如君氣力波瀾地，留取陰何沈范名。"]'),
('a8d8412a-86ea-469b-96be-5030ebe3139f','寄長沙許侍御','李羣玉','唐','唐诗','tang','','[]','三年文會許追隨，和徧南朝雜體詩。',64,'全唐诗/poet.tang.31000.json','["三年文會許追隨，和徧南朝雜體詩。", "未把彩毫還郭璞，乞留殘錦與丘遲。", "竹齋琴酒歡成夢，水寺煙霞賞對誰。", "今日秋風滿湘浦，秪應搔首詠瓊枝。"]'),
('fdb6b7c6-8a6e-4eb6-a13e-19eada8ce02f','望月懷友','李羣玉','唐','唐诗','tang','','[]','浮雲卷盡看朣朧，直出滄溟上碧空。',64,'全唐诗/poet.tang.31000.json','["浮雲卷盡看朣朧，直出滄溟上碧空。", "盈手水光寒不濕，流天素彩靜無風。", "酒花蕩漾金尊裏，櫂影飄颻玉浪中。", "川路正長難可越，美人千里思何窮。"]'),
('997b631a-bfdd-40d0-9142-69a887e1092e','和吳中丞悼笙妓','李羣玉','唐','唐诗','tang','','[]','麗質仙姿煙逐風，鳳皇聲斷吹臺空。',64,'全唐诗/poet.tang.31000.json','["麗質仙姿煙逐風，鳳皇聲斷吹臺空。", "多情草色怨還綠，無主杏花春自紅。", "墮珥尚存芳樹下，餘香漸減玉堂中。", "唯應去抱雲和管，從此長歸阿母宮。"]'),
('052653a6-b5e5-4109-9cd8-7bc2d73c2b76','薛侍御處乞鞾','李羣玉','唐','唐诗','tang','','[]','越客南來誇桂麖，良工用意巧縫成。',64,'全唐诗/poet.tang.31000.json','["越客南來誇桂麖，良工用意巧縫成。", "看時共說茱萸皺，著處嫌無鸜鵒鳴。", "百里奚身悲甚似，五羊皮價敢全輕。", "日於文苑陪高步，贏得芳塵接武名。"]'),
('3ab6830c-bf2b-4d08-b8a4-df3c701b7ace','九子坡聞鷓鴣','李羣玉','唐','唐诗','tang','','[]','落照蒼茫秋草明，鷓鴣啼處遠人行。',64,'全唐诗/poet.tang.31000.json','["落照蒼茫秋草明，鷓鴣啼處遠人行。", "正穿詰曲崎嶇路，更聽鉤輈格磔聲。", "曾泊桂江深岸雨，亦于梅嶺阻歸程。", "此時爲爾腸千斷，乞放今宵白髮生。"]'),
('85081336-b211-4f05-87b8-eb4e587d8195','涼公從叔春祭廣利王廟','李羣玉','唐','唐诗','tang','','[]','龍驤伐鼓下長川，直濟雲濤古廟前。',64,'全唐诗/poet.tang.31000.json','["龍驤伐鼓下長川，直濟雲濤古廟前。", "海客斂威驚火斾，天吳收浪避樓船。", "陰靈向作南溟主，祀典高齊五岳肩。", "從此華夷封域靜，潛熏玉燭奉堯年。"]'),
('0c95f671-62cc-4228-8270-91bdfb3dab51','長沙紫極宮雨夜愁坐','李羣玉','唐','唐诗','tang','','[]','獨坐高齋寒擁衾，洞宮臺殿窅沈沈。',64,'全唐诗/poet.tang.31000.json','["獨坐高齋寒擁衾，洞宮臺殿窅沈沈。", "春燈含思靜相伴，夜雨滴愁更向深。", "窮達未知他日事，是非皆到此時心。", "羈棲摧剪平生志，抱膝時爲梁甫吟。"]'),
('d381b2a7-e535-41b8-8f2b-4aa347d117d8','送人隱居','李羣玉','唐','唐诗','tang','','[]','碁局茅亭幽澗濱，竹寒江靜遠無人。',64,'全唐诗/poet.tang.31000.json','["碁局茅亭幽澗濱，竹寒江靜遠無人。", "邨梅尚斂風前笑，沙草初偷雪後春。", "鵬鷃喻中消日月，滄浪歌裏放心神。", "平生自有煙霞志，久欲拋身狎隱淪。"]'),
('c42c4dd8-02da-4a33-802f-782409305b07','江樓閑望懷關中親故','李羣玉','唐','唐诗','tang','','[]','搖落江天欲盡秋，遠鴻高送一行愁。',64,'全唐诗/poet.tang.31000.json','["搖落江天欲盡秋，遠鴻高送一行愁。", "音書寂絕秦雲外，身世蹉跎楚水頭。", "年貌暗隨黃葉去，時情深付碧波流。", "風淒日冷江湖晚，駐目寒空獨倚樓。"]'),
('b0335e1e-2432-4cf3-aff3-840c87f92ec5','請告南歸留別同館','李羣玉','唐','唐诗','tang','','[]','一點燈前獨坐身，西風初動帝城砧。',64,'全唐诗/poet.tang.31000.json','["一點燈前獨坐身，西風初動帝城砧。", "不勝庾信鄉關思，遂作陶潛歸去吟。", "書閤乍離情黯黯，彤庭迴望肅沈沈。", "應憐一別瀛洲侶，萬里單飛雲外深。"]'),
('586988ec-0168-499f-8610-1238deeceae0','仙明洲口號','李羣玉','唐','唐诗','tang','','[]','長愛沙洲水竹居，暮江春樹綠陰初。',64,'全唐诗/poet.tang.31000.json','["長愛沙洲水竹居，暮江春樹綠陰初。", "浪翻新月金波淺，風損輕雲玉葉疎。", "半浦夜歌聞盪槳，一星幽火照叉魚。", "二年此處尋佳句，景物常輸楚客書。"]'),
('e664e78a-8709-4823-9ddc-0a8b3e7a7be9','送蕭十二校書赴郢州婚姻','李羣玉','唐','唐诗','tang','','[]','蓬萊才子即蕭郎，綵服青書卜鳳皇。',64,'全唐诗/poet.tang.31000.json','["蓬萊才子即蕭郎，綵服青書卜鳳皇。", "玉珮定催紅粉色，錦衾應惹翠雲香。", "馬穿暮雨荆山遠，人宿寒燈郢夢長。", "領取和鳴好風景，石城花月送歸鄉。"]'),
('24853263-11cd-4422-8da7-15c2f5ae654c','送隱者歸羅浮','李羣玉','唐','唐诗','tang','','[]','春山杳杳日遲遲，路入雲峰白犬隨。',64,'全唐诗/poet.tang.31000.json','["春山杳杳日遲遲，路入雲峰白犬隨。", "兩卷素書留貰酒，一柯樵斧坐看棋。", "蓬萊道士飛霞履，清遠仙人寄好詩。", "自此塵寰音信斷，山川風月永相思。"]'),
('b58191d6-06f3-458e-8af5-3b54a2e4b24b','獻王中丞','李羣玉','唐','唐诗','tang','','[]','登仙望絕李膺舟，從此青蠅點遂稠。',64,'全唐诗/poet.tang.31000.json','["登仙望絕李膺舟，從此青蠅點遂稠。", "半夜劒吹牛斗動，二年門掩雀羅愁。", "張儀會展平生舌，韓信那慙跨下羞。", "他日圖勳畫麟閣，定呈肝膽始應休。"]'),
('b5720833-8fbe-4f86-aef3-d0236052cbed','哭小女癡兒','李羣玉','唐','唐诗','tang','','[]','平生未省夢熊羆，稚女如花墜曉枝。',64,'全唐诗/poet.tang.31000.json','["平生未省夢熊羆，稚女如花墜曉枝。", "條蔓縱橫輸葛藟，子孫蕃育羨螽斯。", "方同王衍鍾情切，猶念商瞿有慶遲。", "負爾五年恩愛淚，眼中惟有涸泉知。"]'),
('9bcd69a1-0bb5-4eb6-893a-2ae159b546e3','醉後贈馮姬','李羣玉','唐','唐诗','tang','','[]','黃昏歌舞促瓊筵，銀燭臺西見小蓮。',64,'全唐诗/poet.tang.31000.json','["黃昏歌舞促瓊筵，銀燭臺西見小蓮。", "二寸橫波回慢水，一雙纖手語香弦。", "桂形淺拂梁家黛，瓜字初分碧玉年。", "願託襄王雲雨夢，陽臺今夜降神仙。"]'),
('e02188e9-d326-4874-bde7-a6536567cef0','廣州陪涼公從叔越臺讌集','李羣玉','唐','唐诗','tang','','[]','一逕松梢踏石梯，步窮身在白雲西。',64,'全唐诗/poet.tang.31000.json','["一逕松梢踏石梯，步窮身在白雲西。", "日銜赤浪金車沒，天拂滄波翠幕低。", "高鳥散飛驚大斾，長風萬里卷秋鼙。", "玉鉤挂海笙歌合，珠履三千半似泥。"]'),
('5c23ad6d-3bc7-4655-be03-70cd7a85ce7f','留別馬使君','李羣玉','唐','唐诗','tang','','[]','俱來海上歎煙波，君佩銀魚我觸羅。',64,'全唐诗/poet.tang.31000.json','["俱來海上歎煙波，君佩銀魚我觸羅。", "蜀國才微甘放蕩，專城年少豈蹉跎。", "應憐旅夢千重思，共愴離心一曲歌。", "唯有管弦知客意，分明吹出感恩多。"]'),
('a8325578-f3f1-43dc-9474-c3eb3fcbfdda','將欲南行陪崔八讌海榴亭','李羣玉','唐','唐诗','tang','','[]','朝讌華堂暮未休，幾人偏得謝公留。',64,'全唐诗/poet.tang.31000.json','["朝讌華堂暮未休，幾人偏得謝公留。", "風傳鼓角霜侵戟，雲卷笙歌月上樓。", "賓館盡開徐孺榻，客帆空戀李膺舟。", "謾誇書劒無歸處，水遠山長步步愁。"]'),
('710bdbb7-6c31-4d84-9e80-81fd5aad669f','湖寺清明夜遣懷','李羣玉','唐','唐诗','tang','','[]','柳暗花香愁不眠，獨凭危檻思淒然。',48,'全唐诗/poet.tang.31000.json','["柳暗花香愁不眠，獨凭危檻思淒然。", "野雲將雨渡微月，沙鳥帶聲飛遠天。", "久向飢寒拋弟妹，每因時節憶團圓。"]'),
('6fcff4ed-d5ca-4906-aa85-6981b77860c6','九日','李羣玉','唐','唐诗','tang','','[]','年年羞見菊花開，十度悲秋上楚臺。',64,'全唐诗/poet.tang.31000.json','["年年羞見菊花開，十度悲秋上楚臺。", "半嶺殘陽銜樹落，一行斜雁向人來。", "行雲永絕襄王夢，野水偏傷宋玉懷。", "絲管闌珊歸客盡，黃昏獨自詠詩迴。"]'),
('b508aa7e-f960-4c3f-90b5-0bcacc4ef81b','同鄭相幷歌姬小飲戲贈','李羣玉','唐','唐诗','tang','','[]','裙拖六幅湘江水，鬢聳巫山一段雲。',64,'全唐诗/poet.tang.31000.json','["裙拖六幅湘江水，鬢聳巫山一段雲。", "風格只應天上有，歌聲豈合世間聞。", "胸前瑞雪燈斜照，眼底桃花酒半醺。", "不是相如憐賦客，爭敎容易見文君。"]'),
('6c4c7d3f-486d-4cce-9228-52190da0fa68','秣陵懷古','李羣玉','唐','唐诗','tang','','[]','野花黃葉舊吳宮，六代豪華燭散風。',64,'全唐诗/poet.tang.31000.json','["野花黃葉舊吳宮，六代豪華燭散風。", "龍虎勢衰佳氣歇，鳳皇名在故臺空。", "市朝遷變秋蕪綠，墳塚高低落照紅。", "霸業鼎圖人去盡，獨來惆悵水雲中。"]'),
('ae649af7-5266-4dbf-8cf9-3625b2a3711d','黃陵廟','李羣玉','唐','唐诗','tang','','[]','小姑洲北浦雲邊，二女容華自儼然。',64,'全唐诗/poet.tang.31000.json','["小姑洲北浦雲邊，二女容華自儼然。", "野廟向江春寂寂，古碑無字草芊芊。", "風迴日暮吹芳芷，月落山深哭杜鵑。", "猶似含顰望巡狩，九疑愁斷隔湘川。"]'),
('2da9b1ce-a15f-407d-9d3b-3787b771d1ea','送唐侍御福建省兄','李羣玉','唐','唐诗','tang','','[]','桂枝攀盡賈家才，霄漢春風棣萼開。',64,'全唐诗/poet.tang.31000.json','["桂枝攀盡賈家才，霄漢春風棣萼開。", "世掌綸言傳大筆，官分鴻序壓霜臺。", "閩山翠卉迎飛斾，越水清紋散落梅。", "到日池塘春草綠，謝公應夢惠連來。"]');
